#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reversed permutation p' = [p_n, p_{n-1}, ..., p_1]
        // will have the same set of adjacent sums as p.
        // For example, if p = [p1, p2, p3], sums are [p1+p2, p2+p3].
        // p_rev = [p3, p2, p1], sums are [p3+p2, p2+p1].
        // These sets are identical, so their sorted versions (fingerprints) will be identical.
        // The only case where p_rev might be the same as p is if p is a palindrome,
        // i.e., p_i = p_{n-i+1} for all i.
        // However, the problem guarantees that a different permutation exists.
        // Reversing the permutation is the simplest way to get a different one with the same fingerprint.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

