void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long min_val = a[0];
    long long operations = 0;

    for (int i = 1; i < n; ++i) {
        // For each pile a[i] (where i > 0, so a[i] is not the minimum pile),
        // we can add min_val to it as many times as possible without exceeding k.
        // The number of times min_val can be added to a[i] is (k - a[i]) / min_val.
        // This is integer division, which correctly gives the floor.
        operations += (k - a[i]) / min_val;
    }

    std::cout << operations << std::endl;
}

