#include <iostream>
#include <cmath> // For std::abs

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This is a common competitive programming optimization.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T; // Read the number of test cases

    while (T--) { // Loop T times for each test case
        long long a, b;
        std::cin >> a >> b; // Read current volume 'a' and desired volume 'b'

        // Calculate the absolute difference between 'a' and 'b'.
        // This is the total amount of volume change needed.
        long long diff = std::abs(a - b);

        // Initialize the count of button presses.
        long long presses = 0;

        // Greedy approach:
        // 1. Use as many +5 or -5 buttons as possible.
        presses += diff / 5;
        diff %= 5; // Update remaining difference

        // 2. Use as many +2 or -2 buttons as possible for the remainder.
        presses += diff / 2;
        diff %= 2; // Update remaining difference

        // 3. Use as many +1 or -1 buttons as possible for the final remainder.
        // At this point, diff will be either 0 or 1.
        presses += diff; // If diff is 1, add 1 press; if 0, add 0 presses.

        std::cout << presses << "\n"; // Output the minimum number of presses
    }

    return 0; // Indicate successful execution
}

