void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only numbers up to 2048 can contribute to forming 2048
            counts[s_val]++;
        }
    }

    // Simulate the merging process
    // Iterate through powers of two from smallest to largest
    // 1, 2, 4, ..., 1024
    for (int p = 1; p < 2048; p *= 2) {
        if (counts[p] >= 2) {
            // If we have at least two 'p's, we can combine them to form '2p'
            // The number of '2p's formed is counts[p] / 2
            counts[2 * p] += counts[p] / 2;
        }
    }

    // Check if 2048 was formed or was present initially
    if (counts[2048] > 0) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

