int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int ans = a[0]; // Start with haybales already in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            int pile_idx = i; // 0-indexed pile index
            int haybales_in_pile = a[pile_idx];
            int days_to_move_one = pile_idx; // Cost to move one haybale to pile 0

            if (days_to_move_one == 0) continue; // Should not happen for i >= 1

            // Calculate how many haybales can be moved from this pile
            // Limited by haybales_in_pile and available days
            int max_can_move = d / days_to_move_one;

            int num_to_move = std::min(haybales_in_pile, max_can_move);

            ans += num_to_move;
            d -= num_to_move * days_to_move_one;

            if (d <= 0) { // If no days left, stop
                break;
            }
        }
        std::cout << ans << std::endl;
    }
    return 0;
}

