#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update has_pos_one and has_neg_one for elements to the left
        // If a[i] was 1 or -1, it means it was available for elements to its right.
        // Now that we are processing from right to left, this a[i] is no longer available
        // for elements to its left. So we update the flags.
        if (a[i] == 1) {
            has_pos_one = false;
        } else if (a[i] == -1) {
            has_neg_one = false;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

