#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last price

    // Iterate from right to left (from n-2 down to 0)
    // The last element a[n-1] can never be a bad price because there are no later days.
    for (int i = n - 2; i >= 0; --i) {
        // If the current price a[i] is greater than the minimum price found so far
        // in the suffix a[i+1...n-1], then a[i] is a bad price.
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        }
        // Update the minimum suffix price for the next iteration (i.e., for a[i-1])
        min_suffix_price = std::min(min_suffix_price, a[i]);
    }

    std::cout << bad_prices_count << "\n";
}

