int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' cell
        // to cell n+1. The last 'R' cell is at index `last_R_pos` (0-indexed string, so cell `last_R_pos + 1`).
        // The distance from cell `last_R_pos + 1` to cell `n + 1` is `(n + 1) - (last_R_pos + 1) = n - last_R_pos`.
        // If last_R_pos is -1, it means there were no 'R's in the string.
        // In this case, the jump is from cell 0 to cell n+1, distance is n+1.
        // The loop correctly handles this: if last_R_pos remains -1, then max_gap will be max(0, i - (-1)) for all i.
        // The final gap is from the last 'R' (or 0 if no 'R's) to n+1.
        max_gap = std::max(max_gap, n - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

