int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    bool n_used = false;

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
        if (p[i] == n) {
            n_used = true;
        }
    }

    if (!n_used) {
        // If n was not assigned to any p[i], it means all p[i] were less than n.
        // This implies that the actual value n must be assigned to one of the p[i]
        // that currently has the maximum value among all p[i]'s.
        // Since the problem guarantees a solution, there must be exactly one such p[i]
        // that should be n, and all other p[j] (j!=i) must be less than n.
        // The maximum value in the matrix a is n-1.
        // So, if n is not used, it means all p[i] were determined to be at most n-1.
        // One of them must be n.
        // The one that should be n is the one whose current p[i] value is max_val_in_row = n-1.
        // If there are multiple such p[i] with value n-1, any of them can be chosen.
        // The problem guarantees a solution, so this logic should work.

        // Find the first index i where p[i] is the maximum value found so far (which must be n-1).
        // And assign n to it.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) { // The maximum possible value for max_val_in_row is n-1.
                                 // If n is not used, it means one of the p[i] should be n.
                                 // This p[i] must have been determined as n-1 by the max_val_in_row logic.
                p[i] = n;
                break; // Only one p[i] needs to be changed to n.
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

