int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used to generate the first k distinct differences

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0-indexed) means we take from left
            std::cout << left++;
        } else { // Odd index means we take from right
            std::cout << right--;
        }
        if (i < n - 1) { // Print space if not the last element
            std::cout << " ";
        }
    }

    // The remaining n - (k+1) elements can be filled in increasing order
    // starting from the last number used (which is either left or right,
    // depending on k's parity).
    // The differences generated by these elements will be 1, which is already
    // one of the k distinct differences (specifically, the last one generated).
    for (int i = k + 1; i < n; ++i) {
        std::cout << " " << left++; // left will continue from its last value
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            // If we still need opening brackets and adding one won't exceed k/2
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // If we still need closing brackets, and adding one won't exceed k/2,
            // and the balance allows it (i.e., balance > 0)
            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // We want to divide this into n equal parts.
    // So, each part has an area of (h/2) / n = h / (2n).

    // Let x_i be the distance from the apex to the i-th cut.
    // The triangle formed by the apex and the i-th cut has height x_i.
    // By similar triangles, if the original base is 1 and height is h,
    // then the base of the smaller triangle at height x_i is (x_i / h) * 1 = x_i / h.
    // The area of this smaller triangle is (1/2) * (x_i / h) * x_i = x_i^2 / (2h).

    // For the i-th cut (0-indexed, so for the (k+1)-th piece from the apex),
    // the area of the triangle from the apex to x_k should be (k+1) * (h / (2n)).
    // So, x_k^2 / (2h) = (k+1) * (h / (2n)).
    // x_k^2 = (k+1) * (h^2 / n).
    // x_k = sqrt((k+1) * h^2 / n) = h * sqrt((k+1) / n).

    // We need n-1 cuts, so k will go from 0 to n-2.
    // The problem asks for x_1, x_2, ..., x_{n-1} where x_i is the i-th cut.
    // This means for the first cut (x_1), k=0. For the second cut (x_2), k=1, ..., for the (n-1)-th cut (x_{n-1}), k=n-2.
    // So, the formula is x_i = h * sqrt(i / n) for i from 1 to n-1.

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double xi = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << xi << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'i' such that a[i] < a[i+1]
    // This marks the end of the non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-increasing.
    // If i is 0, the whole array is non-increasing.

    // Find the rightmost index 'j' such that a[j] > a[j+1]
    // This marks the end of the non-decreasing suffix
    int j = i; // Start search from 'i'
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...n-1] is non-decreasing.
    // If j is 0, the whole array is non-decreasing.

    std::cout << j << std::endl;
}

