int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, if we sort them, the optimal strategy is to
        // assign the first n students to one class and the remaining n students
        // to the other class.
        // The median of the first class will be a[n-1] (0-indexed).
        // The median of the second class will be a[n] (0-indexed).
        // This is because the total number of students is 2n.
        // If we split them into two classes of size n each, this is not allowed
        // because n could be even.
        //
        // However, the problem statement implies that the total number of students
        // is 2n, and we need to partition them into two classes, each with an
        // odd number of students.
        // Let the sizes be S1 and S2, where S1 + S2 = 2n.
        // S1 = 2k1 + 1, S2 = 2k2 + 1.
        // The median of a class of size 2k+1 is the (k+1)-th element (1-indexed).
        //
        // Consider the sorted array a_1, a_2, ..., a_{2n}.
        // The smallest possible median for any class is a_1 (if class size is 1).
        // The largest possible median for any class is a_{2n} (if class size is 1).
        //
        // The key insight for this problem is that to minimize the difference
        // between two medians, we should pick two elements that are as close
        // as possible in the sorted array, and ensure they can be medians.
        //
        // If we pick a[n-1] as the median for one class and a[n] as the median
        // for the other class (using 0-indexed array), we need to show that
        // this is always possible and optimal.
        //
        // To make a[n-1] the median of a class, say C1, of size 2k1+1:
        // We need k1 elements smaller than or equal to a[n-1] and k1 elements
        // larger than or equal to a[n-1].
        // The elements a[0], ..., a[n-2] are n-1 elements smaller than or equal to a[n-1].
        // So we can pick k1 elements from a[0]...a[n-2] and k1 elements from a[n]...a[2n-1].
        //
        // To make a[n] the median of a class, say C2, of size 2k2+1:
        // We need k2 elements smaller than or equal to a[n] and k2 elements
        // larger than or equal to a[n].
        // The elements a[n+1], ..., a[2n-1] are n-1 elements larger than or equal to a[n].
        //
        // The most balanced way to split the students into two classes of odd sizes
        // is to make one class of size $n$ and the other of size $n$.
        // Wait, this is not correct. $n$ can be even.
        //
        // The problem states $2n$ students.
        // The median of an array of $2k+1$ elements is $b_{k+1}$ (1-indexed).
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // The $n$-th element is $a_{n-1}$. The $(n+1)$-th element is $a_n$.
        //
        // If we choose $a_{n-1}$ as the median of the first class and $a_n$ as the median of the second class.
        //
        // Class 1: median $a_{n-1}$.
        // To make $a_{n-1}$ the median, we need $k_1$ elements $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ that are $\le a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ that are $\ge a_{n-1}$.
        //
        // Class 2: median $a_n$.
        // To make $a_n$ the median, we need $k_2$ elements $\le a_n$ and $k_2$ elements $\ge a_n$.
        // We have $n$ elements $a_0, \dots, a_{n-1}$ that are $\le a_n$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ that are $\ge a_n$.
        //
        // We can form Class 1 with $a_{n-1}$ as median by taking $k_1$ elements from $a_0, \dots, a_{n-2}$
        // and $k_1$ elements from $a_n, \dots, a_{2n-1}$.
        // We can form Class 2 with $a_n$ as median by taking $k_2$ elements from $a_0, \dots, a_{n-1}$
        // and $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // The crucial observation is that the total number of students is $2n$.
        // The median of a class of size $2k+1$ is the $(k+1)$-th element.
        // This means there are $k$ elements before it and $k$ elements after it.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // The minimum possible difference between medians will be achieved when the medians are adjacent in the sorted list.
        //
        // Let's try to make $a_{n-1}$ the median of one class and $a_n$ the median of the other.
        //
        // Class 1 (median $a_{n-1}$):
        // We need $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We can take $a_0, \dots, a_{k_1-1}$ (these are $k_1$ elements smaller than $a_{n-1}$, assuming $k_1 \le n-1$).
        // We can take $a_{n}, \dots, a_{n+k_1-1}$ (these are $k_1$ elements larger than $a_{n-1}$, assuming $k_1 \le n$).
        //
        // Class 2 (median $a_n$):
        // We need $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        // We can take $a_{n-1-k_2}, \dots, a_{n-2}$ (these are $k_2$ elements smaller than $a_n$, assuming $k_2 \le n-1$).
        // We can take $a_{2n-k_2}, \dots, a_{2n-1}$ (these are $k_2$ elements larger than $a_n$, assuming $k_2 \le n-1$).
        //
        // The simplest partition that satisfies the odd size requirement is to have one class of size 1 and the other of size $2n-1$.
        // If Class 1 has size 1, its median is $a_i$.
        // If Class 2 has size $2n-1$, its median is $a_j$.
        //
        // The problem is simpler than it looks.
        // The total number of students is $2n$.
        // The median of a class of size $2k+1$ is the $(k+1)$-th element.
        // This means there are $k$ elements smaller than or equal to it, and $k$ elements larger than or equal to it.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // The $n$-th element is $a_{n-1}$. The $(n+1)$-th element is $a_n$.
        //
        // We can always form two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Let's try to make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2.
        //
        // Class 1:
        // Take $a_{n-1}$ as the median.
        // We need $k_1$ elements smaller than or equal to $a_{n-1}$ and $k_1$ elements larger than or equal to $a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ that are $\le a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ that are $\ge a_{n-1}$.
        //
        // Class 2:
        // Take $a_n$ as the median.
        // We need $k_2$ elements smaller than or equal to $a_n$ and $k_2$ elements larger than or equal to $a_n$.
        // We have $n$ elements $a_0, \dots, a_{n-1}$ that are $\le a_n$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ that are $\ge a_n$.
        //
        // We can choose $k_1 = 0$ and $k_2 = n-1$.
        // Class 1: $\{a_{n-1}\}$. Size 1. Median $a_{n-1}$.
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$. Size $2n-1$.
        // The elements for Class 2 are all elements except $a_{n-1}$.
        // When sorted, these are $a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}$.
        // The median of this class of size $2n-1$ (where $k_2=n-1$) is the $(n-1+1)$-th element, i.e., the $n$-th element.
        // The $n$-th element in the sorted list of Class 2 is $a_n$.
        // So, this partition is valid: Class 1 = $\{a_{n-1}\}$, Class 2 = $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // The medians are $a_{n-1}$ and $a_n$. The difference is $|a_n - a_{n-1}|$.
        //
        // Can we do better?
        // Suppose the medians are $M_1$ and $M_2$.
        // $M_1$ must be some $a_i$ and $M_2$ must be some $a_j$.
        // To make $a_i$ a median of a class of size $2k_1+1$, we need $k_1$ elements $\le a_i$ and $k_1$ elements $\ge a_i$.
        // This means there must be at least $k_1$ elements before $a_i$ in the full sorted array, and at least $k_1$ elements after $a_i$.
        // So $i \ge k_1$ and $2n-1-i \ge k_1$.
        //
        // Similarly for $a_j$ as median of a class of size $2k_2+1$:
        // $j \ge k_2$ and $2n-1-j \ge k_2$.
        //
        // The total number of elements used is $2k_1+1 + 2k_2+1 = 2n$.
        // So $2(k_1+k_2+1) = 2n \implies k_1+k_2+1 = n$.
        //
        // This means $k_1+k_2 = n-1$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are the first $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are the last $n$ elements.
        //
        // If we pick $a_i$ as median for one class and $a_j$ as median for the other,
        // and assume $i < j$.
        //
        // The elements $a_0, \dots, a_{i-1}$ are $i$ elements.
        // The elements $a_{i+1}, \dots, a_{j-1}$ are $j-1-i$ elements.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are $2n-1-j$ elements.
        //
        // For $a_i$ to be a median, it needs $k_1$ elements before it and $k_1$ elements after it.
        // For $a_j$ to be a median, it needs $k_2$ elements before it and $k_2$ elements after it.
        //
        // The total number of elements before $a_i$ is $i$. So $k_1 \le i$.
        // The total number of elements after $a_j$ is $2n-1-j$. So $k_2 \le 2n-1-j$.
        //
        // The elements between $a_i$ and $a_j$ (exclusive) are $a_{i+1}, \dots, a_{j-1}$. There are $j-1-i$ such elements.
        // These elements can be used for either class.
        //
        // The total number of elements available for "before $a_i$" and "before $a_j$" is $i + (j-1-i) = j-1$.
        // The total number of elements available for "after $a_i$" and "after $a_j$" is $(j-1-i) + (2n-1-j) = 2n-2-i$.
        //
        // This is getting complicated. The simple solution is usually the correct one for competitive programming.
        // The minimum difference will be between adjacent elements in the sorted array.
        // The question is which adjacent elements can be medians.
        //
        // The specific indices $a_{n-1}$ and $a_n$ are special.
        // $a_{n-1}$ is the largest of the first $n$ elements.
        // $a_n$ is the smallest of the last $n$ elements.
        //
        // The partition described above (Class 1 = $\{a_{n-1}\}$, Class 2 = all others) is valid.
        // Class 1 has size 1, median $a_{n-1}$.
        // Class 2 has size $2n-1$. Its elements are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // When sorted, these are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The median of $2n-1$ elements is the $n$-th element (1-indexed).
        // In this sorted list, the $n$-th element is $a_n$.
        // So the medians are $a_{n-1}$ and $a_n$. The difference is $|a_n - a_{n-1}|$.
        //
        // This partition is always possible and satisfies all conditions:
        // 1. Each student assigned to exactly one class. (Yes, $a_{n-1}$ to C1, rest to C2).
        // 2. Each class has an odd number of students. (Yes, 1 and $2n-1$ are odd).
        //
        // Is this the minimum possible difference?
        // Suppose we have two medians $M_1$ and $M_2$.
        // $M_1$ must be some $a_i$ and $M_2$ must be some $a_j$.
        // Let $M_1 \le M_2$. So $a_i \le a_j$.
        //
        // For $a_i$ to be a median of a class of size $2k_1+1$, it needs $k_1$ elements $\le a_i$ and $k_1$ elements $\ge a_i$.
        // For $a_j$ to be a median of a class of size $2k_2+1$, it needs $k_2$ elements $\le a_j$ and $k_2$ elements $\ge a_j$.
        //
        // The total number of elements is $2n$.
        // The total number of elements needed for the "left side" of $a_i$ and $a_j$ is $k_1+k_2$.
        // The total number of elements needed for the "right side" of $a_i$ and $a_j$ is $k_1+k_2$.
        // We know $k_1+k_2 = n-1$.
        //
        // So we need $n-1$ elements to the left of $a_i$ and $a_j$ combined, and $n-1$ elements to the right of $a_i$ and $a_j$ combined.
        //
        // The elements $a_0, \dots, a_{2n-1}$ are sorted.
        // The elements $a_0, \dots, a_{n-2}$ are $n-1$ elements.
        // The elements $a_{n+1}, \dots, a_{2n-1}$ are $n-1$ elements.
        //
        // If $a_i$ is a median, it must have at least $k_1$ elements to its left. So $i \ge k_1$.
        // If $a_j$ is a median, it must have at least $k_2$ elements to its right. So $2n-1-j \ge k_2$.
        //
        // Summing these: $i + (2n-1-j) \ge k_1+k_2 = n-1$.
        // $i - j + 2n - 1 \ge n-1$.
        // $i - j + n \ge 0$.
        // $j - i \le n$.
        //
        // This means the indices of the medians cannot be too far apart.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        // Any median $M_1$ must be $\ge a_0$. Any median $M_2$ must be $\le a_{2n-1}$.
        //
        // The minimum difference is always achieved by $a_n - a_{n-1}$.
        // This is a standard result for problems of this type.
        // When you have $2N$ items and you need to split them into two groups,
        // the optimal split for minimizing difference between "middle" elements
        // often involves splitting at the $N$-th and $(N+1)$-th elements.
        //
        // Example 1: n=1, 2n=2 students. a = [1, 1].
        // Sorted: [1, 1].
        // $a_{n-1} = a_0 = 1$. $a_n = a_1 = 1$.
        // Difference: $|1-1|=0$. Correct.
        //
        // Example 2: n=3, 2n=6 students. a = [6, 5, 4, 1, 2, 3].
        // Sorted: [1, 2, 3, 4, 5, 6].
        // $n=3$. $a_{n-1} = a_2 = 3$. $a_n = a_3 = 4$.
        // Difference: $|4-3|=1$. Correct.
        //
        // Example 3: n=5, 2n=10 students. a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16].
        // Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // $n=5$. $a_{n-1} = a_4 = 8$. $a_n = a_5 = 13$.
        // Difference: $|13-8|=5$. Correct.
        //
        // The logic seems sound. The minimum difference is always $a_n - a_{n-1}$ after sorting.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k_max = n / m; // Number of multiples of m up to n

        // The sequence of last digits (i*m)%10 is periodic with period 10.
        // (i*m)%10 = ((i%10) * (m%10))%10 is not generally true.
        // For example, (1*14)%10 = 4, (2*14)%10 = 8, (3*14)%10 = 2, (4*14)%10 = 6, (5*14)%10 = 0,
        // (6*14)%10 = 4, (7*14)%10 = 8, (8*14)%10 = 2, (9*14)%10 = 6, (10*14)%10 = 0.
        // The sequence of last digits is (m%10), (2m%10), ..., (10m%10).
        // This sequence repeats every 10 terms.
        // The sum of these 10 terms is constant.

        std::vector<long long> last_digits_cycle(10);
        long long sum_of_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            last_digits_cycle[i - 1] = (static_cast<long long>(i) * m) % 10;
            sum_of_cycle += last_digits_cycle[i - 1];
        }

        long long num_full_cycles = k_max / 10;
        long long remaining_terms = k_max % 10;

        long long total_sum = num_full_cycles * sum_of_cycle;

        for (int i = 0; i < remaining_terms; ++i) {
            total_sum += last_digits_cycle[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
