int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;
        if (d == 0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Ensure a >= b for consistent output, though problem doesn't strictly require it.
            // The problem asks for *two* numbers, so (a,b) and (b,a) are equivalent.
            // The example output for d=5 shows a > b.
            // The example output for d=4 shows a = b.
            // The example output for d=69 shows a > b.
            // So, we can just print a1 and b1 directly.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. Its length is 1.
        // min_idx and max_idx are initialized to pos[1].
        // The current segment is [pos[1], pos[1]].
        // Its length is max_idx - min_idx + 1 = 1.
        // Its min value is 1, max value is 1.
        // So for m=1, it's beautiful.

        // For m > 1, we expand the segment to include 'm'.
        // The new segment must contain all numbers from 1 to m.
        // This means it must contain 'm'.
        // We update min_idx and max_idx to cover the range [1, m].
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // A number 'm' is beautiful if there exists a subsegment
        // [p_l, ..., p_r] that is a permutation of [1, ..., m].
        // This implies:
        // 1. The length of the subsegment (r - l + 1) must be m.
        // 2. The minimum value in the subsegment must be 1.
        // 3. The maximum value in the subsegment must be m.
        //
        // The current min_idx and max_idx define the smallest contiguous
        // subsegment of p that contains all numbers from 1 to m.
        // Let this subsegment be p[min_idx ... max_idx].
        //
        // Condition 2 and 3 are guaranteed by how min_idx and max_idx are updated.
        // The only remaining condition is that its length must be m.
        // The length of this subsegment is (max_idx - min_idx + 1).
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

