    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Adjust elements to the left of the median
    // They must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // They must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_val: minimum possible value for a[i] if it's part of an increasing sequence starting from 0
    // a_i' >= i
    std::vector<long long> prefix_min_val(n);
    for (int i = 0; i < n; ++i) {
        prefix_min_val[i] = i;
    }

    // Calculate suffix_min_val: minimum possible value for a[i] if it's part of a decreasing sequence ending at 0
    // a_i' >= (n-1) - i
    std::vector<long long> suffix_min_val(n);
    for (int i = 0; i < n; ++i) {
        suffix_min_val[i] = (n - 1) - i;
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) { // k is 0-indexed peak position
        // Check if a[k] can be the peak
        // For elements before k: a[i] must be >= i
        // For elements after k: a[i] must be >= (n-1) - i
        // And a[k] must be strictly greater than a[k-1] (if k>0) and a[k+1] (if k<n-1)
        // The minimum value for a[k] to be a peak is max(k, (n-1)-k) + 1
        // No, this is not correct. The minimum value for a[k] is just k if it's the end of an increasing sequence
        // or (n-1)-k if it's the start of a decreasing sequence.
        // For a[k] to be a peak, it must be strictly greater than its neighbors.
        // If we choose a_i' = i for i < k, and a_i' = (n-1)-i for i > k,
        // then a_k' must be > k-1 (if k>0) and > (n-1)-(k+1) (if k<n-1).
        // The smallest possible value for a_k' is max(k, (n-1)-k).
        // If k=0, a_0' must be > a_1'. Smallest a_0' is (n-1)-0 = n-1.
        // If k=n-1, a_{n-1}' must be > a_{n-2}'. Smallest a_{n-1}' is n-1.
        // If 0 < k < n-1, a_k' must be > k-1 and > (n-1)-(k+1).
        // The smallest value for a_k' is max(k, (n-1)-k).
        // So, we need a[k] >= max(k, (n-1)-k).

        // Let's re-evaluate the condition for a[k] to be a peak.
        // We need a_i' = i for i < k.
        // We need a_i' = (n-1)-i for i > k.
        // For a_k' to be a peak, it must be strictly greater than a_{k-1}' (if k>0) and a_{k+1}' (if k<n-1).
        // If k=0, a_0' must be >= 0. And a_0' > a_1'. Smallest a_1' is (n-1)-1. So a_0' must be >= (n-1)-1 + 1 = n-1.
        // If k=n-1, a_{n-1}' must be >= 0. And a_{n-1}' > a_{n-2}'. Smallest a_{n-2}' is n-2. So a_{n-1}' must be >= n-2 + 1 = n-1.
        // If 0 < k < n-1, a_k' must be > a_{k-1}' and > a_{k+1}'.
        // Smallest a_{k-1}' is k-1. Smallest a_{k+1}' is (n-1)-(k+1).
        // So a_k' must be >= max(k-1, (n-1)-(k+1)) + 1.
        // This simplifies to a_k' >= max(k, n-1-k).
        // So we need a[k] >= max(k, n-1-k).

        if (a[k] >= std::max(prefix_min_val[k], suffix_min_val[k])) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

