    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements to be placed (potential P[i])
    for (int i = 0; i < n; ++i) { // Pointer for original positions (A_sorted[i])
        // We are trying to find an element a[j] such that a[j] > a[i]
        // If a[j] is not greater than a[i], we need a larger element, so increment j.
        // We must ensure j is always ahead of or at i, and within bounds.
        // The condition j < n is implicitly handled by the loop for i,
        // as j will not exceed n if i does not.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        // If we found such an element a[j] (meaning j is within bounds),
        // we can place a[j] at position i. This contributes to our count.
        // Then we move to the next original position (i+1) and the next available element (j+1).
        if (j < n) {
            count++;
            j++; // This element a[j] is now "used", move to the next available element.
        } else {
            // If j reaches n, it means there are no more elements in 'a'
            // that are greater than the current a[i] or any subsequent a[k] (k > i).
            // So we can stop.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order based on F(N, K) property.
    // F(N, K) = N / (K+1).
    // To maximize sum F(A'_i, B_i) = sum A'_i / (B_i + 1),
    // we want to pair large A'_i with small (B_i + 1), which means small B_i.
    // So, sort A ascending and B ascending.
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest A value should be paired with the i-th smallest B value.
        // The original index of b_elements[i] tells us where this pair should go in the output.
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
    } else {
        // Box 1: (-inf, -1]
        // Final product must be negative and magnitude >= 1
        // Number of negative factors must be odd.
        // At least one factor must have magnitude >= 1, or multiple factors combine to magnitude >= 1.
        // If A+B is odd, the final sign can be negative.
        // If A+B is even, the final sign can be positive.

        // Can it be Box 1?
        // Need odd number of negative factors (A+B is odd).
        // Need magnitude >= 1.
        // If A > 0 or D > 0, we can always achieve magnitude >= 1.
        // If A=0 and D=0, then all initial toys are in (-1, 1).
        //   If B+C > 0, then all products will be in (-1, 1). So Box 1 is impossible.
        //   Unless B+C=0, which means A+D > 0.
        // So, if A+B is odd AND (A > 0 or D > 0 or (B+C == 0 and A+D > 0)), then Box 1 is possible.
        // The condition (A > 0 or D > 0 or (B+C == 0 and A+D > 0)) simplifies to A+D > 0.
        // If A+D > 0, we can always make magnitude >= 1.
        // If A+D == 0, then all toys are in B or C. All products will be in (-1, 1). So Box 1 is impossible.
        if ((A + B) % 2 == 1 && (A > 0 || D > 0)) {
            ans1 = "Ya";
        }

        // Can it be Box 2?
        // Need odd number of negative factors (A+B is odd).
        // Need magnitude < 1.
        // This is possible if we can make all intermediate products have magnitude < 1.
        // This is always possible if A=0 and D=0 (all toys in B or C).
        // If A > 0 or D > 0, we need to be careful.
        // If A+B is odd:
        //   If A=0 and D=0: all toys are in B or C. Product will be in (-1, 1). So Box 2 is possible.
        //   If A > 0 or D > 0:
        //     We need to ensure the final product has magnitude < 1.
        //     This is possible if we can "dilute" the large magnitudes.
        //     Example: -3, -0.5, -0.5, 3
        //     (-0.5)*(-0.5) = 0.25 (Box 3)
        //     (-3)*(0.25) = -0.75 (Box 2)
        //     (-0.75)*(3) = -2.25 (Box 1) -- this is not Box 2
        //     Example: -3, -0.33, -0.25, 3
        //     (-3)*(-0.33) = 0.99 (Box 3)
        //     (0.99)*(3) = 2.97 (Box 4)
        //     (2.97)*(-0.25) = -0.7425 (Box 2) -- this is Box 2
        // The key is that if we have at least one toy in B or C, we can use it to reduce magnitude.
        // If A+B is odd:
        //   If B+C > 0: we can always make magnitude < 1.
        //   If B+C == 0: then all toys are in A or D.
        //     If A > 0 and D > 0: we can make magnitude < 1 if we have enough toys to "cancel" magnitudes.
        //       e.g., -2, 1.5, 0.1 (from B/C) -> -2*1.5 = -3, -3*0.1 = -0.3 (Box 2)
        //       But if B+C=0, we don't have 0.1.
        //       If B+C=0, all toys are in A or D. Products will always have magnitude >= 1. So Box 2 is impossible.
        // So, if A+B is odd AND B+C > 0, then Box 2 is possible.
        if ((A + B) % 2 == 1 && (B > 0 || C > 0)) {
            ans2 = "Ya";
        }

        // Can it be Box 3?
        // Need even number of negative factors (A+B is even).
        // Need magnitude < 1.
        // Similar logic to Box 2, but for positive values.
        // If A+B is even:
        //   If B+C > 0: we can always make magnitude < 1.
        //   If B+C == 0: then all toys are in A or D. Products will always have magnitude >= 1. So Box 3 is impossible.
        // So, if A+B is even AND B+C > 0, then Box 3 is possible.
        if ((A + B) % 2 == 0 && (B > 0 || C > 0)) {
            ans3 = "Ya";
        }

        // Can it be Box 4?
        // Need even number of negative factors (A+B is even).
        // Need magnitude >= 1.
        // Similar logic to Box 1, but for positive values.
        // If A+B is even:
        //   If A > 0 or D > 0: we can always achieve magnitude >= 1.
        //   If A=0 and D=0: then all toys are in B or C. All products will be in (-1, 1). So Box 4 is impossible.
        // So, if A+B is even AND (A > 0 || D > 0), then Box 4 is possible.
        if ((A + B) % 2 == 0 && (A > 0 || D > 0)) {
            ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

