    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Determine the most frequent move the bot makes
        // If counts are equal, any choice is fine.
        // The problem statement implies R, S, P are distinct and ordered.
        // Let's pick 'R' if R count is max, 'S' if S count is max (and R count is not greater),
        // 'P' if P count is max (and R, S counts are not greater).
        // This is equivalent to iterating through R, S, P and updating if current count is strictly greater.
        // Or, if we want to be robust to ties, we can just pick one.
        // The problem asks for *any* optimal answer.
        // So, we can just iterate and pick the first one that has max_count.

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }

        // The move we should play to beat the most frequent bot move
        char my_winning_move = get_winning_move(most_frequent_bot_move);

        // Construct the output string
        for (size_t i = 0; i < s.length(); ++i) {
            std::cout << my_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

