#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (n % 2 == 1) { // N is odd
            if (chanek_turn) {
                chanek_coins += 1;
            } else {
                opponent_coins += 1;
            }
            n -= 1;
        } else { // N is even
            // Check if N is a power of 2
            // A number is a power of 2 if it has only one bit set in its binary representation.
            // n > 0 && (n & (n - 1)) == 0
            if ((n & (n - 1)) == 0) { // N is a power of 2
                // If N is a power of 2, taking N/2 leaves N/2, which is also a power of 2.
                // This means the current player can force the next player to always face a power of 2.
                // Taking 1 coin leaves N-1, which is odd.
                // If current player takes N/2, they get N/2 coins.
                // If current player takes 1, they get 1 coin.
                // The opponent will then face N-1 (odd).
                // If N is a power of 2, the optimal strategy is to take 1 coin.
                // Example: N=4.
                // Chanek takes 1. N=3. Chanek: 1. Opponent's turn.
                // Opponent takes 1. N=2. Opponent: 1. Chanek's turn.
                // Chanek takes 1. N=1. Chanek: 2. Opponent's turn.
                // Opponent takes 1. N=0. Opponent: 2. Chanek: 2.
                // Total: Chanek 2, Opponent 2.
                //
                // Example: N=4.
                // Chanek takes N/2 (2). N=2. Chanek: 2. Opponent's turn.
                // Opponent takes N/2 (1). N=1. Opponent: 1. Chanek's turn.
                // Chanek takes 1. N=0. Chanek: 3. Opponent: 1.
                // Total: Chanek 3, Opponent 1.
                //
                // So if N is a power of 2, the current player takes N/2.
                // This is because taking N/2 gives more coins than taking 1,
                // and the opponent will face a smaller power of 2, which is still even.
                // The opponent will also take N/2 of the remaining.
                // This continues until N=1.
                // The player who faces N=2 will take 1.
                // The player who faces N=1 will take 1.
                //
                // Let's re-evaluate the power of 2 case.
                // If N is a power of 2, say 2^k.
                // Current player takes N/2 = 2^(k-1). Remaining N/2 = 2^(k-1).
                // Next player faces 2^(k-1).
                // This continues until N=2.
                // When N=2, current player takes 1. Remaining N=1.
                // Next player faces N=1, takes 1. Remaining N=0.
                //
                // So, if N is a power of 2, the current player takes N/2.
                // This is the greedy choice.
                if (chanek_turn) {
                    chanek_coins += n / 2;
                } else {
                    opponent_coins += n / 2;
                }
                n /= 2;
            } else { // N is even but not a power of 2
                // N is even, not a power of 2.
                // This means N can be written as 2^k * M, where M is odd and M > 1.
                // Option 1: Take 1 coin. N becomes N-1 (odd).
                // Option 2: Take N/2 coins. N becomes N/2.
                // N/2 = 2^(k-1) * M. This is still even if k > 1.
                // If k=1, N = 2 * M. N/2 = M (odd).
                //
                // If current player takes 1, next player faces N-1 (odd).
                // Next player takes 1. Then current player faces N-2 (even).
                //
                // If current player takes N/2:
                //   If N/2 is odd (i.e., N = 2 * M, M odd):
                //     Current player takes N/2. Next player faces M (odd).
                //     Next player takes 1. Current player faces M-1 (even).
                //   If N/2 is even (i.e., N = 2^k * M, k > 1):
                //     Current player takes N/2. Next player faces N/2 (even).
                //
                // The optimal strategy for an even N that is not a power of 2 is to take N/2.
                // This is because taking N/2 gives more coins than taking 1.
                // And the remaining N/2 is either odd (which forces the opponent to take 1)
                // or it's another even number (which the opponent will also try to take N/2 from).
                // Taking N/2 is always better than taking 1 if N is even and not a power of 2.
                if (chanek_turn) {
                    chanek_coins += n / 2;
                } else {
                    opponent_coins += n / 2;
                }
                n /= 2;
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

