// Function to check if a subarray is a permutation of its length
// This version uses a frequency array and checks max element
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int length) {
    if (length <= 0) return false; // A permutation must have positive length
    if (end_idx - start_idx + 1 != length) return false; // Length mismatch

    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = start_idx; i <= end_idx; ++i) {
        if (arr[i] < 1 || arr[i] > length) {
            return false; // Element out of range [1, length]
        }
        if (seen[arr[i]]) {
            return false; // Duplicate element
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == length; // Max element must be equal to length
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix permutation validity
    // prefix_max[i] stores the maximum value in a[0...i]
    // prefix_is_perm[i] is true if a[0...i] is a permutation of length (i+1)
    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n, false);
    std::vector<bool> seen_prefix(n + 1, false); // Max possible value is n-1, but length can be n. Use n+1 for safety.
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] < 1 || a[i] > i + 1) { // Element must be in [1, i+1]
            possible_prefix = false;
        }
        if (seen_prefix[a[i]]) { // Duplicate found
            possible_prefix = false;
        }
        seen_prefix[a[i]] = true;
        if (a[i] > current_max_prefix) {
            current_max_prefix = a[i];
        }
        prefix_max[i] = current_max_prefix;
        if (possible_prefix && current_max_prefix == i + 1) {
            prefix_is_perm[i] = true;
        }
    }

    // Precompute suffix permutation validity
    // suffix_max[i] stores the maximum value in a[i...n-1]
    // suffix_is_perm[i] is true if a[i...n-1] is a permutation of length (n-i)
    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n, false);
    std::vector<bool> seen_suffix(n + 1, false); // Max possible value is n-1, but length can be n. Use n+1 for safety.
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] < 1 || a[i] > current_len) { // Element must be in [1, current_len]
            possible_suffix = false;
        }
        if (seen_suffix[a[i]]) { // Duplicate found
            possible_suffix = false;
        }
        seen_suffix[a[i]] = true;
        if (a[i] > current_max_suffix) {
            current_max_suffix = a[i];
        }
        suffix_max[i] = current_max_suffix;
        if (possible_suffix && current_max_suffix == current_len) {
            suffix_is_perm[i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1 (since both l1 and l2 must be non-zero)
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        // Check if first l1 elements form a permutation of length l1
        // This is equivalent to checking prefix_is_perm[l1-1]
        bool p1_ok = prefix_is_perm[l1 - 1];

        // Check if last l2 elements form a permutation of length l2
        // This is equivalent to checking suffix_is_perm[l1]
        bool p2_ok = suffix_is_perm[l1];

        if (p1_ok && p2_ok) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

