// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest divisor x of p such that x is not divisible by q.
        // This means x must not contain all prime factors of q with sufficient powers.
        // Let q = f1^e1 * f2^e2 * ... * fk^ek.
        // If x is divisible by q, then x must be divisible by f_i^e_i for all i.
        // To make x not divisible by q, we must remove at least one f_i^e_i from its prime factorization.
        // To maximize x, we should remove the minimum necessary.
        // For each prime factor f_i of q, we can try to divide p by f_i until it's no longer divisible by q.
        // The largest such x will be p / (f_i^k) where f_i^k is the smallest power of f_i such that p / (f_i^k) is not divisible by q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q
            // Or, more precisely, divide current_p by f until current_p is no longer divisible by q
            // while current_p is divisible by q, divide current_p by f
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

