// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    // The pattern is built from right to left, so it's already in the correct order
    // for map keys (e.g., 123 -> "101" for 3,2,1 parities)
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string
    // The key will be the parity pattern string, and the value will be its count.
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Normalize the query pattern to a fixed length (18 digits, max for long long)
            // by padding with '0's from the left.
            // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we effectively compare up to the maximum possible length.
            // Since numbers are up to 10^18 - 1 (18 digits), we can pad to 18.
            // The `get_parity_pattern` function already produces a string that represents
            // the number's parity digits from right to left.
            // So, if the query pattern is "010", it means rightmost is even, second is odd, third is even.
            // This is exactly how `get_parity_pattern` would represent a number like 123 (3 odd, 2 even, 1 odd -> "101").
            // So, we just need to ensure the query pattern is also treated as right-to-left.
            // The problem statement implies padding from the left for *decimal notation*.
            // For example, 92 with pattern 010.
            // 92 -> 2 (even), 9 (odd). Pattern 010 -> 0 (even), 1 (odd), 0 (even).
            // The comparison is:
            // 2 vs 0 (match)
            // 9 vs 1 (match)
            // (implied 0) vs 0 (match)
            // This means we should pad the *query pattern* with '0's to the right to match the length of the number's pattern.
            // Or, more simply, pad the query pattern with '0's to the right to a fixed max length.
            // Example: query "1" -> "100000000000000000" (18 '0's after '1')
            // Example: query "010" -> "010000000000000000"
            // The `get_parity_pattern` function for 92 would return "01".
            // For 2212 it would return "0100".
            // For 50 it would return "01".
            // The map keys are these "right-to-left" parity strings.
            // So, for a query pattern `s`, we need to pad it with '0's to the right
            // to match the maximum possible length of a number's parity pattern.
            // Max length for 10^18-1 is 18 digits.

            // Pad the query pattern `s` with '0's to the right to length 18.
            // This ensures that if a number's pattern is longer than `s`,
            // the extra digits of the number are compared against '0's (even).
            // Example: s="010", number 2212 -> pattern "0100".
            // If we query for "010", we need to match "010", "0100", "01000", etc.
            // This means the query pattern should be effectively "010..."
            // So, we pad `s` with '0's to the right.
            std::string padded_s = s;
            if (padded_s.length() < 18) {
                padded_s.append(18 - padded_s.length(), '0');
            }

            // Now, iterate through the map and check for matches.
            // A number's pattern `num_pat` matches `padded_s` if `num_pat` is a prefix of `padded_s`.
            // Example: padded_s = "010000..."
            // num_pat = "01" (for 92) -> matches because "01" is a prefix of "010000..."
            // num_pat = "010" (for 50) -> matches
            // num_pat = "0100" (for 2212) -> matches

            int match_count = 0;
            for (auto const& [key_pattern, count] : counts) {
                // Check if key_pattern is a prefix of padded_s
                // Or, more accurately, if padded_s is a prefix of key_pattern
                // when considering the "supplemented with 0s" rule.
                // Let's re-evaluate the padding logic.
                // The problem states: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
                // "Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
                // This means we should compare digit by digit, and if one runs out, assume 0s.
                // Example: s = "010", number 92.
                // 92 -> "01" (rightmost 2 is even, next 9 is odd)
                // s = "010" (rightmost 0 is even, next 1 is odd, next 0 is even)
                // Compare:
                // 0 (from 92's "01") vs 0 (from s "010") -> match
                // 1 (from 92's "01") vs 1 (from s "010") -> match
                // (implied 0 from 92) vs 0 (from s "010") -> match
                // This means the number's pattern must be a prefix of the query pattern,
                // OR the query pattern must be a prefix of the number's pattern.
                // And the common prefix must match.
                // This is equivalent to saying:
                // If `num_pat` is "01" and `query_pat` is "010", they match.
                // If `num_pat` is "0100" and `query_pat` is "010", they match.
                // This means we should normalize both to a fixed length (e.g., 18) by padding with '0's.
                // `get_parity_pattern` already gives us the "right-to-left" string.
                // So, for a number `N`, its pattern is `P_N`.
                // For a query `S`, its pattern is `P_S`.
                // We need to compare `P_N` and `P_S` after padding both to length 18 with '0's.
                // Let's call these `P_N_padded` and `P_S_padded`.
                // If `P_N_padded == P_S_padded`, then they match.

                // The `get_parity_pattern` function returns a string like "01" for 92.
                // The query pattern `s` is given as "010".
                // We need to pad `s` to 18 characters with '0's on the right.
                // So "010" becomes "010000000000000000".
                // And for each `key_pattern` in the map (e.g., "01" for 92),
                // we also pad it to 18 characters with '0's on the right.
                // So "01" becomes "010000000000000000".
                // Then we compare these padded strings.

                std::string key_padded = key_pattern;
                if (key_padded.length() < 18) {
                    key_padded.append(18 - key_padded.length(), '0');
                }

                if (key_padded == padded_s) {
                    match_count += count;
                }
            }
            std::cout << match_count << "\n";
        }
    }

    return 0;
}

#include <iostream>
