int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1, y)
            // If f1 == 0, robot cannot move left.
            // So, if x_i > X, it needs to move left. If it can't, it can't reach X.
            // This means X must be >= x_i.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2: can move up (x, y+1)
            // If f2 == 0, robot cannot move up.
            // So, if y_i < Y, it needs to move up. If it can't, it can't reach Y.
            // This means Y must be <= y_i.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3: can move right (x+1, y)
            // If f3 == 0, robot cannot move right.
            // So, if x_i < X, it needs to move right. If it can't, it can't reach X.
            // This means X must be <= x_i.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (x, y-1)
            // If f4 == 0, robot cannot move down.
            // So, if y_i > Y, it needs to move down. If it can't, it can't reach Y.
            // This means Y must be >= y_i.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. The problem guarantees that if a solution exists,
            // one such point has coordinates within [-10^5, 10^5].
            // We can pick any point within the valid range.
            // For example, (min_x, min_y) is a valid choice.
            // We need to clamp it to the guaranteed range if it falls outside,
            // but since the problem guarantees a solution within [-10^5, 10^5]
            // if one exists, and our bounds are derived from robot positions
            // which are also within [-10^5, 10^5], min_x and min_y will naturally
            // be within a reasonable range.
            // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
            // The initial coordinates are up to 10^5.
            // min_x, max_x, min_y, max_y will be within [-10^5, 10^5] if all robots are within that range.
            // The initial large values for min/max are just to represent infinity.
            // The actual bounds will be set by robot coordinates.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Since MOD is prime (10^9 + 7), inverse of 2 is (MOD + 1) / 2.
    long long sum_r_term;
    if (b == 1) { // If b=1, then r cannot be in [1, b-1], so sum_r is 0.
        sum_r_term = 0;
    } else {
        long long b_minus_1 = (b - 1) % MOD;
        long long b_val = b % MOD;
        long long inv2 = (MOD + 1) / 2; // Modular inverse of 2 modulo MOD
        sum_r_term = (b_minus_1 * b_val) % MOD;
        sum_r_term = (sum_r_term * inv2) % MOD;
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k_term;
    long long a_val = a % MOD;
    long long b_val = b % MOD;
    long long a_plus_1 = (a + 1) % MOD;
    long long inv2 = (MOD + 1) / 2; // Modular inverse of 2 modulo MOD

    long long sum_k_part1 = (a_val * a_plus_1) % MOD;
    sum_k_part1 = (sum_k_part1 * inv2) % MOD;
    sum_k_part1 = (sum_k_part1 * b_val) % MOD;

    long long sum_k_part2 = a_val;

    sum_k_term = (sum_k_part1 + sum_k_part2) % MOD;

    // The total sum is (sum_r_term * sum_k_term) % MOD
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
