int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos_by_char(26);
    for (int i = 0; i < L; ++i) {
        pos_by_char[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char char0 = s[k_actual];

        std::vector<int> possible_k_initial;
        for (int pk : pos_by_char[char0 - 'a']) {
            possible_k_initial.push_back(pk);
        }

        if (possible_k_initial.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < L; ++p) {
            char char_p = s[(k_actual + p) % L];

            int count_unique_k = 0;
            for (int pk : possible_k_initial) {
                if (s[(pk + p) % L] == char_p) {
                    count_unique_k++;
                }
            }

            if (count_unique_k == 1) {
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 1.0);
            } else {
                // If count_unique_k > 1, Vasya cannot uniquely determine k with this p.
                // The problem statement says "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                // So, if count_unique_k > 1, Vasya loses for this (k_actual, p) pair.
                // The probability of winning for this (k_actual, p) is 0.
                // Vasya wants to maximize his win probability, so he chooses p to maximize it.
                // If all p lead to count_unique_k > 1, then max_win_prob_for_k_actual remains 0.
            }
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int x = 0; x <= 9; ++x) {
        std::string t(n, ' ');
        int last1 = -1; // Last digit in S1
        int first2 = -1; // First digit in S2
        bool possible_x = true;

        // First pass: assign digits based on x
        // Digits < x go to S1
        // Digits > x go to S2
        // Digits == x are undecided
        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                t[i] = '1';
            } else if (d[i] > x) {
                t[i] = '2';
            }
        }

        // Second pass: assign digits == x
        // The first occurrence of x and subsequent x's that maintain non-decreasing S1 go to S1.
        // After a certain point, x's must go to S2 to maintain non-decreasing S2.
        // This point is determined by the first x that is greater than or equal to the last digit of S1.
        // All subsequent x's must go to S2.

        // Find the split point for 'x' digits
        int split_idx = -1;
        for (int i = 0; i < n; ++i) {
            if (d[i] == x) {
                if (split_idx == -1) { // First 'x' encountered
                    split_idx = i;
                }
            }
        }

        // If no 'x' digits, all 'undecided' are already handled.
        // If there are 'x' digits, we need to find the exact split.
        // The strategy is: all 'x's before the first 'x' that is followed by a '2' (a digit > x) go to '1'.
        // All 'x's after that go to '2'.
        // More precisely, all 'x's that appear before any digit > x are candidates for color 1.
        // All 'x's that appear after any digit > x are candidates for color 2.
        // The split point for 'x's is the first 'x' that must be colored '2' to maintain sortedness.
        // This means all 'x's before this split point are colored '1', and all 'x's from this split point onwards are colored '2'.

        // Let's refine the split point for 'x'.
        // We want to find the largest index `k` such that all `d[i] == x` for `i < k` can be colored '1',
        // and all `d[i] == x` for `i >= k` can be colored '2'.
        // This means `d[k]` (if it's `x`) should be the first `x` in `S2`.
        // So, all `d[i] == x` for `i < k` go to `S1`.
        // All `d[i] == x` for `i >= k` go to `S2`.
        // The condition is that `S1` must be non-decreasing and `S2` must be non-decreasing.
        // And `max(S1) <= min(S2)`.

        // Let's try a simpler greedy approach for 'x' digits:
        // Color '1' as many 'x's as possible, then color '2' the rest.
        // The split point for 'x's is where we transition from coloring '1' to coloring '2'.
        // This split point must be chosen such that all digits colored '1' form a non-decreasing sequence,
        // and all digits colored '2' form a non-decreasing sequence.
        // And the last '1' digit <= first '2' digit.

        // The critical observation is that if we have a digit `d[i] == x`, and `d[j] == x` for `j > i`,
        // and there is some `d[k] > x` for `i < k < j`, then `d[i]` must be '1' and `d[j]` must be '2'.
        // Because if `d[i]` is '2', then `d[k]` would be '2' before `d[i]` in `S2`, which is impossible.
        // If `d[j]` is '1', then `d[k]` would be '2' after `d[j]` in `S1`, which is impossible.

        // So, all 'x's that appear before any digit > x must be '1'.
        // All 'x's that appear after any digit > x must be '2'.
        // What about 'x's that appear between digits > x? This is not possible.
        // The sequence of digits > x must be non-decreasing.
        // The sequence of digits < x must be non-decreasing.

        // Let's find the first index `k` such that `d[k] == x` and all `d[i]` for `i < k` are either `< x` or `== x`.
        // And all `d[i]` for `i >= k` are either `> x` or `== x`.
        // This is not quite right.

        // The correct split for 'x' digits:
        // All `d[i] == x` that appear before any `d[j] > x` must be colored '1'.
        // All `d[i] == x` that appear after any `d[j] > x` must be colored '2'.
        // What about `d[i] == x` that appear *between* `d[j] > x` and `d[k] > x`?
        // This is the tricky part.

        // Let's try to find the first `d[i] == x` that we color '2'.
        // All `d[j] == x` for `j < i` must be '1'.
        // All `d[j] == x` for `j >= i` must be '2'.
        // This implies that for any `k < i`, if `d[k] > x`, then `d[k]` must be '2'.
        // And for any `k >= i`, if `d[k] < x`, then `d[k]` must be '1'.
        // This is already handled by the initial assignment.

        // The condition is that `S1` must be non-decreasing, `S2` must be non-decreasing, and `max(S1) <= min(S2)`.
        // `max(S1)` will be `x` if any `x` is colored '1', or `max(d_i < x)` otherwise.
        // `min(S2)` will be `x` if any `x` is colored '2', or `min(d_i > x)` otherwise.

        // Let's iterate through the digits and assign colors.
        // `last1_val` stores the last digit assigned to color 1.
        // `first2_val` stores the first digit assigned to color 2.
        // `t` is the coloring string.

        int current_last1 = -1;
        int current_first2 = -1;
        bool possible_current_x = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                if (d[i] < current_last1) { // S1 not non-decreasing
                    possible_current_x = false;
                    break;
                }
                if (current_first2 != -1 && d[i] > current_first2) { // d[i] < x but > first2, impossible
                    possible_current_x = false;
                    break;
                }
                t[i] = '1';
                current_last1 = d[i];
            } else if (d[i] > x) {
                if (d[i] < current_first2) { // S2 not non-decreasing
                    possible_current_x = false;
                    break;
                }
                if (current_last1 != -1 && d[i] < current_last1) { // d[i] > x but < last1, impossible
                    possible_current_x = false;
                    break;
                }
                t[i] = '2';
                if (current_first2 == -1) {
                    current_first2 = d[i];
                }
            } else { // d[i] == x
                // Try to assign to '1'
                if (d[i] >= current_last1 && (current_first2 == -1 || d[i] <= current_first2)) {
                    t[i] = '1';
                    current_last1 = d[i];
                } else { // Must assign to '2'
                    if (d[i] < current_first2) { // S2 not non-decreasing
                        possible_current_x = false;
                        break;
                    }
                    t[i] = '2';
                    if (current_first2 == -1) {
                        current_first2 = d[i];
                    }
                }
            }
        }

        if (possible_current_x) {
            std::cout << t << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting character for a path
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() <= 1) { // A character with 0 or 1 neighbor must be an endpoint of a path
            start_char = c;
            break;
        }
    }

    // If all characters in s have 2 neighbors, it means they form a cycle.
    // This is only possible if s itself forms a cycle, e.g., "abacaba" implies b-a-c.
    // If s is "abacaba", 'a' has neighbors 'b' and 'c'. 'b' has 'a'. 'c' has 'a'.
    // So 'b' and 'c' have 1 neighbor, 'a' has 2.
    // If all characters in used_in_s have 2 neighbors, it means they form a single cycle.
    // A single cycle of length > 2 is not possible on a linear keyboard.
    // A cycle of length 2 (e.g., "ababa") is not possible because s[i] != s[i+1].
    // So, there must be at least one character with 1 or 0 neighbors.
    // The only exception is if used_in_s is empty (s is empty), but s.length() >= 1.
    // Or if used_in_s has only one character (e.g., "aaaaa"), but s[i] != s[i+1].
    // So start_char will always be found.

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first step

        while (current_char != '\0' && visited_in_layout.find(current_char) == visited_in_layout.end()) {
            layout_str += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Check if all characters from s are included in the constructed path
    if (layout_str.length() != used_in_s.size()) {
        // This means there are multiple disconnected components or cycles.
        // For example, if s = "ab" and then "cd", these are two separate paths.
        // This is not allowed because the keyboard must be a single row.
        // The only way this can happen is if we have multiple paths that need to be connected.
        // But our algorithm only builds one path. If there are other characters in used_in_s
        // that are not part of the first path, it means they form another path/component.
        // This is not allowed.
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

