#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total balance
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain balance.
    // Key: balance, Value: number of jars removed from left
    std::map<int, int> left_balance_to_removed_count;
    left_balance_to_removed_count[0] = 0; // Removing 0 jars from left gives balance 0

    int current_left_balance = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_left_balance++;
        } else {
            current_left_balance--;
        }
        // Store the minimum number of jars removed to achieve this balance.
        // Since we iterate from n-1 down to 0, i.e., removing 1, 2, ..., n jars,
        // the first time we encounter a balance, it corresponds to the minimum
        // number of jars removed (n-i).
        if (left_balance_to_removed_count.find(current_left_balance) == left_balance_to_removed_count.end()) {
            left_balance_to_removed_count[current_left_balance] = n - i;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Case 1: No jars removed from the right side.
    // The remaining jars are a prefix of the left side.
    // The balance of remaining jars is initial_balance - current_left_balance.
    // We need this to be 0. So initial_balance = current_left_balance.
    // The number of jars removed from the left is left_balance_to_removed_count[initial_balance].
    if (left_balance_to_removed_count.count(initial_balance)) {
        min_removed_jars = std::min(min_removed_jars, left_balance_to_removed_count[initial_balance]);
    }

    // Iterate through removing jars from the right side
    int current_right_balance = 0;
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_right_balance++;
        } else {
            current_right_balance--;
        }
        int num_removed_right = i - n + 1; // Number of jars removed from right side

        // The balance of the remaining jars is initial_balance - current_right_balance - current_left_balance.
        // We need this to be 0.
        // So, current_left_balance = initial_balance - current_right_balance.
        int target_left_balance = initial_balance - current_right_balance;

        if (left_balance_to_removed_count.count(target_left_balance)) {
            int num_removed_left = left_balance_to_removed_count[target_left_balance];
            min_removed_jars = std::min(min_removed_jars, num_removed_left + num_removed_right);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

