int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Although problem states n >= 3, handle for completeness if it were allowed
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones(n, -1); // Stores index of nearest 1 to the left (inclusive)
    std::vector<int> right_ones(n, n); // Stores index of nearest 1 to the right (inclusive)
    std::vector<int> left_zeros(n, -1); // Stores index of nearest 0 to the left (inclusive)
    std::vector<int> right_zeros(n, n); // Stores index of nearest 0 to the right (inclusive)

    int last_one = -1;
    int last_zero = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            last_one = i;
        } else {
            last_zero = i;
        }
        left_ones[i] = last_one;
        left_zeros[i] = last_zero;
    }

    last_one = n;
    last_zero = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            last_one = i;
        } else {
            last_zero = i;
        }
        right_ones[i] = last_one;
        right_zeros[i] = last_zero;
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Current element is 0, it can become 1
            // Find nearest 1 to the left and right
            int l1 = left_ones[i];
            int r1 = right_ones[i];

            if (l1 != -1 && r1 != n) { // There are 1s on both sides
                int dist = std::min(i - l1, r1 - i);
                max_k = std::max(max_k, dist);
            }
        } else { // Current element is 1, it can become 0
            // Find nearest 0 to the left and right
            int l0 = left_zeros[i];
            int r0 = right_zeros[i];

            if (l0 != -1 && r0 != n) { // There are 0s on both sides
                int dist = std::min(i - l0, r0 - i);
                max_k = std::max(max_k, dist);
            }
        }
    }

    std::cout << max_k << "\n";

    std::vector<int> b(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // If original is 0, it becomes 1 if it's within max_k distance of two 1s
            int l1 = left_ones[i];
            int r1 = right_ones[i];
            if (l1 != -1 && r1 != n && (i - l1 <= max_k) && (r1 - i <= max_k)) {
                b[i] = 1;
            } else {
                b[i] = 0;
            }
        } else { // If original is 1, it becomes 0 if it's within max_k distance of two 0s
            int l0 = left_zeros[i];
            int r0 = right_zeros[i];
            if (l0 != -1 && r0 != n && (i - l0 <= max_k) && (r0 - i <= max_k)) {
                b[i] = 0;
            } else {
                b[i] = 1;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

