#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain any triple.
    // Initialize with n-1, meaning s[i...n-1] does not contain a triple.
    // This will be updated downwards.
    std::vector<int> max_r_for_l(n);
    for (int i = 0; i < n; ++i) {
        max_r_for_l[i] = n - 1;
    }

    // Iterate through all possible starting positions x (0-indexed)
    // and all possible step sizes k.
    // The condition is s_x = s_{x+k} = s_{x+2k}.
    // The indices are x, x+k, x+2k.
    // The length of this pattern is 2k+1.
    // The minimum k is 1.
    // The maximum k is such that x+2k < n.
    // So 2k < n-x, k < (n-x)/2.
    // The maximum k is (n-x-1)/2.
    // The maximum possible k is when x=0, k = (n-1)/2.
    // If n=1,2,3, no k is possible.
    // If n=4, x=0, k=1: s_0=s_1=s_2. x=1, k=1: s_1=s_2=s_3.
    // If n=5, x=0, k=1: s_0=s_1=s_2. x=1, k=1: s_1=s_2=s_3. x=2, k=1: s_2=s_3=s_4.
    //         x=0, k=2: s_0=s_2=s_4.

    // The maximum k we need to check is small.
    // If k is large, say k >= 9, then 2k+1 >= 19.
    // If we have a triple s_x = s_{x+k} = s_{x+2k}, then the length of the segment
    // is 2k+1.
    // If k >= 9, then 2k+1 >= 19.
    // Any substring of length 19 or more will contain a triple if one exists.
    // The problem states that if a triple exists, then l <= x and x+2k <= r.
    // This means the substring s[l-1...r-1] must contain the segment s[x...x+2k].
    // If we find a triple (x, k), then any (l, r) such that l-1 <= x and x+2k <= r-1
    // is a "good" pair.
    // We are counting "good" pairs. It's easier to count "bad" pairs (those that don't contain any triple)
    // and subtract from total.

    // A pair (l, r) is "bad" if the substring s[l-1...r-1] does NOT contain any triple.
    // Let's find the smallest r_min for each l such that s[l-1...r_min-1] contains a triple.
    // Then all (l, r) with r < r_min are bad.
    // For a fixed l (0-indexed), let min_r_idx be the smallest index such that s[l...min_r_idx] contains a triple.
    // If no such triple exists, min_r_idx = n.
    // Then for this l, the bad pairs are (l, l), (l, l+1), ..., (l, min_r_idx-1).
    // The number of bad pairs for this l is (min_r_idx - 1) - l + 1 = min_r_idx - l.
    // Sum this over all l.

    // Let's find the first occurrence of a triple.
    // For each starting index `i` (0-indexed), we want to find the smallest `j` such that
    // the substring `s[i...j]` contains a triple.
    // Let `min_end_idx[i]` be this `j`. If no such `j` exists, `min_end_idx[i] = n`.
    // Then for each `i`, the number of bad `(l, r)` pairs starting at `i` is `min_end_idx[i] - i`.
    // The total number of bad pairs is sum(min_end_idx[i] - i) for i from 0 to n-1.

    // We can iterate `i` from `n-1` down to `0`.
    // `min_end_idx[i]` can be initialized to `n`.
    // `min_end_idx[i]` will be `min(min_end_idx[i+1], current_triple_end_idx)`.
    // `current_triple_end_idx` is `x+2k` for a triple starting at `x` where `x >= i`.
    // This is not quite right. `min_end_idx[i]` is the smallest `j` such that `s[i...j]` contains a triple.
    // This means there exists `x, k` such that `i <= x` and `x+2k <= j`.
    // We need to find `min(x+2k)` over all `x, k` such that `i <= x`.

    // Let `last_triple_end[i]` be the smallest `j` such that `s[i...j]` contains a triple.
    // If no such triple exists, `last_triple_end[i] = n`.
    // We can compute this by iterating `i` from `n-1` down to `0`.
    // `last_triple_end[i]` will be `min(last_triple_end[i+1], current_triple_end_idx_if_x_is_i)`.
    // This is still not quite right. `last_triple_end[i]` should be `min(last_triple_end[i+1], min_j_for_x_eq_i)`.
    // `min_j_for_x_eq_i` is the smallest `x+2k` for a triple starting at `x=i`.

    // Let's re-evaluate the `max_r_for_l` array.
    // `max_r_for_l[i]` is the maximum `r` (0-indexed) such that `s[i...r]` does NOT contain any triple.
    // Initially, `max_r_for_l[i] = n-1`.
    // If we find a triple `s_x = s_{x+k} = s_{x+2k}`, then any substring `s[l...r]` that contains `s[x...x+2k]`
    // is a "good" substring.
    // This means for any `l <= x`, the `max_r_for_l[l]` cannot be greater than `x+2k-1`.
    // So, for each `l` from `0` to `x`, we update `max_r_for_l[l] = min(max_r_for_l[l], x+2k-1)`.
    // This is `O(N^2)` if we iterate `l` for each triple.

    // The maximum `k` we need to check is small.
    // If `k` is large, say `k >= 9`, then `2k+1 >= 19`.
    // If `s_x = s_{x+k} = s_{x+2k}` exists, then `x+2k` is the end of the pattern.
    // The maximum `k` to check is `(n-1)/2`.
    // However, the problem constraints on `k` are `1 <= k <= n`.
    // But `x+2k <= n` implies `2k <= n-x`. So `k <= (n-x)/2`.
    // The maximum `k` is `n/2`.
    // If `k` is large, say `k > 8`, then `2k+1 > 17`.
    // If we have a triple `s_x = s_{x+k} = s_{x+2k}`, then the substring `s[x...x+2k]` is "good".
    // Any `(l, r)` such that `l <= x` and `x+2k <= r` is a good pair.
    // The smallest `r` for a given `l` that makes `(l, r)` good is `x+2k`.
    // We are looking for `min_r_idx[l]` = `min(x+2k)` over all `x, k` such that `l <= x`.

    // Let's find all `x+2k` values for triples.
    // `min_valid_r[i]` = minimum `r` (0-indexed) such that `s[i...r]` contains a triple.
    // Initialize `min_valid_r[i] = n` for all `i`.
    // Iterate `x` from `0` to `n-1`.
    // Iterate `k` from `1` up to `(n-1-x)/2`.
    // If `s[x] == s[x+k] && s[x] == s[x+2k]`:
    //   Then `x+2k` is an end index of a triple starting at `x`.
    //   For all `l` from `0` to `x`, `min_valid_r[l] = min(min_valid_r[l], x+2k)`.
    // This is `O(N^3)` in worst case (N for x, N for k, N for l). Too slow.

    // Optimization:
    // `min_valid_r[l]` is non-decreasing as `l` decreases.
    // `min_valid_r[l] = min(min_valid_r[l+1], min_end_for_x_eq_l)`.
    // Let `min_end_for_x_eq_l` be the minimum `x+2k` for a triple starting at `x=l`.
    // Iterate `l` from `n-1` down to `0`.
    // `current_min_end_for_l = n`.
    // For `k` from `1` up to `(n-1-l)/2`:
    //   If `s[l] == s[l+k] && s[l] == s[l+2k]`:
    //     `current_min_end_for_l = min(current_min_end_for_l, l+2k)`.
    // `min_valid_r[l] = min(current_min_end_for_l, (l+1 < n ? min_valid_r[l+1] : n))`.
    // This is `O(N^2)`. Still too slow for N=300,000.

    // The key observation is that `k` doesn't need to be large.
    // If `k` is large, say `k >= 9`, then `2k+1 >= 19`.
    // If `s_x = s_{x+k} = s_{x+2k}` exists, then `x+2k` is the end of the pattern.
    // The maximum `k` we need to check is small.
    // Consider the maximum length of a "bad" substring.
    // If a substring `s[l...r]` has length `len = r-l+1`.
    // If `len >= 19`, it must contain a triple.
    // Why? This is a known result from combinatorics on words, related to "avoidable patterns".
    // For binary strings, any string of length 19 must contain `xxx` (three consecutive identical characters)
    // or `xyx` or `xxyy` or `xyxy` etc.
    // The specific pattern `s_x = s_{x+k} = s_{x+2k}` is called an "arithmetic progression of length 3".
    // It is known that any binary string of length 9 contains an arithmetic progression of length 3.
    // For example, `000`, `111`, `01010`, `00100`, `11011`.
    // Let's verify this.
    // Length 1: 0, 1
    // Length 2: 00, 01, 10, 11
    // Length 3: 000 (triple), 001, 010, 011, 100, 101, 110, 111 (triple)
    // Length 4: 0010, 0100, 0110, 1001, 1011, 1101
    // Length 5: 00100 (0_0_0), 00101, 01001, 01010 (0_0_0, 1_1_1), 01100, 01101, 10010, 10100, 10101, 11011 (1_1_1)
    // The longest binary string that avoids `s_x = s_{x+k} = s_{x+2k}` is `00110100`. This has length 8.
    // Any binary string of length 9 must contain such a triple.
    // Example: `00110100` (length 8).
    // `00110100`
    // `x=0, k=1: s_0=s_1=s_2? 0=0!=1`
    // `x=0, k=2: s_0=s_2=s_4? 0!=1!=0`
    // `x=0, k=3: s_0=s_3=s_6? 0!=1!=0`
    // `x=1, k=1: s_1=s_2=s_3? 0!=1!=1`
    // `x=1, k=2: s_1=s_3=s_5? 0!=1!=1`
    // `x=2, k=1: s_2=s_3=s_4? 1=1!=0`
    // `x=2, k=2: s_2=s_4=s_6? 1!=0!=0`
    // `x=3, k=1: s_3=s_4=s_5? 1!=0!=1`
    // `x=4, k=1: s_4=s_5=s_6? 0!=1!=0`
    // `x=5, k=1: s_5=s_6=s_7? 1!=0!=0`
    // Indeed, `00110100` avoids the pattern.
    // So, any substring of length 9 or more must contain a triple.
    // This means `k` only needs to be checked up to `k=4` (since `2k+1` for `k=4` is `9`).
    // If `k=1`, `2k+1=3`.
    // If `k=2`, `2k+1=5`.
    // If `k=3`, `2k+1=7`.
    // If `k=4`, `2k+1=9`.
    // So, we only need to check `k` from `1` to `4`.
    // This makes the `O(N^2)` approach `O(N * max_k)` which is `O(N * 4) = O(N)`.

    // Let `min_valid_r_idx[i]` be the smallest `r` (0-indexed) such that `s[i...r]` contains a triple.
    // If no such `r` exists, `min_valid_r_idx[i] = n`.
    // We iterate `i` from `n-1` down to `0`.
    // `min_valid_r_idx[i]` is initialized to `n`.
    // If `i+1 < n`, `min_valid_r_idx[i] = min(min_valid_r_idx[i], min_valid_r_idx[i+1])`.
    // This ensures that if `s[i+1...r]` contains a triple, then `s[i...r]` also contains it.
    // Then, for `k` from `1` to `4`:
    //   If `i+2*k < n` and `s[i] == s[i+k] && s[i] == s[i+2*k]`:
    //     `min_valid_r_idx[i] = min(min_valid_r_idx[i], i+2*k)`.

    std::vector<int> min_valid_r_idx(n + 1, n); // min_valid_r_idx[i] for 0-indexed i.
                                                // min_valid_r_idx[n] is just n.

    for (int i = n - 1; i >= 0; --i) {
        if (i + 1 < n) {
            min_valid_r_idx[i] = min_valid_r_idx[i+1];
        }
        for (int k = 1; k <= 4; ++k) { // Only need to check k up to 4
            if (i + 2 * k < n) {
                if (s[i] == s[i+k] && s[i] == s[i+2*k]) {
                    min_valid_r_idx[i] = std::min(min_valid_r_idx[i], i + 2 * k);
                }
            } else {
                // No need to check larger k for this i
                break;
            }
        }
    }

    // Now, for each `l` (0-indexed), `min_valid_r_idx[l]` is the smallest `r` (0-indexed)
    // such that `s[l...r]` contains a triple.
    // If `min_valid_r_idx[l] == n`, it means no triple exists starting at or after `l`.
    // The number of "bad" pairs `(l, r)` (0-indexed) is:
    // For a fixed `l`, `r` can range from `l` to `min_valid_r_idx[l] - 1`.
    // The count is `(min_valid_r_idx[l] - 1) - l + 1 = min_valid_r_idx[l] - l`.
    // Sum this over all `l`.

    for (int i = 0; i < n; ++i) {
        invalid_pairs += (min_valid_r_idx[i] - i);
    }

    long long good_pairs = total_pairs - invalid_pairs;
    std::cout << good_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        // Current head h_idx is at h[h_idx]
        // It can cover tracks in [h[h_idx] - T, h[h_idx] + T]

        // Find the first target track p[p_idx] that this head can potentially cover.
        // If p[p_idx] is too far to the left, this head cannot cover it.
        // This head can only cover p[p_idx] if p[p_idx] <= h[h_idx] + T.
