        int last_r_pos = -1; // Represents the last 'R' position, or -1 for cell 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                max_dist = std::max(max_dist, (i + 1) - (last_r_pos + 1));
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R'
        // to cell n+1. If no 'R' was found, it's a jump from cell 0 to n+1.
        max_dist = std::max(max_dist, (n + 1) - (last_r_pos + 1));

        std::cout << max_dist << "\n";
    }
