#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs 3 students).
        // So, the number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // 3 * k <= c + m + x  =>  k <= (c + m + x) / 3
        // Therefore, k <= min(c, m, (c + m + x) / 3).
        // Let's check if this minimum is always achievable.
        // If we form 'k' teams, we use 'k' coders and 'k' mathematicians as the required minimums.
        // The remaining students are (c - k) coders, (m - k) mathematicians, and 'x' unspecialized students.
        // The total number of remaining students is (c - k) + (m - k) + x = c + m + x - 2k.
        // Each of the 'k' teams needs 3 members. We've already assigned 2 members (1 coder, 1 mathematician).
        // So, each team needs 1 more member. In total, 'k' more members are needed.
        // If c + m + x - 2k >= k, then we have enough remaining students to fill the 'k' remaining slots.
        // This simplifies to c + m + x >= 3k.
        // This condition is exactly the third constraint we derived: k <= (c + m + x) / 3.
        // Since we are taking the minimum of c, m, and (c + m + x) / 3, the condition c + m + x >= 3k will always hold.
        // Thus, the maximum number of teams is simply the minimum of these three values.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_staircase_cells = 1; // Cells for a 1-stair staircase
        long long current_n = 1; // Number of stairs for the current staircase (1, 3, 7, 15, ...)

        while (x >= current_staircase_cells) {
            x -= current_staircase_cells;
            count++;

            // Calculate cells for the next nice staircase
            // The next n is 2 * current_n + 1
            // The number of cells for a staircase with n stairs is n * (n + 1) / 2
            // Let n_prev = current_n. n_next = 2 * n_prev + 1.
            // cells_next = n_next * (n_next + 1) / 2
            //            = (2 * n_prev + 1) * (2 * n_prev + 2) / 2
            //            = (2 * n_prev + 1) * (n_prev + 1)
            // This can also be seen as cells_next = cells_prev + (n_prev + 1)^2
            // Or, more simply, the pattern of cells is 1, 7, 30, 111, ...
            // The difference between consecutive terms is (2^k)^2.
            // The number of cells for a staircase with 2^k - 1 stairs is (2^k - 1) * (2^k) / 2 = (2^k - 1) * 2^(k-1).
            // Let's use the formula: current_n = 2^k - 1.
            // The next n will be 2^(k+1) - 1.
            // The number of cells for 2^k - 1 stairs is (2^k - 1) * 2^(k-1).
            // The number of cells for 2^(k+1) - 1 stairs is (2^(k+1) - 1) * 2^k.
            // The difference is (2^(k+1) - 1) * 2^k - (2^k - 1) * 2^(k-1)
            // = 2^k * (2^(k+1) - 1) - 2^(k-1) * (2^k - 1)
            // = 2^k * (2 * 2^k - 1) - 2^(k-1) * (2^k - 1)
            // = 2 * 2^(2k) - 2^k - 2^(2k-1) + 2^(k-1)
            // This is getting complicated.
            // Let's use the observation that the cost of the k-th nice staircase (with 2^k-1 stairs) is (2^k-1)*2^(k-1).
            // The next cost is (2^(k+1)-1)*2^k.
            // The ratio of consecutive costs is roughly 4.
            // current_n = 1, cells = 1.
            // next_n = 2*1 + 1 = 3. cells = 3*(3+1)/2 = 6.
            // current_n = 3, cells = 6.
            // next_n = 2*3 + 1 = 7. cells = 7*(7+1)/2 = 28.
            // current_n = 7, cells = 28.
            // next_n = 2*7 + 1 = 15. cells = 15*(15+1)/2 = 120.
            // The pattern of cells is 1, 6, 28, 120, ...
            // The previous calculation was wrong.
            // The cost of a staircase with n stairs is n*(n+1)/2.
            // For n=1, cost=1.
            // For n=3, cost=6.
            // For n=7, cost=28.
            // For n=15, cost=120.
            // The sequence of n values is 1, 3, 7, 15, ..., which is 2^k - 1.
            // The sequence of costs is (2^k - 1) * (2^k) / 2 = (2^k - 1) * 2^(k-1).
            // Let's re-calculate current_staircase_cells for the next iteration.
            // current_n is 2^k - 1.
            // The next n will be 2 * current_n + 1.
            // The cells for the next staircase will be (2 * current_n + 1) * (2 * current_n + 2) / 2
            // = (2 * current_n + 1) * (current_n + 1).
            current_staircase_cells = (2 * current_n + 1) * (current_n + 1);
            current_n = 2 * current_n + 1;
        }
        std::cout << count << "\n";
    }
    return 0;
}

