int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (x_i)
        // should be i * (total_area / n).
        // Total area = (1/2) * base * height = (1/2) * 1 * h = h/2.
        // Area_i = i * (h / (2n)).
        //
        // For a triangle similar to the original with height x_i, its area is (x_i^2) / (2h).
        // So, (x_i^2) / (2h) = i * (h / (2n)).
        // x_i^2 = i * (h^2 / n).
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

