#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is a non-increasing suffix.
    // This means a[p] >= a[p+1] >= ... >= a[n-1].
    // We start from n-1 and move left.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // Now, a[p...n-1] is non-increasing.
    // We need to find the rightmost index `q` such that a[q...p-1] is a non-decreasing suffix.
    // This means a[q] <= a[q+1] <= ... <= a[p-1].
    // We start from p-1 and move left.
    // If p is 0, this loop won't run, which is correct.
    int q = p; // q is the start of the non-decreasing part.
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }

    // The prefix to erase has length `q`.
    // The remaining array is a[q...n-1].
    // This remaining array has the structure:
    // [non-decreasing part] [non-increasing part]
    // a[q...p-1] is non-decreasing.
    // a[p...n-1] is non-increasing.
    // This structure is exactly what makes an array "good".
    // For example, if a[q...p-1] is [1,2,3] and a[p...n-1] is [5,4,3],
    // the combined array is [1,2,3,5,4,3].
    // We can pick 1, then 2, then 3 (from left), then 3, then 4, then 5 (from right).
    // This forms [1,2,3,3,4,5], which is non-decreasing.

    std::cout << q << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of multiples of m up to n

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute last digits for multiples of m up to 10m
        // The cycle of last digits of (i * m) % 10 has a length of at most 10.
        // Specifically, it's the cycle of (i * (m % 10)) % 10.
        // The sequence of last digits (m%10, 2m%10, ..., 10m%10) will always contain a full cycle.
        // For example, if m=2, last digits are 2,4,6,8,0,2,4,6,8,0. Cycle length 5.
        // If m=5, last digits are 5,0,5,0,5,0,5,0,5,0. Cycle length 2.
        // If m=1, last digits are 1,2,3,4,5,6,7,8,9,0. Cycle length 10.
        // The sum of last digits for i=1 to 10 is always a full cycle sum.

        std::vector<long long> cycle_digits(10);
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            cycle_sum += cycle_digits[i - 1];
        }

        long long num_full_cycles = k / 10;
        long long remaining_elements = k % 10;

        long long total_sum = num_full_cycles * cycle_sum;

        for (int i = 0; i < remaining_elements; ++i) {
            total_sum += cycle_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, if we sort them as a_0, a_1, ..., a_{2n-1},
        // and partition them into two classes of odd sizes,
        // the optimal strategy to minimize the difference between medians
        // is to make one class from a_0, ..., a_{n-1} and the other from a_n, ..., a_{2n-1}.
        //
        // Specifically, if we take the first n elements for one class and the last n elements for the other,
        // this is not a valid partition because n can be even, making class sizes even.
        //
        // However, the key insight is that the median of a class of size 2k+1 is the (k+1)-th element.
        // If we have 2n students, and we sort them: a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the two "middle" elements: a_{n-1} and a_n.
        //
        // If we form a class C1 using elements a_0, ..., a_{n-1} and a class C2 using elements a_n, ..., a_{2n-1},
        // this is not a valid partition because each class would have n elements.
        //
        // The crucial observation is that to minimize the difference between medians,
        // we want the medians to be as close as possible.
        //
        // If we sort all 2n students, a_0, a_1, ..., a_{2n-1}.
        // The median of the first class will be some a_i, and the median of the second class will be some a_j.
        //
        // It can be shown that the minimum difference is achieved when the two medians are
        // a_{n-1} and a_n.
        //
        // For example, we can form one class with students {a_0, a_1, ..., a_{n-1}} and
        // another class with students {a_n, a_{n+1}, ..., a_{2n-1}}.
        // Each class has n students. If n is odd, this is a valid partition.
        // The median of the first class would be a_{(n-1)/2}.
        // The median of the second class would be a_{n + (n-1)/2}.
        //
        // If n is even, this partition is not valid.
        //
        // However, the problem asks for *any* partition into two odd-sized classes.
        // The minimum difference between medians will always be |a_n - a_{n-1}|.
        //
        // To see why, consider any partition into two odd-sized classes, C1 and C2.
        // Let their medians be M1 and M2.
        // Suppose M1 < M2.
        // M1 must be some a_i and M2 must be some a_j, with i < j.
        //
        // If we take the first n elements {a_0, ..., a_{n-1}} and the last n elements {a_n, ..., a_{2n-1}},
        // we can always construct valid odd-sized classes such that their medians are a_{n-1} and a_n.
        //
        // For example, we can form one class with {a_0, a_1, ..., a_{n-1}} and another with {a_n, ..., a_{2n-1}}.
        // This is not a valid partition if n is even.
        //
        // The correct logic is that the median of the first class will be at most a_{n-1},
        // and the median of the second class will be at least a_n.
        //
        // Consider the sorted array a_0, ..., a_{2n-1}.
        // The element a_{n-1} is the largest element that can be the median of a class of size at most n,
        // if that class is formed from the smallest elements.
        // The element a_n is the smallest element that can be the median of a class of size at most n,
        // if that class is formed from the largest elements.
        //
        // More formally, if we pick any $k$ elements for the first class, and $2n-k$ elements for the second class,
        // where $k$ and $2n-k$ are both odd.
        // The median of the first class will be some $a_i$.
        // The median of the second class will be some $a_j$.
        //
        // The minimum possible value for $a_j$ (median of the second class) is $a_n$.
        // This happens if the second class has $n$ elements (if $n$ is odd), and these are $a_n, \dots, a_{2n-1}$.
        // Or, if the second class has $n+2$ elements, $a_{n-1}, \dots, a_{2n-1}$ (median $a_{n-1 + (n+2-1)/2} = a_{n-1 + (n+1)/2} = a_{(3n)/2}$ if $n$ is odd).
        //
        // The key is that the median of the first class will be at index at most n-1.
        // The median of the second class will be at index at least n.
        //
        // Let's consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        // We can always form a class $C_1$ using $n$ elements from $a_0, \dots, a_{2n-1}$ and $C_2$ using the remaining $n$ elements.
        // If $n$ is odd, this is a valid partition. The median of $C_1$ (if it's $a_0, \dots, a_{n-1}$) is $a_{(n-1)/2}$.
        // The median of $C_2$ (if it's $a_n, \dots, a_{2n-1}$) is $a_{n + (n-1)/2}$.
        // This is not what the example implies.
        //
        // The example for n=3 (2n=6 students) with skills [1,2,3,4,5,6]
        // Output is 1.
        // a_0=1, a_1=2, a_2=3, a_3=4, a_4=5, a_5=6.
        // n=3. a_{n-1} = a_2 = 3. a_n = a_3 = 4.
        // |a_3 - a_2| = |4 - 3| = 1. This matches the example.
        //
        // For n=1 (2n=2 students) with skills [1,1]
        // Output is 0.
        // a_0=1, a_1=1.
        // n=1. a_{n-1} = a_0 = 1. a_n = a_1 = 1.
        // |a_1 - a_0| = |1 - 1| = 0. This matches the example.
        //
        // For n=5 (2n=10 students) with skills [2,3,4,5,8,13,13,16,17,20]
        // Output is 5.
        // n=5. a_{n-1} = a_4 = 8. a_n = a_5 = 13.
        // |a_5 - a_4| = |13 - 8| = 5. This matches the example.
        //
        // It seems the answer is always a_n - a_{n-1} after sorting.
        //
        // Why is this always possible?
        // We need to assign students to two classes, C1 and C2, both of odd size.
        // Let's say we want to achieve medians $a_{n-1}$ and $a_n$.
        //
        // To make $a_{n-1}$ the median of $C_1$:
        // $C_1$ must contain $a_{n-1}$.
        // It must contain $k$ elements smaller than $a_{n-1}$ and $k$ elements larger than $a_{n-1}$.
        // The smallest $n$ elements are $a_0, \dots, a_{n-1}$.
        // The largest $n$ elements are $a_n, \dots, a_{2n-1}$.
        //
        // We can form $C_1$ with $a_{n-1}$ as its median.
        // For example, take $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$. This class has $n$ elements.
        // If $n$ is odd, its median is $a_{(n-1)/2}$.
        // If $n$ is even, this is not a valid class size.
        //
        // The problem states that the median of $[b_1, \dots, b_{2k+1}]$ is $b_{k+1}$.
        // This means the median is the element at index $k$ in 0-indexed sorted array.
        //
        // The $n$-th element (0-indexed) is $a_{n-1}$.
        // The $(n+1)$-th element (0-indexed) is $a_n$.
        //
        // We can always construct a partition where $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Consider the partition:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        //
        // Each class has $n$ students.
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler than trying to construct the classes.
        // Any class of odd size $2k+1$ must have a median.
        // Let $M_1$ be the median of the first class and $M_2$ be the median of the second class.
        //
        // The total number of students is $2n$.
        // If we sort all students $a_0, a_1, \dots, a_{2n-1}$.
        //
        // Consider the $n$ smallest students $S_L = \{a_0, \dots, a_{n-1}\}$ and $n$ largest students $S_R = \{a_n, \dots, a_{2n-1}\}$.
        //
        // Any class $C_1$ must have an odd number of students, say $2k_1+1$.
        // Its median $M_1$ will be some $a_i$.
        // Any class $C_2$ must have an odd number of students, say $2k_2+1$.
        // Its median $M_2$ will be some $a_j$.
        //
        // The total number of students is $2n$.
        // The sum of students in both classes is $2n$.
        //
        // The crucial point is that $a_{n-1}$ is the largest element among the first $n$ elements, and $a_n$ is the smallest element among the last $n$ elements.
        //
        // If we pick $a_{n-1}$ as the median of the first class, we need $k$ elements smaller than it and $k$ elements larger than it.
        // If we pick $a_n$ as the median of the second class, we need $k'$ elements smaller than it and $k'$ elements larger than it.
        //
        // The minimum difference is indeed $a_n - a_{n-1}$.
        // This is because we can always form two classes such that $a_{n-1}$ is the median of one and $a_n$ is the median of the other.
        //
        // Let's try to construct such a partition.
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // This is not a valid partition if $n$ is even.
        //
        // The problem is equivalent to finding two indices $i$ and $j$ such that $a_j - a_i$ is minimized,
        // where $a_i$ is the median of one class and $a_j$ is the median of the other.
        //
        // Consider the $n$-th element $a_{n-1}$ and the $(n+1)$-th element $a_n$ in the sorted array.
        //
        // We can form a class $C_1$ of size $2k_1+1$ and $C_2$ of size $2k_2+1$.
        // $2k_1+1 + 2k_2+1 = 2n \implies 2(k_1+k_2+1) = 2n \implies k_1+k_2+1 = n$.
        //
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        //
        // It is always possible to construct a partition such that $M_1 = a_{n-1}$ and $M_2 = a_n$.
        //
        // For example, let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is a partition into two classes of size $n$.
        // If $n$ is odd, this is a valid partition.
        // The median of $C_1$ is $a_{(n-1)/2}$. The median of $C_2$ is $a_{n+(n-1)/2}$.
        // This does not give $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        // This is a known result for similar problems.
        // The logic is that any median of a class must be one of the $a_i$.
        // If we have two classes, $C_1$ and $C_2$, with medians $M_1$ and $M_2$.
        // Without loss of generality, assume $M_1 \le M_2$.
        //
        // The total number of elements is $2n$.
        // The median of $C_1$ must be $a_i$ for some $i$.
        // The median of $C_2$ must be $a_j$ for some $j$.
        //
        // The key is that $a_{n-1}$ is the largest possible median for a class that contains only elements from $a_0, \dots, a_{n-1}$.
        // And $a_n$ is the smallest possible median for a class that contains only elements from $a_n, \dots, a_{2n-1}$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // We can form $C_1$ with $a_{n-1}$ as its median.
        // We can form $C_2$ with $a_n$ as its median.
        //
        // Let $k_1$ be the number of elements smaller than $a_{n-1}$ in $C_1$, and $k_1$ elements larger than $a_{n-1}$ in $C_1$.
        // So $|C_1| = 2k_1+1$.
        // Let $k_2$ be the number of elements smaller than $a_n$ in $C_2$, and $k_2$ elements larger than $a_n$ in $C_2$.
        // So $|C_2| = 2k_2+1$.
        //
        // We need to pick $k_1$ elements from $a_0, \dots, a_{n-2}$ for $C_1$.
        // We need to pick $k_1$ elements from $a_n, \dots, a_{2n-1}$ for $C_1$.
        // This is not how it works. The elements are chosen from the entire set.
        //
        // The simplest argument is that if you sort all $2n$ students, $a_0, \dots, a_{2n-1}$,
        // then the median of one class will be $a_i$ and the median of the other will be $a_j$.
        // It must be that $i < n$ and $j \ge n$ (or vice versa).
        // If both medians are $a_i, a_j$ with $i, j < n$, then all $2n$ students cannot be partitioned.
        // If both medians are $a_i, a_j$ with $i, j \ge n$, then all $2n$ students cannot be partitioned.
        //
        // So one median must be from $a_0, \dots, a_{n-1}$ and the other from $a_n, \dots, a_{2n-1}$.
        // To minimize the difference, we pick the largest possible from the first group and smallest possible from the second group.
        // The largest possible median from $a_0, \dots, a_{n-1}$ is $a_{n-1}$.
        // The smallest possible median from $a_n, \dots, a_{2n-1}$ is $a_n$.
        //
        // We can always construct a partition where $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is a partition into two classes of size $n$.
        // If $n$ is odd, this is a valid partition.
        // The median of $C_1$ is $a_{(n-1)/2}$. The median of $C_2$ is $a_{n+(n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler than constructing the classes.
        // The minimum difference is always $a_n - a_{n-1}$.
        // This is a standard result for this type of problem.
        // The proof relies on the fact that if you have $2n$ elements, and you want to split them into two groups of odd size,
        // the "split point" for the medians will always be between $a_{n-1}$ and $a_n$.
        //
        // The median of the first class will be some $a_i$ where $i < n$.
        // The median of the second class will be some $a_j$ where $j \ge n$.
        // To minimize $|a_j - a_i|$, we want $a_i$ to be as large as possible and $a_j$ to be as small as possible.
        // The largest possible $a_i$ with $i < n$ is $a_{n-1}$.
        // The smallest possible $a_j$ with $j \ge n$ is $a_n$.
        //
        // So the minimum difference is $a_n - a_{n-1}$.
        //
        // This is a common trick in competitive programming problems involving medians and partitions.
        // The indices are 0-based. So $a_{n-1}$ is the $n$-th element and $a_n$ is the $(n+1)$-th element.
        //
        // Example 2: n=3, 2n=6. a = [1,2,3,4,5,6].
        // a_{n-1} = a_2 = 3.
        // a_n = a_3 = 4.
        // Difference = 4-3 = 1.
        //
        // Example 3: n=5, 2n=10. a = [2,3,4,5,8,13,13,16,17,20].
        // a_{n-1} = a_4 = 8.
        // a_n = a_5 = 13.
        // Difference = 13-8 = 5.
        //
        // The solution is simply to sort the array and output $a_n - a_{n-1}$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment [1] is always a permutation of {1}.
    // The segment is p[pos[1]...pos[1]].
    // min_idx = pos[1], max_idx = pos[1].
    // Current min_val = 1, current max_val = 1.
    ans[0] = '1';

    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 2; m <= n; ++m) {
        // To check if m is beautiful, we need to expand the current segment
        // [min_idx, max_idx] to include 'm'.
        // The number 'm' is at pos[m].

        // Update min_idx and max_idx to cover the range [1, ..., m]
        // This means the segment must span from min(pos[1], ..., pos[m])
        // to max(pos[1], ..., pos[m]).
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // If the current segment [min_idx, max_idx] has length m
        // (i.e., max_idx - min_idx + 1 == m),
        // then it contains all numbers from 1 to m (because we've expanded
        // it to include pos[1]...pos[m]) and no numbers greater than m
        // (because we only consider numbers up to m).
        // Thus, it forms a permutation of 1...m.
        if (max_idx - min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For a = (d + sqrt(d^2 - 4d)) / 2
            // For b = (d - sqrt(d^2 - 4d)) / 2
            // Both a and b will be non-negative because d >= 4.
            // If d >= 4, then d^2 >= 4d, so d^2 - 4d >= 0.
            // Also, sqrt(d^2 - 4d) <= sqrt(d^2) = d.
            // So d - sqrt(d^2 - 4d) >= 0.
            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;
            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // If a[median_idx] is less than s, we need to increase it.
    // All elements to its right (a[median_idx+1] to a[n-1]) must be >= s.
    // If any of them are < s, we must increase them to s.
    if (a[median_idx] < s) {
        for (int i = median_idx + 1; i < n; ++i) {
            if (a[i] < s) {
                operations += (s - a[i]);
            } else {
                // Since the array is sorted, all subsequent elements will also be >= s.
                break;
            }
        }
    }
    // If a[median_idx] is greater than s, we need to decrease it.
    // All elements to its left (a[0] to a[median_idx-1]) must be <= s.
    // If any of them are > s, we must decrease them to s.
    else if (a[median_idx] > s) {
        for (int i = median_idx - 1; i >= 0; --i) {
            if (a[i] > s) {
                operations += (a[i] - s);
            } else {
                // Since the array is sorted, all previous elements will also be <= s.
                break;
            }
        }
    }
    // If a[median_idx] == s, no additional operations are needed for elements
    // to its left or right to satisfy the median property, as long as they
    // are already in their correct relative positions (which they are due to sorting).
    // The elements to the left are <= s, and to the right are >= s.

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());

    int count = 0;
    int b_ptr = 0; // Pointer for the elements we are trying to place (the 'b' array elements)

    // Iterate through the sorted 'a' array (representing the original positions)
    // We try to find an element from 'a' (at b_ptr) that is strictly greater than
    // the current element a[i] (representing the original value at position i).
    for (int i = 0; i < n; ++i) {
        // While b_ptr is within bounds and a[b_ptr] is not greater than a[i],
        // we increment b_ptr to find a suitable larger element.
        // This effectively skips elements in the 'b' array that are too small
        // to be placed at the current 'a[i]' position.
        while (b_ptr < n && a[b_ptr] <= a[i]) {
            b_ptr++;
        }

        // If we found an element a[b_ptr] that is strictly greater than a[i],
        // we can make a successful match.
        // We increment count and move to the next element in 'b' array.
        if (b_ptr < n) {
            count++;
            b_ptr++;
        } else {
            // If b_ptr reaches n, it means we have exhausted all available
            // larger elements from the 'b' array. No more matches can be made.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i; // Not strictly needed for B, but good practice
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    // We need to sort B based on its value, but we only care about the values themselves
    // The original_index for B is not used for rearrangement logic.
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& x, const Element& y) {
        return x.value > y.value;
    });

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Fill A' such that a_prime[original_index_of_b_i] = a_elements[i].value
    // This pairs the smallest A with the largest B, second smallest A with second largest B, etc.
    for (int i = 0; i < m; ++i) {
        a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if it's possible to form the increasing part
    // For a_1 < a_2 < ... < a_k, we need a_i >= i-1 for 1 <= i <= k.
    // The maximum possible k is n.
    // We need to find the largest prefix where a_i >= i-1 holds.
    int max_inc_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) { // a_i must be at least i (0-indexed)
            max_inc_len = i + 1;
        } else {
            break;
        }
    }

    // Check if it's possible to form the decreasing part
    // For a_k > a_{k+1} > ... > a_n, we need a_i >= n-i for k <= i <= n.
    // The maximum possible k is 1.
    // We need to find the largest suffix where a_i >= n-1-i holds.
    int max_dec_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) { // a_i must be at least (n-1-i) (0-indexed)
            max_dec_len = n - i;
        } else {
            break;
        }
    }

    // If there is any element that can be part of both an increasing prefix and a decreasing suffix,
    // then it's possible.
    // This means there exists a k (1-indexed) such that:
    // 1. a_1 < ... < a_k is possible (i.e., a_i >= i-1 for 1 <= i <= k)
    // 2. a_k > ... > a_n is possible (i.e., a_i >= n-i for k <= i <= n)
    // In 0-indexed terms:
    // 1. a_0 < ... < a_{k-1} is possible (i.e., a_i >= i for 0 <= i <= k-1)
    // 2. a_{k-1} > ... > a_{n-1} is possible (i.e., a_i >= n-1-i for k-1 <= i <= n-1)
    //
    // This is equivalent to checking if max_inc_len + max_dec_len > n.
    // max_inc_len is the length of the longest prefix a[0...k_inc-1] such that a_i >= i.
    // max_dec_len is the length of the longest suffix a[k_dec...n-1] such that a_i >= n-1-i.
    // If max_inc_len + max_dec_len > n, it means there's an overlap.
    // The overlap implies there's at least one index `j` such that `j < max_inc_len` AND `j >= n - max_dec_len`.
    // This `j` can be our peak `k-1`.
    // For example, if n=5, max_inc_len=3, max_dec_len=3.
    // Inc part covers indices 0, 1, 2.
    // Dec part covers indices 2, 3, 4.
    // Index 2 is covered by both. So a[2] can be the peak.
    //
    // The condition max_inc_len + max_dec_len > n correctly identifies if there's an overlap.
    // If max_inc_len is the length of the prefix, it covers indices [0, max_inc_len-1].
    // If max_dec_len is the length of the suffix, it covers indices [n-max_dec_len, n-1].
    // An overlap exists if (max_inc_len - 1) >= (n - max_dec_len).
    // Which simplifies to max_inc_len + max_dec_len - 1 >= n.
    // Or max_inc_len + max_dec_len > n.

    if (max_inc_len + max_dec_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

