#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a subarray is a permutation
// `arr` is the input array, `start` is the starting index (inclusive),
// `end` is the ending index (exclusive), `length` is the expected length of the permutation.
bool is_permutation(const std::vector<int>& arr, int start, int end, int length) {
    if (length == 0) return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
                                  // For this problem, l1, l2 >= 1.
    if (end - start != length) return false;

    std::vector<bool> seen(length + 1, false);
    int max_val = 0;

    for (int i = start; i < end; ++i) {
        int val = arr[i];
        if (val < 1 || val > length) {
            return false; // Value out of range [1, length]
        }
        if (seen[val]) {
            return false; // Duplicate value
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // All values must be present from 1 to length.
    // If max_val is length and all values are distinct and within range,
    // then all values from 1 to length must be present.
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i+1], a[i]);
    }

    // Precompute prefix distinct counts and suffix distinct counts
    std::vector<int> prefix_distinct_count(n);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        prefix_distinct_count[i] = current_distinct_prefix;
    }

    std::vector<int> suffix_distinct_count(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        suffix_distinct_count[i] = current_distinct_suffix;
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if first part is a permutation of length l1
        // Conditions:
        // 1. Max element in a[0...l1-1] must be l1.
        // 2. Number of distinct elements in a[0...l1-1] must be l1.
        bool p1_is_perm = (prefix_max[l1-1] == l1) && (prefix_distinct_count[l1-1] == l1);

        // Check if second part is a permutation of length l2
        // Conditions:
        // 1. Max element in a[l1...n-1] must be l2.
        // 2. Number of distinct elements in a[l1...n-1] must be l2.
        bool p2_is_perm = (suffix_max[l1] == l2) && (suffix_distinct_count[l1] == l2);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

