int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    for (int k = 0; k <= n; ++k) { // k is the number of items taken from the left
        int items_from_left = k;
        int items_from_right = n - k;

        long long current_energy = 0;

        // Energy for items taken from left
        current_energy += prefix_sum[items_from_left] * l;

        // Energy for items taken from right
        current_energy += (prefix_sum[n] - prefix_sum[n - items_from_right]) * r;

        // Penalty for imbalance
        if (items_from_left > items_from_right) {
            int diff = items_from_left - items_from_right;
            if (diff > 1) { // If diff is 1, no extra penalty for last item
                current_energy += (long long)(diff - 1) * Ql;
            }
        } else if (items_from_right > items_from_left) {
            int diff = items_from_right - items_from_left;
            if (diff > 1) { // If diff is 1, no extra penalty for last item
                current_energy += (long long)(diff - 1) * Qr;
            }
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

