#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long ans = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            long long current_prime_factor = i;
            long long p_copy = p;

            // Calculate the highest power of current_prime_factor that divides q
            long long q_power_val = 1;
            while (temp_q % current_prime_factor == 0) {
                q_power_val *= current_prime_factor;
                temp_q /= current_prime_factor;
            }

            // Reduce p by dividing out current_prime_factor until it's no longer divisible by q_power_val
            // This ensures x is not divisible by q_power_val (and thus not by q)
            long long current_x = p_copy;
            while (current_x % q_power_val == 0) {
                current_x /= current_prime_factor;
            }
            ans = std::max(ans, current_x);
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    if (temp_q > 1) {
        long long current_prime_factor = temp_q;
        long long p_copy = p;

        // Reduce p by dividing out current_prime_factor until it's no longer divisible by current_prime_factor (which is q_power_val here)
        long long current_x = p_copy;
        while (current_x % current_prime_factor == 0) {
            current_x /= current_prime_factor;
        }
        ans = std::max(ans, current_x);
    }

    return ans;
}

