#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, b-1=0, sum is 0.
    sum_r_term = (sum_r_term * b) / 2;
    sum_r_term %= MOD;

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // This is (b * sum_{k=1 to a} k) + (sum_{k=1 to a} 1)
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a

    long long sum_k_val = (a * (a + 1)) / 2;
    sum_k_val %= MOD;

    long long sum_k_term = (b % MOD * sum_k_val) % MOD;
    sum_k_term = (sum_k_term + a % MOD) % MOD;

    // Total sum = (sum_k_term) * (sum_r_term)
    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (char c : s) {
        used_in_s.insert(c);
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
    }

    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
        if (adj[c].size() == 1) {
            if (start_char != '\0') { // More than one potential start char, or already found one
                // This case is tricky. If there are multiple components, or a cycle,
                // we might have multiple degree-1 nodes.
                // The logic below handles this by checking if the path construction fails.
            }
            start_char = c;
        }
    }

    if (used_in_s.empty()) { // Empty password, any layout is fine
        std::cout << "YES\n";
        std::cout << "abcdefghijklmnopqrstuvwxyz\n";
        return;
    }

    if (used_in_s.size() == 1) { // Password has only one unique character
        std::cout << "YES\n";
        std::string layout = "";
        layout += *used_in_s.begin();
        for (char c = 'a'; c <= 'z'; ++c) {
            if (c != *used_in_s.begin()) {
                layout += c;
            }
        }
        std::cout << layout << "\n";
        return;
    }

    // If no character has degree 1, it means all characters have degree 0 or 2.
    // Degree 0 characters are isolated. Degree 2 characters form cycles or paths.
    // If all characters in used_in_s have degree 2, it must be a cycle.
    // A cycle cannot be laid out on a single row.
    // If there are multiple components, and some are cycles, it's also impossible.
    // The only way it's possible is if all characters in used_in_s form a single path.
    // A single path must have exactly two degree-1 nodes (endpoints) and the rest degree-2.
    // If start_char is still '\0', it means all characters in used_in_s have degree 2 (or 0).
    // This implies a cycle or multiple paths/cycles.
    // We need to find *a* start_char. If all characters have degree 2, it's a cycle.
    // If there are multiple components, we need to pick one.
    // Let's pick an arbitrary character from used_in_s if start_char is not found.
    if (start_char == '\0') {
        start_char = *used_in_s.begin(); // Pick any character to start traversal
    }

    std::string layout_part = "";
    std::set<char> visited;
    char current = start_char;
    char prev = '\0'; // Sentinel for the first step

    while (visited.find(current) == visited.end()) {
        layout_part += current;
        visited.insert(current);

        char next_char = '\0';
        for (char neighbor : adj[current]) {
            if (neighbor != prev) {
                next_char = neighbor;
                break;
            }
        }
        prev = current;
        current = next_char;
        if (current == '\0' && visited.size() < used_in_s.size()) {
            // This means we reached an end of a path, but not all characters in s were visited.
            // This implies multiple components or a cycle that wasn't fully traversed.
            // For example, if s="abacaba", adj[a]={b,c}, adj[b]={a}, adj[c]={a}.
            // Start with b. Path: b-a-c. Visited {b,a,c}. used_in_s {a,b,c}. All visited. OK.
            // If s="abacaba" and s="def", then used_in_s={a,b,c,d,e,f}.
            // Path b-a-c. Visited {a,b,c}. current becomes '\0'.
            // But used_in_s has d,e,f not visited. So this is a NO.
            std::cout << "NO\n";
            return;
        }
    }

    if (visited.size() != used_in_s.size()) {
        // If we finished the traversal but didn't visit all characters from 's',
        // it means there are multiple connected components in the graph formed by 's'.
        // This is not a single path, so it's impossible.
        std::cout << "NO\n";
        return;
    }

    // If we reached here, it means all characters in 's' form a single path.
    // Now, append the remaining unused characters.
    std::string final_layout = layout_part;
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            final_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << final_layout << "\n";
}

