#include <iostream>
#include <vector>
#include <string>
#include <iomanip>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c1 = s[k_actual];

        std::vector<int> possible_k_values = char_indices[c1 - 'a'];

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_c1 = 0.0;

        for (int p = 2; p <= L; ++p) { // Vasya chooses position p (1-indexed), so index is p-1
            // For a fixed p, calculate the probability of winning given c1
            // This is the probability that k_actual is uniquely determined among possible_k_values
            // by observing s[k_actual] and s[(k_actual + p - 1) % L].
            // This is equivalent to checking if for all other k_prime in possible_k_values,
            // s[(k_prime + p - 1) % L] != s[(k_actual + p - 1) % L].

            char c2_actual = s[(k_actual + p - 1) % L];

            bool is_unique_for_this_p = true;
            for (int k_prime : possible_k_values) {
                if (k_prime == k_actual) continue;
                if (s[(k_prime + p - 1) % L] == c2_actual) {
                    is_unique_for_this_p = false;
                    break;
                }
            }

            if (is_unique_for_this_p) {
                max_win_prob_for_c1 = std::max(max_win_prob_for_c1, 1.0);
                break; // Found a p that guarantees win for this k_actual, no need to check further p's
            }
        }
        total_win_prob += max_win_prob_for_c1;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can always assume n is the larger coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: k < n. It's impossible to reach (n, m) in k moves if k is less than the
        // maximum coordinate, because each move can change a coordinate by at most 1.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the parity of the target coordinates.
        // (n % 2) and (m % 2) give 0 for even, 1 for odd.
        // (n % 2) ^ (m % 2) is 0 if n and m have the same parity, 1 if they have different parity.
        long long parity_diff = (n % 2) ^ (m % 2);

        // Calculate the parity of the total moves k.
        long long k_parity = k % 2;

        // If the parity of (n, m) is different from the parity of (0, 0) after k moves,
        // it's impossible.
        // The parity of (x, y) changes by (dx % 2, dy % 2) with each move.
        // The sum of parities (x+y) % 2 changes by (dx+dy) % 2.
        // A diagonal move (dx, dy != 0) changes (x+y) % 2 by (1+1)%2 = 0 or (1-1)%2 = 0.
        // A straight move (dx=0 or dy=0) changes (x+y) % 2 by (1+0)%2 = 1 or (0+1)%2 = 1.
        // So, the parity of (x+y) changes if and only if the move is straight.
        // This means (n+m)%2 must have the same parity as k%2 if all moves were straight.
        // However, a simpler observation is that the parity of (x,y) changes by (dx,dy) mod 2.
        // After k moves, the final (x,y) parity is (k_x_parity, k_y_parity).
        // The final (x,y) parity must match (n%2, m%2).
        // The parity of the sum of coordinates (x+y) changes by (dx+dy)%2.
        // If dx, dy are both non-zero (diagonal), (dx+dy)%2 is 0.
        // If one of dx, dy is zero (straight), (dx+dy)%2 is 1.
        // So, (n+m)%2 must have the same parity as the number of straight moves.
        // Number of straight moves = k - D.
        // (n+m)%2 == (k - D)%2.
        // This implies (n+m)%2 == k%2 - D%2.
        // If n and m have different parities, (n+m)%2 = 1.
        // If n and m have same parities, (n+m)%2 = 0.
        //
        // A simpler way to think about it:
        // Each move changes the parity of x by dx%2 and y by dy%2.
        // After k moves, the final x-coordinate's parity is (sum of dx%2 for all moves) % 2.
        // The final y-coordinate's parity is (sum of dy%2 for all moves) % 2.
        //
        // Consider the parity of (n-m).
        // A diagonal move (dx, dy) changes (x-y) to (x+dx - (y+dy)) = (x-y) + (dx-dy).
        // If dx, dy are both non-zero, then dx-dy is either 0 (e.g., (1,1) -> 1-1=0) or +-2 (e.g., (1,-1) -> 1-(-1)=2).
        // In either case, (dx-dy) is even. So a diagonal move preserves the parity of (x-y).
        // A straight move (dx=0 or dy=0) changes (x-y) by dx or -dy.
        // If dx=0, dy!=0, (x-y) changes by -dy (odd).
        // If dy=0, dx!=0, (x-y) changes by dx (odd).
        // So a straight move flips the parity of (x-y).
        //
        // The initial (x-y) is 0. The final (x-y) is (n-m).
        // The parity of (n-m) must be the same as the parity of the number of straight moves.
        // Let D be diagonal moves, S be straight moves. S = k - D.
        // (n-m)%2 == S%2 == (k-D)%2.
        //
        // We want to maximize D.
        // The maximum possible D is k.
        // If D=k, then S=0. (n-m)%2 == 0. This means n and m must have the same parity.
        // If n and m have different parities, then (n-m)%2 = 1. So S must be odd.
        // This means D must be even.
        //
        // The maximum number of diagonal moves is k - (n-m)%2 if k and (n-m) have the same parity.
        // If k and (n-m) have different parities, then we need one more straight move, so k - (n-m)%2 - 2.
        // This is equivalent to:
        // If (k - n) % 2 == 0 (k and n have same parity), then (k - m) % 2 == (n - m) % 2.
        // If (k - n) % 2 == 1 (k and n have different parity), then (k - m) % 2 == 1 - (n - m) % 2.
        //
        // The condition for reachability is that (k - n) and (k - m) must have the same parity.
        // This is equivalent to (n % 2) == (m % 2).
        // If (n % 2) != (m % 2), then (k - n) and (k - m) will always have different parities.
        // This means it's impossible to reach (n, m) in k moves if n and m have different parities.
        //
        // Let's re-evaluate the parity condition.
        // The point (x,y) can be reached from (0,0) in k moves if and only if:
        // 1. k >= max(|x|, |y|)
        // 2. (k - |x|) % 2 == 0
        // 3. (k - |y|) % 2 == 0
        //
        // For our problem, n, m are positive. So |n|=n, |m|=m.
        // Conditions:
        // 1. k >= n (since n >= m)
        // 2. (k - n) % 2 == 0
        // 3. (k - m) % 2 == 0
        //
        // Condition 2 and 3 together imply that n and m must have the same parity.
        // Because if (k-n) is even and (k-m) is even, then (k-n) - (k-m) = m-n must be even.
        // This means m and n must have the same parity.
        //
        // So, if (n % 2) != (m % 2), it's impossible.
        if ((n % 2) != (m % 2)) {
            std::cout << -1 << "\n";
            continue;
        }

        // If (n % 2) == (m % 2), then (k - n) and (k - m) must both be even.
        // This means k and n must have the same parity.
        // If (k % 2) != (n % 2), then it's impossible.
        if ((k % 2) != (n % 2)) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, all conditions for reachability are met.
        // k >= n
        // (n % 2) == (m % 2)
        // (k % 2) == (n % 2)
        // These three conditions together imply (k % 2) == (m % 2) and (k - n) % 2 == 0 and (k - m) % 2 == 0.

        // We want to maximize diagonal moves.
        // The minimum number of moves to reach (n, m) is n (assuming n >= m).
        // This can be achieved by n diagonal moves to (n, n) and then n-m straight moves to (n, m).
        // No, this is wrong. The minimum number of moves is n, by making m diagonal moves to (m,m)
        // and then n-m straight moves to (n,m). This uses m diagonal moves and n-m straight moves.
        // Total moves = m + (n-m) = n.
        // This path uses n moves and m diagonal moves.
        //
        // We have k total moves. We need to reach (n, m).
        // We can make n moves to reach (n, m) using m diagonal moves and n-m straight moves.
        // This leaves k - n moves.
        // Each pair of moves (+1,0) and (-1,0) (or similar for y or diagonal) can be added without changing the final position.
        // Each such pair consists of 2 moves.
        // If we add a pair of moves like (1,0) and (-1,0), it's two straight moves.
        // If we add a pair of moves like (1,1) and (-1,-1), it's two diagonal moves.
        // If we add a pair of moves like (1,0) and (0,1) and then (-1,-1), it's two straight and one diagonal.
        //
        // The key insight is that any two moves can be "cancelled out" in terms of position,
        // but they still count towards the total k moves.
        // For example, move (1,0) then (-1,0) brings you back to the same x,y.
        // This uses 2 straight moves.
        // Move (1,1) then (-1,-1) brings you back to the same x,y.
        // This uses 2 diagonal moves.
        //
        // We have k moves. We need to cover the "distance" n.
        // We can make n diagonal moves to reach (n, n) if n=m.
        // If n > m, we can make m diagonal moves to reach (m, m).
        // Then we need to cover n-m distance in x-direction. This takes n-m straight moves.
        // So, we use m diagonal moves and n-m straight moves. Total moves = m + (n-m) = n.
        // This leaves k - n moves.
        // These k - n moves must be "wasted" by moving back and forth.
        // Since (k - n) is even (from our parity checks), we can always waste them in pairs.
        // Each pair of wasted moves can be either two straight moves or two diagonal moves.
        // To maximize diagonal moves, we should waste them as two diagonal moves.
        // So, we add (k - n) / 2 pairs of diagonal moves.
        // Each pair adds 2 diagonal moves.
        // Total diagonal moves = m (from initial path) + (k - n) / 2 * 2
        // Total diagonal moves = m + (k - n)
        // This simplifies to k - (n - m).

        // Let's verify this.
        // Total moves = k.
        // Number of diagonal moves = D.
        // Number of straight moves = S.
        // D + S = k.
        //
        // We know that n and m are the final coordinates.
        // The minimum number of moves to reach (n,m) is n (assuming n >= m).
        // This path involves m diagonal moves and n-m straight moves.
        // So, we have at least m diagonal moves and at least n-m straight moves.
        //
        // The remaining k - n moves must be "extra" moves.
        // Since (k - n) is even, we can use (k - n) / 2 pairs of moves.
        // Each pair can be two diagonal moves (e.g., (1,1) then (-1,-1)).
        // Or each pair can be two straight moves (e.g., (1,0) then (-1,0)).
        // To maximize diagonal moves, we use (k - n) / 2 pairs of diagonal moves.
        //
        // So, the maximum diagonal moves = m (from the initial path) + 2 * ((k - n) / 2)
        // = m + (k - n)
        // = k - n + m.

        std::cout << k - n + m << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_diff = 0; // count(type 1) - count(type 2)
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s - count of 2s) among jars n, n-1, ..., n-k+1
    // This is equivalent to (count of 1s - count of 2s) among jars 1, ..., k
    // if we consider the left side as a separate array and reverse it.
    // Let's use the definition: diff_L[k] is the difference for jars 1 to k.
    // And diff_R[k] is the difference for jars 2n-k+1 to 2n.

    // We need to find a pair (k_L, k_R) such that
    // (initial_diff - diff_L_removed - diff_R_removed) == 0
    // where diff_L_removed is the difference of jars 1 to k_L
    // and diff_R_removed is the difference of jars 2n-k_R+1 to 2n.
    // This means initial_diff - (diff_L_removed + diff_R_removed) = 0
    // or diff_L_removed + diff_R_removed = initial_diff.

    // Let's define `bal[i]` as the balance (1s - 2s) for the prefix `a[0...i-1]`.
    // `bal[0] = 0`
    // `bal[i] = bal[i-1] + (a[i-1] == 1 ? 1 : -1)` for `i > 0`.
    // The balance of jars `0` to `k-1` (i.e., `k` jars) is `bal[k]`.
    // The balance of jars `2n-k` to `2n-1` (i.e., `k` jars) is `bal[2n] - bal[2n-k]`.

    // We are removing `k_L` jars from the left (jars `n-k_L` to `n-1`)
    // and `k_R` jars from the right (jars `n` to `n+k_R-1`).
    // This is not what the problem states.
    // "he chooses to empty either the first non-empty jar to his left or the first non-empty jar to his right."
    // This means he removes jars `n, n-1, ..., n-k_L+1` and `n+1, n+2, ..., n+k_R`.
    // The remaining jars are `1, ..., n-k_L` and `n+k_R+1, ..., 2n`.

    // Let's calculate the balance of the remaining jars.
    // Total balance of all jars is `initial_diff`.
    // If we remove `k_L` jars from the left (jars `n, n-1, ..., n-k_L+1`)
    // and `k_R` jars from the right (jars `n+1, n+2, ..., n+k_R`).
    // The remaining jars are `1, ..., n-k_L` and `n+k_R+1, ..., 2n`.

    // Let `pref_bal[i]` be the balance of jars `0` to `i-1`.
    // `pref_bal[0] = 0`.
    // `pref_bal[i] = pref_bal[i-1] + (a[i-1] == 1 ? 1 : -1)` for `i > 0`.
    // The balance of jars `0` to `n-k_L-1` is `pref_bal[n-k_L]`.
    // The balance of jars `n+k_R` to `2n-1` is `pref_bal[2n] - pref_bal[n+k_R]`.
    // The total balance of remaining jars is `pref_bal[n-k_L] + (pref_bal[2n] - pref_bal[n+k_R])`.
    // We want this to be 0.
    // So, `pref_bal[n-k_L] - pref_bal[n+k_R] + pref_bal[2n] = 0`.
    // Or `pref_bal[n+k_R] - pref_bal[n-k_L] = pref_bal[2n]`.

    // We need to find minimum `k_L + k_R`.
    // `k_L` can range from `0` to `n`.
    // `k_R` can range from `0` to `n`.

    // Let's precompute `pref_bal` values.
    std::vector<int> pref_bal(2 * n + 1, 0);
    for (int i = 0; i < 2 * n; ++i) {
        pref_bal[i + 1] = pref_bal[i] + (a[i] == 1 ? 1 : -1);
    }

    // `pref_bal[2n]` is the total balance of all jars.
    // We are looking for `pref_bal[n+k_R] - pref_bal[n-k_L] == pref_bal[2n]`.

    // Store `pref_bal[n-k_L]` values for `k_L` from `0` to `n`.
    // `n-k_L` ranges from `n` down to `0`.
    // Map `balance_value` to `min_k_L`.
    std::map<int, int> left_balances;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_idx = n - k_L; // Index for pref_bal
        int balance_val = pref_bal[current_idx];
        if (left_balances.find(balance_val) == left_balances.end()) {
            left_balances[balance_val] = k_L;
        } else {
            left_balances[balance_val] = std::min(left_balances[balance_val], k_L);
        }
    }

    int min_removed = 2 * n; // Max possible jars removed

    // Iterate `k_R` from `0` to `n`.
    // `n+k_R` ranges from `n` up to `2n`.
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_idx = n + k_R; // Index for pref_bal
        int balance_val_right = pref_bal[current_idx];

        // We need `balance_val_right - pref_bal[n-k_L] == pref_bal[2n]`.
        // So, `pref_bal[n-k_L] == balance_val_right - pref_bal[2n]`.
        int target_balance_left = balance_val_right - pref_bal[2 * n];

        if (left_balances.count(target_balance_left)) {
            int k_L = left_balances[target_balance_left];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: minimum distance to a 0 to the left (inclusive)
    // L[i] = 0 if a[i] == 0
    // L[i] = L[i-1] + 1 if a[i] == 1 and i > 0
    // L[0] = 0 if a[0] == 0, infinity if a[0] == 1 (effectively, no 0 to the left)
    // For our purpose, we can just say L[0] = 0 if a[0] == 0, else a large value.
    // But since we only care about L[i] for i > 0, and L[i] is distance to a[i] itself if a[i]==0,
    // we can initialize L[0] based on a[0].

    if (a[0] == 0) {
        L[0] = 0;
    } else {
        L[0] = n + 1; // Represents infinity for practical purposes
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = 0;
        } else {
            L[i] = L[i - 1] + 1;
        }
    }

    // Calculate R[i]: minimum distance to a 0 to the right (inclusive)
    // R[i] = 0 if a[i] == 0
    // R[i] = R[i+1] + 1 if a[i] == 1 and i < n-1
    // R[n-1] = 0 if a[n-1] == 0, infinity if a[n-1] == 1
    if (a[n - 1] == 0) {
        R[n - 1] = 0;
    } else {
        R[n - 1] = n + 1; // Represents infinity
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = 0;
        } else {
            R[i] = R[i + 1] + 1;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int dist_to_nearest_zero = std::min(L[i], R[i]);
            if (dist_to_nearest_zero == n + 1) { // No zeros in the sequence
                std::cout << 0 << std::endl;
                for (int j = 0; j < n; ++j) {
                    std::cout << a[j] << (j == n - 1 ? "" : " ");
                }
                std::cout << std::endl;
                return 0;
            }
            max_k = std::max(max_k, (dist_to_nearest_zero + 1) / 2);
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            b[i] = 0;
        } else { // a[i] == 1
            int dist_to_nearest_zero = std::min(L[i], R[i]);
            if (dist_to_nearest_zero == n + 1) { // Should not happen if max_k > 0
                b[i] = 1;
            } else if (dist_to_nearest_zero <= max_k) {
                b[i] = 0;
            } else {
                b[i] = 1;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max possible value for f(t) is N (length of s), which is 2e5.
    // 2^17 = 131072
    // 2^18 = 262144
    // So, the maximum length of a binary string whose decimal value is <= 2e5 is 18.
    // We can iterate through all possible starting positions `i`.
    // For each `i`, we can extend the substring to the right.
    // The maximum length of substring we need to check is 18 (or slightly more to be safe, say 20).
    // Let's use a constant `MAX_CHECK_LEN` for this.
    // A safe upper bound for MAX_CHECK_LEN would be 18 + 1 (for 0s) + 1 (safety) = 20.
    // Or simply, if the value exceeds N, we can stop.
    // The maximum value of N is 2e5.
    // The maximum length of a substring we need to consider is 18 (for 1xxxx... pattern).
    // If the substring starts with '0', it can have many leading zeros.
    // The actual length of the substring can be up to N.
    // The value f(t) is at most N.
    // The number of bits required to represent N is log2(N).
    // For N = 2e5, log2(2e5) is about 17.6. So, at most 18 bits.
    // This means the '1' in the binary representation cannot be further than 18 positions from the right end of the substring.
    // If a substring is s[l...r], its length is len = r - l + 1.
    // The value f(s[l...r]) must be equal to len.
    // If s[l] is '1', then the value is at least 2^(len-1).
    // If s[l] is '0', then we need to find the first '1' to calculate the value.
    // Let's iterate through all possible starting positions `i`.
    // For each `i`, we iterate through possible ending positions `j`.
    // The length of the substring s[i...j] is `len = j - i + 1`.
    // We need to calculate `val = f(s[i...j])`.
    // If `val == len`, it's a good substring.

    // The crucial observation is that if s[i] is '1', then `val` grows exponentially with `len`.
    // If `len` is large, `val` will quickly exceed `n`.
    // Specifically, if `s[i] == '1'`, then `val >= 2^(len-1)`.
    // If `2^(len-1) > n`, then `val > n`, so `val` cannot be equal to `len` (since `len <= n`).
    // `2^(len-1) > n` implies `len-1 > log2(n)`.
    // For `n = 2e5`, `log2(n)` is approx 17.6. So `len-1 > 17.6`, meaning `len > 18.6`.
    // So, if `s[i] == '1'`, we only need to check `len` up to about 19.
    // Let's set a practical limit, say `MAX_BITS = 20`.
    // This means for `s[i] == '1'`, we only need to check `j` such that `j - i + 1 <= MAX_BITS`.

    // What if `s[i]` is '0'?
    // Then `f(s[i...j])` is the value of `s[k...j]` where `k` is the first index >= `i` such that `s[k] == '1'`.
    // If all characters from `s[i...j]` are '0', then `f(s[i...j]) = 0`.
    // In this case, `len = j - i + 1`. If `len = 0`, it's a good substring. But `len` is always at least 1.
    // So `f(00...0) = 0` can never be equal to `len >= 1`.
    // Thus, a substring consisting only of '0's is never good.
    // This means we only care about substrings that contain at least one '1'.

    // Let's iterate `i` from `0` to `n-1`.
    // For each `i`, we iterate `j` from `i` to `n-1`.
    // We maintain the current binary value `current_val` and current length `current_len`.
    // We also need to handle leading zeros.

    for (int i = 0; i < n; ++i) {
        long long current_val = 0;
        // We need to find the first '1' to start calculating the value.
        // Let's say `first_one_idx` is the index of the first '1' in `s[i...j]`.
        // If `s[i]` is '0', we can skip it and count how many leading zeros there are.
        // The actual binary value starts from the first '1'.
        // The length of the substring is `j - i + 1`.
        // The value `f(s[i...j])` is the decimal value of `s[first_one_idx ... j]`.

        // Strategy: Iterate `i` from `0` to `n-1`.
        // For each `i`, iterate `j` from `i` to `n-1`.
        // Calculate `val = f(s[i...j])`.
        // If `val == j - i + 1`, increment count.
        // This is too slow (O(N^2 * logN) or O(N^2)). N=2e5, N^2=4e10.

        // Optimized strategy:
        // Iterate `i` from `0` to `n-1`.
        // Maintain `current_val` for `s[k...j]` where `k` is the first '1' in `s[i...j]`.
        // Maintain `leading_zeros_count` for `s[i...k-1]`.
        // The total length is `leading_zeros_count + (j - k + 1)`.

        // Let's fix the starting position `i`.
        // We need to find the first '1' at or after `i`.
        int first_one_idx = -1;
        for (int k = i; k < n; ++k) {
            if (s[k] == '1') {
                first_one_idx = k;
                break;
            }
        }

        if (first_one_idx == -1) {
            // No '1's from `i` to `n-1`. All remaining substrings are '0's.
            // f(00...0) = 0. Length is always >= 1. So no good substrings.
            break; // No more '1's in the rest of the string.
        }

        // Now `first_one_idx` is the index of the first '1' at or after `i`.
        // The number of leading zeros for a substring starting at `i` and having its first '1' at `first_one_idx` is `first_one_idx - i`.
        int leading_zeros = first_one_idx - i;
        current_val = 0;

        // Iterate `j` from `first_one_idx` to `n-1`.
        // This `j` is the right endpoint of the substring `s[i...j]`.
        // The actual binary value is formed by `s[first_one_idx ... j]`.
        // The length of this binary value part is `j - first_one_idx + 1`.
        // The total length of the substring `s[i...j]` is `leading_zeros + (j - first_one_idx + 1)`.

        for (int j = first_one_idx; j < n; ++j) {
            // Update current_val
            current_val = (current_val << 1) | (s[j] - '0');

            // Check if current_val exceeds a reasonable limit.
            // If current_val > n + MAX_BITS (e.g., 2e5 + 20), it's too large.
            // The maximum possible length is n.
            // If current_val > n, it cannot be equal to the length.
            // The length of the binary part is `j - first_one_idx + 1`.
            // The total length of the substring is `leading_zeros + (j - first_one_idx + 1)`.
            // If `current_val` becomes very large, it will exceed `n` and also `total_length`.
            // A safe upper bound for `current_val` to check is `n + MAX_BITS`.
            // `MAX_BITS` is roughly 18. So `n + 18`.
            // If `current_val` exceeds `n + 18`, then it's definitely too large to be equal to `total_length`.
            // This is because `total_length` is at most `n`.
            // So, if `current_val > n + 18`, we can break from this inner loop.
            // This is the key optimization.
            if (current_val > n + 20) { // Using 20 as a slightly larger safe constant
                break;
            }

            long long total_length = leading_zeros + (j - first_one_idx + 1);

            if (current_val == total_length) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Represents upper bounds for a_0[i]
    std::vector<long long> current_delta(n, 0);

    // First pass: Determine upper bounds for initial_a[i]
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Fill in unspecified initial_a values.
    // If initial_a[j] is still LLONG_MAX, it means no type 2 operation constrained it.
    // We can set it to 0, as it satisfies |a_i| <= 10^9 and doesn't violate any max constraints.
    // The problem statement says "all numbers in his array didn't exceed 10^9 in their absolute value".
    // This implies the initial values.
    // A value of 0 is always within [-10^9, 10^9].
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
        // Check if the determined initial_a[i] is within the allowed range.
        // If it's not, it's impossible.
        // However, the problem constraints on m_i and d_i are such that
        // m_i - current_delta[j] will fit in long long.
        // The final check for |a_i| <= 10^9 will be done after reconstruction.
    }

    // Second pass: Verify the solution
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta
    std::vector<long long> reconstructed_a(n);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                reconstructed_a[j] = initial_a[j] + current_delta[j];
                max_val = std::max(max_val, reconstructed_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Final check for initial_a values
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits initially 1
    int current_or_mask = 0;    // All bits initially 0
    int current_xor_mask = 0;   // All bits initially 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // Determine the final AND mask
    // If a bit is 0 in current_and_mask, it must be 0 in the final result.
    // If a bit is 1 in current_and_mask, it means it was 1 after all AND/OR/XOR operations on an initial 1.
    // So, the final AND mask is current_and_mask.
    // However, we need to consider the effect of XOR.
    // If a bit is 0 in current_and_mask, it means (1 & ... & C_i) is 0.
    // If a bit is 1 in current_and_mask, it means (1 & ... & C_i) is 1.
    // The final AND mask for the simplified operations should be such that it forces bits to 0 if they are 0 in current_and_mask.
    // This is equivalent to saying that the final AND mask should be current_and_mask.
    // But this is not quite right.
    // Let's use the property that (x & A) | B ^ C is the general form.
    // We have:
    // f(0) = (0 & current_and_mask) | current_or_mask ^ current_xor_mask
    // f(1023) = (1023 & current_and_mask) | current_or_mask ^ current_xor_mask

    // Let's find the equivalent A, B, C for (x & A) | B ^ C
    // For each bit i:
    // Let x_i be the i-th bit of input x.
    // Let a_i = (current_and_mask >> i) & 1
    // Let o_i = (current_or_mask >> i) & 1
    // Let c_i = (current_xor_mask >> i) & 1
    //
    // The final value of bit i for input x_i is:
    // if x_i = 0: (0 & a_i) | o_i ^ c_i = o_i ^ c_i
    // if x_i = 1: (1 & a_i) | o_i ^ c_i = a_i | o_i ^ c_i

    // Let's define the target values for each bit:
    // target_bit_0[i] = (o_i ^ c_i)
    // target_bit_1[i] = (a_i | o_i ^ c_i)

    // We want to find A, B, C such that for each bit i:
    // (0 & A_i) | B_i ^ C_i = target_bit_0[i]
    // (1 & A_i) | B_i ^ C_i = target_bit_1[i]

    // From the first equation: B_i ^ C_i = target_bit_0[i]
    // Substitute into the second: A_i | target_bit_0[i] = target_bit_1[i]

    // This gives us:
    // B_i ^ C_i = target_bit_0[i]
    // A_i | target_bit_0[i] = target_bit_1[i]

    // From A_i | target_bit_0[i] = target_bit_1[i]:
    // If target_bit_0[i] = 0: A_i = target_bit_1[i]
    // If target_bit_0[i] = 1: target_bit_1[i] must be 1. If not, it's impossible.
    // (But it will always be consistent because target_bit_0[i] <= target_bit_1[i] is always true:
    // o_i ^ c_i <= a_i | o_i ^ c_i)
    // So, A_i = target_bit_1[i] if target_bit_0[i] = 0, and A_i can be 0 or 1 if target_bit_0[i] = 1.
    // To minimize operations, we want A_i to be 1 only if necessary.
    // So, A_i = target_bit_1[i] & (~target_bit_0[i]) is not quite right.
    // A_i must be 1 if target_bit_1[i] is 1 and target_bit_0[i] is 0.
    // A_i can be 0 or 1 if target_bit_1[i] is 1 and target_bit_0[i] is 1.
    // A_i must be 0 if target_bit_1[i] is 0.
    // The simplest choice for A_i is A_i = target_bit_1[i] & (~target_bit_0[i]).
    // This means A = (target_bit_1 & (~target_bit_0)).
    // Let's verify: (x & A) | target_bit_0.
    // If x_i = 0: (0 & A_i) | target_bit_0[i] = target_bit_0[i]. Correct.
    // If x_i = 1: (1 & A_i) | target_bit_0[i] = A_i | target_bit_0[i].
    // A_i | target_bit_0[i] = (target_bit_1[i] & (~target_bit_0[i])) | target_bit_0[i]
    // = (target_bit_1[i] | target_bit_0[i]) & ((~target_bit_0[i]) | target_bit_0[i])
    // = (target_bit_1[i] | target_bit_0[i]) & 1
    // = target_bit_1[i] | target_bit_0[i].
    // This must be equal to target_bit_1[i]. This implies target_bit_0[i] <= target_bit_1[i], which is true.
    // So, the simplified form is (x & A) | B, where B = target_bit_0.
    // This means C = 0.

    // Let's calculate A and B.
    int A = 0;
    int B = 0;

    for (int i = 0; i < 10; ++i) {
        int a_i = (current_and_mask >> i) & 1;
        int o_i = (current_or_mask >> i) & 1;
        int c_i = (current_xor_mask >> i) & 1;

        int target_bit_0_i = o_i ^ c_i;
        int target_bit_1_i = (a_i | o_i) ^ c_i; // This is the correct calculation for f(1023) bit i

        // B_i = target_bit_0_i
        if (target_bit_0_i == 1) {
            B |= (1 << i);
        }

        // A_i = target_bit_1_i if target_bit_0_i = 0
        // A_i = 0 if target_bit_1_i = 0 and target_bit_0_i = 1 (impossible)
        // A_i = 0 if target_bit_1_i = 1 and target_bit_0_i = 1
        // So A_i = target_bit_1_i & (~target_bit_0_i)
        if (target_bit_1_i == 1 && target_bit_0_i == 0) {
            A |= (1 << i);
        }
    }

    // The simplified form is (x & A) | B.
    // This can be represented as:
    // 1. & A
    // 2. | B
    // Or if A=1023, just | B.
    // Or if B=0, just & A.
    // Or if A=1023 and B=0, no ops.

    if (A != 1023) { // If A is not all ones, we need an AND operation
        result_ops.push_back({'&', A});
    }
    if (B != 0) { // If B is not all zeros, we need an OR operation
        result_ops.push_back({'|', B});
    }

    // The problem statement implies that the final form is (x & A) | B ^ C.
    // Let's re-evaluate the general form.
    // The final value for bit i is `(x_i & A_i) | B_i ^ C_i`.
    // Let `f_0 = current_or_mask ^ current_xor_mask` (result for input 0)
    // Let `f_1 = (current_and_mask | current_or_mask) ^ current_xor_mask` (result for input 1023)

    // We need to find A, B, C such that:
    // `(0 & A) | B ^ C = f_0`
    // `(1023 & A) | B ^ C = f_1`

    // From the first equation: `B ^ C = f_0`
    // Substitute into the second: `(1023 & A) | f_0 = f_1`

    // Let's find A, B, C bit by bit.
    // For each bit `i`:
    // `B_i ^ C_i = (f_0 >> i) & 1`
    // `(A_i) | ((f_0 >> i) & 1) = ((f_1 >> i) & 1)`

    // Let `f0_i = (f_0 >> i) & 1` and `f1_i = (f_1 >> i) & 1`.
    // `A_i | f0_i = f1_i`.
    // This implies `f0_i <= f1_i`. This is always true because `(current_or_mask ^ current_xor_mask)`
    // is a submask of `((current_and_mask | current_or_mask) ^ current_xor_mask)` if we consider the XOR part as a flip.
    // More precisely, `f0_i` is the value of bit `i` when input is 0.
    // `f1_i` is the value of bit `i` when input is 1.
    // The transformation for bit `i` is `x_i -> (x_i & a_i) | o_i ^ c_i`.
    // So `f0_i = o_i ^ c_i`.
    // And `f1_i = (1 & a_i) | o_i ^ c_i = a_i | o_i ^ c_i`.
    // It is always true that `o_i ^ c_i <= a_i | o_i ^ c_i`.

    // From `A_i | f0_i = f1_i`:
    // If `f0_i = 0`: `A_i = f1_i`.
    // If `f0_i = 1`: `f1_i` must be 1. `A_i` can be 0 or 1. We choose `A_i = 0` to simplify.
    // So, `A_i = f1_i & (~f0_i)`.
    // This means `A = f_1 & (~f_0)`.

    // Now we have `B ^ C = f_0`.
    // We can choose `B = f_0` and `C = 0`. This gives `| f_0`.
    // Or we can choose `B = 0` and `C = f_0`. This gives `^ f_0`.
    // Or we can choose `B = X` and `C = X ^ f_0`.

    // The standard simplified form is `(x & A) | B ^ C`.
    // We found `A = f_1 & (~f_0)`.
    // We need to represent `f_0` using `| B ^ C`.
    // The most compact way is to use one OR and one XOR.
    // If `f_0` has bits set, we can use `| f_0` (i.e., `B = f_0, C = 0`).
    // If `f_0` has bits set, we can use `^ f_0` (i.e., `B = 0, C = f_0`).
    // The problem is that `| B` and `^ C` are applied sequentially.
    // `(x & A) | B` then `^ C`.
    // So the final form is `((x & A) | B) ^ C`.

    // Let's re-calculate `f_0` and `f_1` based on the original operations.
    // `f_0` is the result of applying all operations to `0`.
    // `f_1` is the result of applying all operations to `1023`.
    int val0 = 0;
    int val1 = 1023;

    // Re-run the operations on val0 and val1
    // This is equivalent to what current_and_mask, current_or_mask, current_xor_mask track.
    // Let's verify:
    // For input `x`, the output bit `i` is `(x_i & a_i) | o_i ^ c_i`.
    // `val0` corresponds to `o_i ^ c_i` for each bit `i`.
    // `val1` corresponds to `a_i | o_i ^ c_i` for each bit `i`.
    // So, `val0 = current_or_mask ^ current_xor_mask`.
    // And `val1 = (current_and_mask | current_or_mask) ^ current_xor_mask`.
    // This is correct.

    // Now we need to find A, B, C for `((x & A) | B) ^ C`.
    // For each bit `i`:
    // `((0 & A_i) | B_i) ^ C_i = val0_i`  => `B_i ^ C_i = val0_i`
    // `((1 & A_i) | B_i) ^ C_i = val1_i`  => `(A_i | B_i) ^ C_i = val1_i`

    // From `B_i ^ C_i = val0_i`, we have `C_i = B_i ^ val0_i`.
    // Substitute into the second equation:
    // `(A_i | B_i) ^ (B_i ^ val0_i) = val1_i`

    // This is the general form.
    // We want to minimize operations.
    // The problem states "no more than 5 lines".
    // The standard simplified form is `& A`, `| B`, `^ C`.
    // This is 3 operations.

    // Let's try to find A, B, C for `((x & A) | B) ^ C`.
    // We need to determine `A_i`, `B_i`, `C_i` for each bit `i`.
    // Let `f(x_i)` be the final value of bit `i` for input `x_i`.
    // `f(0) = val0_i`
    // `f(1) = val1_i`

    // Case 1: `f(0) = 0, f(1) = 0`
    // `B_i ^ C_i = 0` => `B_i = C_i`
    // `(A_i | B_i) ^ C_i = 0` => `A_i | B_i = C_i`
    // So `A_i | B_i = B_i`. This implies `A_i = 0`.
    // We can choose `B_i = 0, C_i = 0`.
    // Result: `A_i = 0, B_i = 0, C_i = 0`.

    // Case 2: `f(0) = 0, f(1) = 1`
    // `B_i ^ C_i = 0` => `B_i = C_i`
    // `(A_i | B_i) ^ C_i = 1` => `A_i | B_i = C_i ^ 1`
    // So `A_i | B_i = B_i ^ 1`.
    // If `B_i = 0`: `A_i | 0 = 0 ^ 1` => `A_i = 1`.
    // If `B_i = 1`: `A_i | 1 = 1 ^ 1` => `1 = 0`. Impossible.
    // So we must have `B_i = 0, C_i = 0, A_i = 1`.
    // Result: `A_i = 1, B_i = 0, C_i = 0`.

    // Case 3: `f(0) = 1, f(1) = 0`
    // `B_i ^ C_i = 1` => `C_i = B_i ^ 1`
    // `(A_i | B_i) ^ C_i = 0` => `A_i | B_i = C_i`
    // So `A_i | B_i = B_i ^ 1`.
    // If `B_i = 0`: `A_i | 0 = 0 ^ 1` => `A_i = 1`.
    // If `B_i = 1`: `A_i | 1 = 1 ^ 1` => `1 = 0`. Impossible.
    // So we must have `B_i = 0, C_i = 1, A_i = 1`.
    // Result: `A_i = 1, B_i = 0, C_i = 1`.

    // Case 4: `f(0) = 1, f(1) = 1`
    // `B_i ^ C_i = 1` => `C_i = B_i ^ 1`
    // `(A_i | B_i) ^ C_i = 1` => `A_i | B_i = C_i ^ 1`
    // So `A_i | B_i = (B_i ^ 1) ^ 1 = B_i`.
    // This implies `A_i = 0`.
    // We can choose `B_i = 0, C_i = 1`.
    // Result: `A_i = 0, B_i = 0, C_i = 1`.

    // Summarizing the choices for `A_i, B_i, C_i` to achieve `f(0)` and `f(1)`:
    // `A_i` is 1 if `f(0) = 0` and `f(1) = 1` (Case 2) OR `f(0) = 1` and `f(1) = 0` (Case 3).
    // This is `A_i = f(0) ^ f(1)`.
    // `B_i` is always 0 in these minimal choices.
    // `C_i` is 1 if `f(0) = 1` (Case 3, Case 4).
    // This is `C_i = f(0)`.

    // So, the simplified operations are:
    // `& (f_0 ^ f_1)`
    // `^ f_0`
    // This is two operations.

    int final_A = 0; // This is the A in `x & A`
    int final_C = 0; // This is the C in `^ C`

    for (int i = 0; i < 10; ++i) {
        int f0_i = (current_or_mask >> i) & 1 ^ (current_xor_mask >> i) & 1;
        int f1_i = ((current_and_mask >> i) & 1 | (current_or_mask >> i) & 1) ^ ((current_xor_mask >> i) & 1);

        if (f0_i ^ f1_i) { // If f(0) != f(1), then A_i must be 1
            final_A |= (1 << i);
        }
        if (f0_i) { // If f(0) = 1, then C_i must be 1
            final_C |= (1 << i);
        }
    }

    // The simplified program is `(x & final_A) ^ final_C`.
    // This is at most two operations.
    // If `final_A == 1023` (all bits 1), then `x & final_A` is just `x`. So we only need `^ final_C`.
    // If `final_C == 0`, then `x ^ final_C` is just `x`. So we only need `& final_A`.
    // If `final_A == 1023` and `final_C == 0`, then no operations are needed.

    if (final_A != 1023) {
        result_ops.push_back({'&', final_A});
    }
    if (final_C != 0) {
        result_ops.push_back({'^', final_C});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].id = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_office_cry_effect = children[i].v;
        long long accumulated_hall_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated hall cry effect
            children[j].p -= accumulated_hall_cry_effect;

            // Apply current office cry effect
            if (current_office_cry_effect > 0) {
                children[j].p -= current_office_cry_effect;
                current_office_cry_effect--;
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_hall_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The minimum possible value for b_i, considering b_{i-1}

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a_i + x_i >= prev_val
        // We need (a_i + x_i) % m >= prev_val.
        // The smallest possible value for (a_i + x_i) % m is a_i itself (if x_i=0).
        // The largest possible value for (a_i + x_i) % m is (a_i + x) % m.
        // If a_i >= prev_val, we can choose x_i = 0, and b_i = a_i. This is valid.
        // So, prev_val for the next element remains a_i.
        if (current_a >= prev_val) {
            // We need to check if we can make b_i = a_i.
            // This requires x_i = 0, which is <= x. This is always possible.
            // However, we might need to increment a_i to make it larger than prev_val
            // if a_i is too small relative to prev_val, but a_i + x is large enough.
            // Example: prev_val = 5, a_i = 1, m = 10, x = 3.
            // If we choose x_i = 0, b_i = 1, which is < prev_val. Not allowed.
            // We need b_i >= prev_val.
            // The values we can achieve for b_i are in range [a_i, (a_i + x) % m] if a_i + x < m,
            // or [a_i, m-1] U [0, (a_i + x) % m] if a_i + x >= m.
            // More simply, we can achieve any value v such that v = (a_i + k) % m for 0 <= k <= x.

            // If a_i + x < m:
            // The possible values for b_i are [a_i, a_i + x].
            // If a_i >= prev_val, we can pick b_i = a_i.
            // If a_i < prev_val, we need a_i + x >= prev_val. If so, we can pick b_i = prev_val.
            // If a_i + x < prev_val, then it's impossible.

            // If a_i + x >= m: (i.e., we can wrap around)
            // The possible values for b_i are [a_i, m-1] U [0, (a_i + x) % m].
            // We can always pick b_i = prev_val if prev_val is in this range.
            // Since prev_val is always <= m-1, and we can achieve any value from 0 to (a_i + x) % m,
            // and also values from a_i to m-1, we can always achieve prev_val.
            // So, if a_i + x >= m, we can always set b_i = prev_val.

            // Combining these:
            // If a_i + x >= m, we can always make b_i = prev_val.
            // If a_i + x < m:
            //   If a_i >= prev_val, we can make b_i = a_i.
            //   If a_i < prev_val, we need a_i + x >= prev_val. If so, we can make b_i = prev_val.
            //   If a_i < prev_val AND a_i + x < prev_val, then it's impossible.

            // Let's simplify the logic:
            // We need to find a b_i such that prev_val <= b_i <= (a_i + x) % m (if no wrap-around)
            // or prev_val <= b_i and b_i can be (a_i + k) % m for 0 <= k <= x.

            // If a_i + x < m:
            //   If a_i >= prev_val, we can choose x_i = 0, so b_i = a_i.
            //   If a_i < prev_val, we must increment a_i. We need a_i + x_i >= prev_val.
            //     The maximum value we can reach is a_i + x. If a_i + x < prev_val, it's impossible.
            //     Otherwise, we can choose x_i such that a_i + x_i = prev_val.
            //     So, if a_i < prev_val and a_i + x < prev_val, this path is invalid.
            //     Otherwise, we can set b_i = prev_val.
            // So, if a_i < prev_val and a_i + x < prev_val, return false.
            // Otherwise, we can set b_i = max(prev_val, a_i).
            // This is equivalent to: if a_i < prev_val, we must use prev_val.
            // If a_i >= prev_val, we can use a_i.
            // So, if a_i < prev_val, we must check if a_i + x >= prev_val. If not, impossible.
            // If a_i >= prev_val, we can just use a_i.
            // So, if a_i < prev_val and a_i + x < prev_val, then it's impossible.
            // Otherwise, prev_val for next iteration is max(prev_val, a_i).
            // This is wrong. If a_i < prev_val, we must set b_i = prev_val.
            // If a_i >= prev_val, we can set b_i = a_i.
            // So, if a_i < prev_val, we must check if a_i + x >= prev_val. If not, return false.
            // If it is, then we set b_i = prev_val.
            // If a_i >= prev_val, we set b_i = a_i.
            // So, if a_i < prev_val and a_i + x < prev_val, return false.
            // Otherwise, prev_val for next iteration is prev_val. (This is if we set b_i = prev_val)
            // Or prev_val for next iteration is a_i. (This is if we set b_i = a_i)
            // We want to minimize b_i to allow more flexibility for b_{i+1}.
            // So, if a_i >= prev_val, we can choose b_i = a_i.
            // If a_i < prev_val, we must choose b_i = prev_val. This is only possible if a_i + x >= prev_val.
            // So, if a_i < prev_val and a_i + x < prev_val, it's impossible.
            // Otherwise, the next prev_val is prev_val.
            // This is the correct logic for the case where a_i + x < m.
            // If a_i >= prev_val, we can choose x_i = 0, so b_i = a_i. The next prev_val is a_i.
            // If a_i < prev_val, we need to increment a_i. We must ensure a_i + x >= prev_val.
            // If a_i + x < prev_val, it's impossible.
            // If a_i + x >= prev_val, we can choose x_i such that (a_i + x_i) % m = prev_val.
            // The next prev_val is prev_val.
            // So, if a_i >= prev_val, next prev_val = a_i.
            // Else (a_i < prev_val): if a_i + x < prev_val, return false. Else, next prev_val = prev_val.
            // This is for the case where a_i + x < m.

            // Let's consider the two ranges for b_i:
            // 1. b_i is in [prev_val, m-1].
            // 2. b_i is in [0, prev_val-1]. This is only possible if we wrap around.

            // If a_i + x < m:
            //   The possible values for b_i are [a_i, a_i + x].
            //   If a_i >= prev_val: We can choose b_i = a_i. This is the smallest possible valid b_i.
            //     So, prev_val for next iteration becomes a_i.
            //   If a_i < prev_val: We need b_i >= prev_val. The smallest possible b_i is prev_val.
            //     This requires a_i + x >= prev_val. If not, it's impossible.
            //     If a_i + x >= prev_val, we can choose b_i = prev_val.
            //     So, prev_val for next iteration becomes prev_val.
            // This can be summarized:
            // If a_i >= prev_val: next_prev_val = a_i.
            // Else (a_i < prev_val):
            //   If a_i + x < prev_val: return false.
            //   Else: next_prev_val = prev_val.
            // This is for the case where a_i + x < m.

            // If a_i + x >= m: (wrap around is possible)
            //   The possible values for b_i are [a_i, m-1] U [0, (a_i + x) % m].
            //   We want to find the smallest b_i >= prev_val.
            //   If prev_val is in [a_i, m-1], we can choose b_i = prev_val.
            //   If prev_val is in [0, (a_i + x) % m], we can choose b_i = prev_val.
            //   Since prev_val is always <= m-1, and we can achieve any value from 0 to (a_i + x) % m,
            //   and also values from a_i to m-1, we can always achieve prev_val.
            //   So, if a_i + x >= m, we can always set b_i = prev_val.
            //   Thus, prev_val for next iteration becomes prev_val.

            // Let's combine these two cases:
            // If a_i + x >= m:
            //   We can always achieve prev_val. So, next prev_val is prev_val.
            // Else (a_i + x < m):
            //   If a_i >= prev_val:
            //     We can achieve a_i (by x_i=0). This is the smallest valid b_i.
            //     So, next prev_val is a_i.
            //   Else (a_i < prev_val):
            //     We need to achieve at least prev_val. The smallest value we can achieve is a_i.
            //     The largest value we can achieve without wrap-around is a_i + x.
            //     If a_i + x < prev_val, it's impossible. Return false.
            //     Otherwise (a_i + x >= prev_val), we can achieve prev_val.
            //     So, next prev_val is prev_val.

            // This logic seems correct.
            if (current_a + x < m) { // No wrap-around possible for a_i + x
                if (current_a >= prev_val) {
                    // We can choose x_i = 0, b_i = a_i. This is valid and minimal.
                    prev_val = current_a;
                } else { // current_a < prev_val
                    // We must increment a_i. Check if we can reach prev_val.
                    if (current_a + x < prev_val) {
                        return false; // Cannot reach prev_val
                    }
                    // Else, we can reach prev_val. We choose b_i = prev_val.
                    // prev_val remains prev_val.
                }
            } else { // Wrap-around possible for a_i + x (current_a + x >= m)
                // We can achieve any value in [current_a, m-1] and [0, (current_a + x) % m].
                // Since prev_val is always <= m-1, we can always achieve prev_val.
                // So, we choose b_i = prev_val.
                // prev_val remains prev_val.
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and a_i values to prevent overflow
// a_i can be up to 10^9, and y can accumulate many such values.
// x can be up to n, which is 2*10^5.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_val[0] is unused, a_val[1] corresponds to a_2, ..., a_val[n-1] corresponds to a_n
    // We will adjust indices to be 0-based for convenience, so a_val[k] stores a_{k+2}
    // Or, more simply, store a_2 at index 2, a_3 at index 3, etc.
    // So, a_arr[0] and a_arr[1] are unused. a_arr[k] stores a_k.
    std::vector<long long> a_arr(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_arr[i];
    }

    // dp_x[k] stores the final x position if we start at (k, 0) and take one pair of steps (x+a_x, y+a_x), then (x-a_x, y+a_x)
    // dp_y[k] stores the total y accumulated if we start at (k, 0) and take one pair of steps
    // dp_x[k] and dp_y[k] are for the state *after* the first pair of steps.
    // We need to handle the initial a_1 value separately for each query.
    // The actual values a_2, ..., a_n are fixed.
    // The problem states "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
    // This means a_1 is set to 'i' for each run.

    // We need to compute results for starting x values from 1 to n.
    // Let's define dp_x[k] as the next x position if we are at x=k and take the first step (x+a_x).
    // Let's define dp_y[k] as the y accumulated if we are at x=k and take the first step (y+a_x).
    // This is not quite right. The problem has a loop.
    // Let's define dp_next_x[k] and dp_total_y[k] as the state (x, y) after the *entire sequence of operations*
    // starting from x=k, assuming a_k is the value used.
    // This is a dynamic programming approach where we compute results for larger x values first.
    // If x + a_x > n or x + a_x <= 0, then the program terminates after the first step.
    // If x - a_x > n or x - a_x <= 0, then the program terminates after the second step.
    // Otherwise, it continues from x - a_x.

    // dp_next_x[k] stores the final x position if we start at x=k and apply the operations.
    // dp_total_y[k] stores the total y accumulated if we start at x=k and apply the operations.
    // Initialize with -2 to indicate not computed, or -1 for infinite loop.
    std::vector<long long> dp_total_y(n + 1, -2); // -2 means not computed, -1 means infinite loop
    std::vector<long long> dp_final_x(n + 1, -2); // -2 means not computed, -1 means infinite loop

    // Iterate from n down to 1 to fill DP table
    for (int k = n; k >= 1; --k) {
        long long current_a_k = a_arr[k];

        long long x_after_step1 = k + current_a_k;
        long long y_after_step1 = current_a_k;

        if (x_after_step1 > n || x_after_step1 <= 0) {
            // Terminates after step 1
            dp_final_x[k] = x_after_step1;
            dp_total_y[k] = y_after_step1;
        } else {
            // Continues to step 2
            long long x_after_step2 = x_after_step1 - current_a_k;
            long long y_after_step2 = y_after_step1 + current_a_k;

            if (x_after_step2 > n || x_after_step2 <= 0) {
                // Terminates after step 2
                dp_final_x[k] = x_after_step2;
                dp_total_y[k] = y_after_step2;
            } else {
                // Continues from x_after_step2.
                // This is where the DP comes in.
                // We need to check if dp_total_y[x_after_step2] is already computed.
                // Since we iterate k downwards, x_after_step2 = k + a_k - a_k = k.
                // This is an infinite loop if a_k is not 0.
                // If x_after_step2 == k, it means we return to the same state, which is an infinite loop.
                // This is only true if a_k is 0, which is not allowed (a_i >= 1).
                // So x_after_step2 will be different from k.
                // The problem states x = x + a_x, y = y + a_x, then x = x - a_x, y = y + a_x.
                // So the next x is k - a_k.
                // Let's re-evaluate the state transition.
                // Current state: (x, y)
                // 1. x' = x + a_x, y' = y + a_x
                // 2. x'' = x' - a_x', y'' = y' + a_x'
                // This is the tricky part. The problem says "The program now increases y by a_x while decreasing x by a_x."
                // This means a_x from the *original* x, not the new x'.
                // So, if current x is `curr_x`, and `val = a_arr[curr_x]`:
                // Step 1: `next_x = curr_x + val`, `curr_y = curr_y + val`
                // Step 2: `next_x = next_x - val`, `curr_y = curr_y + val`
                // So, the x value after one full cycle of (step 2, step 3) is `curr_x + val - val = curr_x`.
                // This would mean an infinite loop if `curr_x + val` and `curr_x` are both within bounds.
                // This interpretation makes the problem trivial (always infinite loop if within bounds).
                // Let's re-read carefully: "The program increases both x and y by a value equal to a_x simultaneously."
                // "The program now increases y by a_x while decreasing x by a_x."
                // This implies `a_x` refers to the `a` value at the *current* `x` at the time of the operation.
                // Let `x_0` be the initial `x`.
                // Step 2: `x_1 = x_0 + a[x_0]`, `y_1 = y_0 + a[x_0]`
                // Step 3: `x_2 = x_1 - a[x_1]`, `y_2 = y_1 + a[x_1]`
                // This is the standard interpretation for competitive programming problems.
                // So, `x_after_step1` is the new `x` for the second operation.

                // If `x_after_step1` is out of bounds, we terminate. This is handled.
                // If `x_after_step1` is in bounds:
                // `val_at_x_after_step1 = a_arr[x_after_step1]`
                // `x_after_step2 = x_after_step1 - val_at_x_after_step1`
                // `y_after_step2 = y_after_step1 + val_at_x_after_step1`

                long long val_at_x_after_step1 = a_arr[x_after_step1];
                long long next_x_for_dp = x_after_step1 - val_at_x_after_step1;
                long long y_accumulated_in_this_pair = y_after_step1 + val_at_x_after_step1;

                if (next_x_for_dp > n || next_x_for_dp <= 0) {
                    // Terminates after this pair of steps
                    dp_final_x[k] = next_x_for_dp;
                    dp_total_y[k] = y_accumulated_in_this_pair;
                } else {
                    // Continues from next_x_for_dp.
                    // We need to check if dp_total_y[next_x_for_dp] is already computed.
                    // Since we iterate k downwards, next_x_for_dp could be smaller or larger than k.
                    // If next_x_for_dp > k, it means we need to compute it.
                    // If next_x_for_dp < k, it means it's already computed.
                    // This suggests a recursive approach with memoization or a different DP order.
                    // The maximum value of x is n. The minimum is 1.
                    // The values a_i are positive.
                    // x_after_step1 = k + a_k. This is always > k.
                    // next_x_for_dp = (k + a_k) - a_{k+a_k}. This can be anything.
                    // This is a graph problem. Each state (x) transitions to (x + a_x - a_{x+a_x}).
                    // We can detect cycles using visited states.

                    // Let's use a recursive function with memoization.
                    // `solve(current_x)` returns a pair {final_x, total_y}
                    // If `dp_total_y[current_x]` is not -2, return it.
                    // If `current_x` is in a cycle, return {-1, -1} (or some indicator for infinite loop).

                    // To detect cycles, we can use a `visiting` array.
                    // 0: not visited
                    // 1: currently visiting (in recursion stack)
                    // 2: finished visiting (memoized)
                    std::vector<int> visited_state(n + 1, 0); // 0: unvisited, 1: visiting, 2: visited

                    std::function<std::pair<long long, long long>(int)> solve = 
                        [&](int current_x) -> std::pair<long long, long long> {
                        if (current_x <= 0 || current_x > n) {
                            return {current_x, 0}; // Base case: terminated, 0 additional y
                        }
