struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;
    long long second_min_a = elements[1].value;
    long long second_max_a = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (second_max_a + max_a) - (min_a + second_min_a);
    std::vector<int> partition1(n, 1);

