    //
    // The minimum possible sum `a_i + a_j` is `min_a + second_min_a`.
    // The maximum possible sum `a_i + a_j` is `second_max_a + max_a`.
    //
    // If we put `min_a` in group 1 and `max_a` in group 2, and all other elements `a_i` (for `1 < i < n-1`) in group 1.
    // Group 1: `min_a`, `a_2`, ..., `a_{n-1}`
    // Group 2: `max_a`
    //
    // Values of f:
    // - `min_a + a_i` for `i \in [1, n-2]` (same group)
    // - `a_i + a_j` for `i, j \in [1, n-2]` (same group)
    // - `min_a + max_a + h` (different groups)
    // - `a_i + max_a + h` for `i \in [1, n-2]` (different groups)
    //
    // min_f:
    //   - `min_a + second_min_a` (from group 1)
    //   - `min_a + max_a + h` (from different groups)
    //   - `second_min_a + max_a + h` (from different groups)
    // So, `min_f = std::min(min_a + second_min_a, min_a + max_a + h)`
    //
    // max_f:
    //   - `second_max_a + elements[n-2].value` (from group 1)
    //   - `second_max_a + max_a + h` (from different groups)
    //   - `min_a + max_a + h` (from different groups)
    // So, `max_f = std::max(second_max_a + elements[n-2].value, second_max_a + max_a + h)`
    //
    // This is the partition where elements[0] is in group 1, elements[n-1] is in group 2,
    // and all elements[1]...elements[n-2] are in group 1.
    //
    // Let's call this "split_ends" partition.
    // Group 1: elements[0], elements[1], ..., elements[n-2]
    // Group 2: elements[n-1]
    //
    // min_f_split_ends:
    //   - `elements[0].value + elements[1].value` (from group 1)
    //   - `elements[0].value + elements[n-1].value + h` (across groups)
    //   - `elements[1].value + elements[n-1].value + h` (across groups)
    // So, `min_f_split_ends = std::min({elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h})`
    // (The `elements[1].value + elements[n-1].value + h` is always >= `elements[0].value + elements[n-1].value + h` because `elements[1].value >= elements[0].value`)
    //
    // max_f_split_ends:
    //   - `elements[n-3].value + elements[n-2].value` (from group 1, if n >= 3)
    //   - `elements[n-2].value + elements[n-1].value + h` (across groups)
    // So, `max_f_split_ends = std::max(elements[n-2].value + elements[n-1].value + h, elements[n-3].value + elements[n-2].value)` (if n >= 3)
    // If n=2, then group 1 has elements[0], group 2 has elements[1]. Only one pair: elements[0]+elements[1]+h.
    // If n=2, min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    //
    // Let's refine the split_ends partition:
    // Group 1: elements[0], elements[1], ..., elements[n-2]
    // Group 2: elements[n-1]
    //
    // Possible f values:
    // 1. `elements[i].value + elements[j].value` for `0 <= i < j <= n-2` (within group 1)
    //    Min: `elements[0].value + elements[1].value`
    //    Max: `elements[n-3].value + elements[n-2].value` (if n >= 3)
    // 2. `elements[i].value + elements[n-1].value + h` for `0 <= i <= n-2` (across groups)
    //    Min: `elements[0].value + elements[n-1].value + h`
    //    Max: `elements[n-2].value + elements[n-1].value + h`
    //
    // So, for this partition:
    // `min_f_val = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h)` (if n >= 2)
    // `max_f_val = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h)` (if n >= 3)
    //
    // Special handling for n=2:
    // Group 1: elements[0]
    // Group 2: elements[1]
    // Only one pair: (elements[0], elements[1]). They are in different groups.
    // f = elements[0].value + elements[1].value + h.
    // min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    //
    // Special handling for n=3:
    // Group 1: elements[0], elements[1]
    // Group 2: elements[2]
    // Pairs:
    //   - (elements[0], elements[1]): elements[0].value + elements[1].value (same)
    //   - (elements[0], elements[2]): elements[0].value + elements[2].value + h (diff)
    //   - (elements[1], elements[2]): elements[1].value + elements[2].value + h (diff)
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[1].value + elements[2].value + h
    // Goodness = (elements[1].value + elements[2].value + h) - (elements[0].value + elements[1].value)
    //          = elements[2].value + h - elements[0].value
    //
    // Let's calculate goodness for this "split_ends" partition for general n >= 2.
    long long min_f_split_ends;
    long long max_f_split_ends;

    if (n == 2) {
        min_f_split_ends = elements[0].value + elements[1].value + h;
        max_f_split_ends = elements[0].value + elements[1].value + h;
    } else { // n >= 3
        min_f_split_ends = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
        max_f_split_ends = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h);
    }
    long long goodness2 = max_f_split_ends - min_f_split_ends;
    std::vector<int> partition2(n);
    for (int i = 0; i < n - 1; ++i) {
        partition2[elements[i].original_index] = 1;
    }
    partition2[elements[n-1].original_index] = 2;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // The only way to form a new string is s2s1.
    // We need s2s1 to be a palindrome and s2s1 != s.
    // This is possible if s is not a "half-palindrome" (e.g., "abccba" is, "abcde" is not)
    // and s is not composed of all identical characters.

    // If all characters are the same, e.g., "aaaa", "qqqq"
    // Any cut s1|s2 will result in s1s2 = s and s2s1 = s.
    // For example, "a|aaa" -> "aaaa". "aa|aa" -> "aaaa".
    // So, if all characters are the same, k=1 is impossible.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }
    if (all_same) {
        std::cout << "Impossible\n";
        return 0;
    }

    // If not all characters are the same, k=1 might be possible.
    // Consider s = "otto". s1="ot", s2="to". s2s1 = "toot". "toot" is a palindrome and != "otto".
    // Consider s = "nolon". s1="no", s2="lon". s2s1 = "lonno". Not a palindrome.
    // s1="nol", s2="on". s2s1 = "onnol". Not a palindrome.
    // The problem states that if k=1 is possible, it's always by cutting in the middle.
    // This is not strictly true. For "kinnikkinnik", cut "kinnik|kinnik". s2s1 = "kinnikkinnik" (same).
    // Cut "kinnikkinnik" into "kinnikkin|nik". s2s1 = "nikkinnikkin". This is a palindrome and != s.
    // So k=1 is possible for "kinnikkinnik".

    // The condition for k=1 to be possible is that there exists *some* cut point `i`
    // such that `s[i...N-1] + s[0...i-1]` is a palindrome and not equal to `s`.
    // Since `s` is already a palindrome, `s[i...N-1] + s[0...i-1]` will be `s`
    // if and only if `s[i...N-1]` is a suffix of `s` and `s[0...i-1]` is a prefix of `s`
    // such that `s[i...N-1] + s[0...i-1]` is `s`. This is only true if `s[i...N-1]` is empty or `s[0...i-1]` is empty,
    // which means `i=0` or `i=N`. But `i` must be `1 <= i < N`.
    // So `s_2 s_1` is always different from `s` if `s_1` and `s_2` are non-empty.
    // We just need to check if `s_2 s_1` is a palindrome for any cut.

    // Iterate through all possible cut points for k=1
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (is_palindrome(s_prime)) {
            // Since s1 and s2 are non-empty, s_prime will always be different from s.
            // Example: s="abccba", s1="abc", s2="cba". s_prime="cbabcc". Not a palindrome.
            // Example: s="otto", s1="ot", s2="to". s_prime="toot". Palindrome.
            std::cout << 1 << "\n";
            return 0;
        }
    }

    // If k=1 is not possible, check for k=2.
    // With k=2, we make two cuts, resulting in three pieces: s1, s2, s3.
    // s = s1 s2 s3.
    // We can rearrange them. For example, s3 s2 s1, s1 s3 s2, etc.
    // The problem statement implies that if k=2 is possible, it's always possible
    // by cutting `s` into `s[0...i-1]`, `s[i...N-1-i]`, `s[N-i...N-1]`
    // and rearranging to `s[N-i...N-1] + s[i...N-1-i] + s[0...i-1]`.
    // This is essentially taking a prefix `s[0...i-1]` and its symmetric suffix `s[N-i...N-1]`
    // and swapping them around the middle part `s[i...N-1-i]`.
    // Since `s` is a palindrome, `s[0...i-1]` is the reverse of `s[N-i...N-1]`.
    // Let `P = s[0...i-1]`, `M = s[i...N-1-i]`, `S = s[N-i...N-1]`.
    // We know `P = reverse(S)`.
    // The original string is `P M S`.
    // A possible rearrangement is `S M P`.
    // Since `P = reverse(S)`, then `S = reverse(P)`.
    // So `S M P` is `reverse(P) M P`.
    // For `reverse(P) M P` to be a palindrome, it must be equal to `reverse(P M P)`.
    // `reverse(P M P) = reverse(P) reverse(M) reverse(reverse(P)) = reverse(P) reverse(M) P`.
    // So we need `reverse(P) M P == reverse(P) reverse(M) P`.
    // This implies `M == reverse(M)`, i.e., `M` must be a palindrome.
    //
    // This means if we can find a cut point `i` such that `s[i...N-1-i]` (the middle part) is a palindrome,
    // and `i > 0` (so `P` and `S` are non-empty), then we can form `S M P`.
    // This new string `S M P` will be a palindrome.
    // We also need `S M P != P M S`.
    // `S M P == P M S` implies `S == P`.
    // Since `S = reverse(P)`, this means `P = reverse(P)`, i.e., `P` must be a palindrome.
    // So, if we can find an `i` such that `s[i...N-1-i]` is a palindrome AND `s[0...i-1]` is NOT a palindrome,
    // then `S M P` will be a palindrome and `S M P != P M S`.
    //
    // The smallest `i` for which `s[i...N-1-i]` is a palindrome is `i=1`.
    // This means `s[1...N-2]` must be a palindrome.
    // If `s[1...N-2]` is a palindrome, and `s[0]` is not equal to `s[N-1]` (which is impossible since `s` is a palindrome),
    // or `s[0]` is not a palindrome (which is always true for a single character string unless N=1).
    // The condition `s[0...i-1]` is NOT a palindrome is equivalent to `s[0...i-1] != reverse(s[0...i-1])`.
    // But `s[0...i-1]` is `P`, and `reverse(s[0...i-1])` is `S`.
    // So `P != S` is the condition.
    // If `P == S`, then `P` must be a palindrome.
    // So we need `P` to not be a palindrome.

    // Let's check if `s` can be cut into `P M S` where `M` is a palindrome and `P != S`.
    // `P` is `s.substr(0, i)`. `S` is `s.substr(N-i)`.
    // Since `s` is a palindrome, `P` is `reverse(S)`.
    // So `P != S` means `P != reverse(P)`, i.e., `P` is not a palindrome.
    //
    // We need to find an `i` such that `1 <= i <= N/2`.
    // The middle part `s.substr(i, N - 2*i)` must be a palindrome.
    // And the prefix `s.substr(0, i)` must NOT be a palindrome.
    // If such an `i` exists, then `k=2` is the answer.

    // Example: "nolon"
    // N=5.
    // i=1: P="n", M="olo", S="n".
    // M="olo" is a palindrome.
    // P="n" is a palindrome.
    // Here P=S. So S M P = n olo n = nolon. This is the same as s.
    // So this specific rearrangement doesn't work for i=1.
    //
    // The example "nolon" -> 2 cuts. "no|l|on" -> "on|l|no".
    // Here s1="no", s2="l", s3="on".
    // s1 is not a palindrome. s2 is a palindrome. s3 is not a palindrome.
    // s1 = reverse(s3).
    // The rearrangement is s3 s2 s1.
    // s3 s2 s1 = "on" + "l" + "no" = "onlno". This is a palindrome.
    // And "onlno" != "nolon".
    // This matches the condition: `s` is `P M reverse(P)`.
    // We rearrange to `reverse(P) M P`.
    // This is a palindrome if `M` is a palindrome.
    // This is different from `s` if `P` is not a palindrome.
    //
    // For "nolon":
    // P = "no" (length 2). M = "l" (length 1). reverse(P) = "on".
    // `s` is `P M reverse(P)` = "no" + "l" + "on" = "nolon".
    // `M` ("l") is a palindrome.
    // `P` ("no") is NOT a palindrome.
    // So `reverse(P) M P` = "on" + "l" + "no" = "onlno" is a palindrome and `!= s`.
    // This requires `k=2` cuts. The cuts are after `P` and after `M`.
    // The length of `P` is `i`. The length of `M` is `N - 2*i`.
    // So `i` must be `1 <= i < N/2`.
    //
    // We need to check if there exists an `i` such that `1 <= i < N/2`
    // and `s.substr(i, N - 2*i)` is a palindrome AND `s.substr(0, i)` is NOT a palindrome.
    // If such an `i` exists, then `k=2` is the answer.

    // Check for k=2
    // Iterate `i` from 1 up to `N/2 - 1`.
    // `P = s.substr(0, i)`
    // `M = s.substr(i, N - 2*i)`
    // `S = s.substr(N-i)`
    // We know `s` is `P M S`.
    // We want to form `S M P`.
    // `S M P` is a palindrome if `M` is a palindrome.
    // `S M P` is different from `P M S` if `P != S`.
    // Since `s` is a palindrome, `P` is `reverse(S)`.
    // So `P != S` is equivalent to `P != reverse(P)`, i.e., `P` is not a palindrome.
    //
    // So we need to find `i` such that `1 <= i < N/2`:
    // 1. `s.substr(i, N - 2*i)` is a palindrome (the middle part)
    // 2. `s.substr(0, i)` is NOT a palindrome (the prefix part)

    for (int i = 1; i <= n / 2; ++i) { // i is length of prefix P
        std::string P = s.substr(0, i);
        std::string M = s.substr(i, n - 2 * i);

        if (is_palindrome(M)) {
            if (!is_palindrome(P)) {
                std::cout << 2 << "\n";
                return 0;
            }
        }
    }

    // If neither k=1 nor k=2 works, it's impossible.
    std::cout << "Impossible\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];

        // If current head can cover p[p_idx]
        if (std::abs(current_h - p[p_idx]) <= T) {
            // This head can cover p[p_idx] and potentially more tracks to its right.
            // The rightmost track this head can cover is current_h + T.
            long long cover_limit = current_h + T;

            // Advance p_idx past all tracks covered by this head.
            while (p_idx < m && p[p_idx] <= cover_limit) {
                p_idx++;
            }
        }
    }
    return p_idx == m; // True if all tracks are covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2*10^10 is a safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[i] stores the minimum r (1-based) such that s[i-1..r-1] contains a pattern.
                                                // If no such r exists, it's n+1.

    // Iterate through all possible starting positions x (0-based) for the pattern s[x] = s[x+k] = s[x+2k]
    // and all possible k.
    // The maximum possible k is such that x + 2k < n.
    // So, 2k < n - x, or k < (n - x) / 2.
    // The minimum k is 1.
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern s[x], s[x+k], s[x+2k].
                // The segment covered by this pattern is [x, x+2k].
                // Any substring s[l..r] (0-based) that contains this segment, i.e., l <= x and x+2k <= r,
                // will satisfy the condition.
                // We are interested in the smallest possible r for a given l.
                // For any l' such that l' <= x, the minimum r' required is x+2k.
                // So, for each l from 0 to x, we can update min_r_for_l[l+1] (1-based index for l)
                // with std::min(current_value, x+2k+1) (1-based index for r).

                // The problem statement uses 1-based indexing for l, r, x, k.
                // If s_x = s_{x+k} = s_{x+2k} (1-based x, k), then the segment is [x, x+2k].
                // For any l' <= x, the minimum r' is x+2k.
                // So, for l_idx from 1 to x, min_r_for_l[l_idx] = min(min_r_for_l[l_idx], x+2k).
                // In 0-based: for x_0 = x-1, k_0 = k. Pattern at s[x_0], s[x_0+k_0], s[x_0+2k_0].
                // Segment is [x_0, x_0+2k_0].
                // For l_0 from 0 to x_0, min_r_for_l[l_0+1] = min(min_r_for_l[l_0+1], x_0+2k_0+1).

                // The smallest possible k is 1.
                // The largest possible k is such that x + 2k < n.
                // If k is large, say k=7, then x+2k = x+14.
                // If k is small, say k=1, then x+2k = x+2.
                // The problem states $1 \leq x, k \leq n$. This is a bit confusing with 0-based indexing.
                // Let's stick to 0-based for s, and 1-based for l, r, x, k as in problem.
                // $s_x = s_{x+k} = s_{x+2k}$ means $s[x-1] = s[x+k-1] = s[x+2k-1]$.
                // The segment is $[x-1, x+2k-1]$ (0-based).
                // For any $l_{0based}$ from $0$ to $x-1$, the minimum $r_{0based}$ is $x+2k-1$.
                // So, for $l_{1based}$ from $1$ to $x$, $min\_r\_for\_l[l_{1based}]$ should be updated with $x+2k$.

                // The problem statement implies $x$ is 1-indexed.
                // Let's use $x_{0idx}$ for 0-indexed $x$. So $x_{0idx} = x_{1idx}-1$.
                // The pattern is $s[x_{0idx}], s[x_{0idx}+k], s[x_{0idx}+2k]$.
                // The rightmost index of this pattern is $x_{0idx}+2k$.
                // The minimum $r_{1idx}$ that contains this pattern is $x_{0idx}+2k+1$.
                // This pattern starts at $x_{0idx}$.
                // So for any $l_{1idx}$ from $1$ to $x_{0idx}+1$, the minimum $r_{1idx}$ is $x_{0idx}+2k+1$.

                // The problem statement says $l \leq x < x+2k \leq r$.
                // This means $l_{1idx} \leq x_{1idx}$ and $x_{1idx}+2k \leq r_{1idx}$.
                // The minimum $r_{1idx}$ for a given $l_{1idx}$ is $x_{1idx}+2k$.
                // So for $l_{1idx}$ from $1$ to $x_{1idx}$, we update $min\_r\_for\_l[l_{1idx}]$ with $x_{1idx}+2k$.

                // Let's use 0-based indexing for $x$ and $k$ in the loop, and convert to 1-based for $l, r$ and $min\_r\_for\_l$.
                // $x_{0idx}$ is current $x$ in loop. $k_{0idx}$ is current $k$ in loop.
                // Pattern is $s[x_{0idx}], s[x_{0idx}+k_{0idx}], s[x_{0idx}+2k_{0idx}]$.
                // The 1-based $x$ from problem statement is $x_{0idx}+1$.
                // The 1-based $k$ from problem statement is $k_{0idx}$.
                // The minimum $r_{1idx}$ for this pattern is $(x_{0idx}+1) + 2k_{0idx}$.
                // This applies for any $l_{1idx}$ from $1$ to $x_{0idx}+1$.

