#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // Apply constraints from s_i = '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Verify if the constructed w can produce s
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        // Check w_{i-x}
        if (i - x >= 0 && w[i - x] == '1') {
            s_prime[i] = '1';
        }
        // Check w_{i+x}
        if (i + x < n && w[i + x] == '1') {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

