#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long count = 0;

        // Use as many 5s as possible
        count += diff / 5;
        diff %= 5;

        // Handle remaining diff (0, 1, 2, 3, 4)
        if (diff == 1 || diff == 2) {
            count += 1;
        } else if (diff == 3 || diff == 4) {
            count += 2;
        }
        // If diff is 0, no additional presses needed.

        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile a[i], we can add min_val to it
            // (k - a[i]) / min_val times.
            // This is integer division, which correctly gives the floor.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

