    while (t--) {
        int n;
        std::cin >> n;
        std::vector<std::pair<int, int>> a_indexed(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a_indexed[i].first;
            a_indexed[i].second = i; // Store original index
        }
        std::vector<std::pair<int, int>> b_indexed(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> b_indexed[i].first;
            b_indexed[i].second = i; // Store original index
        }

        // Sort both arrays by brightness value
        std::sort(a_indexed.begin(), a_indexed.end());
        std::sort(b_indexed.begin(), b_indexed.end());

        // Create result arrays, initialized to hold the final assignment
        // x_result[original_index_of_daughter_i] = necklace_brightness
        // y_result[original_index_of_daughter_i] = bracelet_brightness
        std::vector<int> x_result(n);
        std::vector<int> y_result(n);

        // The strategy is to pair the i-th smallest necklace with the i-th largest bracelet.
        // This ensures distinct sums.
        // Specifically, if a_i is sorted ascending and b_i is sorted descending,
        // then a_i + b_i will be distinct.
        // Here, a_indexed is sorted ascending. We will use b_indexed in reverse order.
        for (int i = 0; i < n; ++i) {
            // The i-th daughter (in terms of sorted necklace brightness)
            // receives the i-th smallest necklace (a_indexed[i].first)
            // and the i-th largest bracelet (b_indexed[n - 1 - i].first).
            // The problem asks for output based on the original order of daughters.
            // The simplest interpretation is that the first daughter gets x_1, y_1,
            // the second daughter gets x_2, y_2, etc.
            // The problem statement says "if the i-th daughter receives a necklace with brightness x_i".
            // This implies we can assign any necklace/bracelet to any daughter,
            // as long as the set of x_i is a permutation of a_i and y_i is a permutation of b_i.
            // The simplest way to satisfy this is to just output the sorted a's and sorted b's (one reversed).
            // Let's assign a_indexed[i].first to x_i and b_indexed[n-1-i].first to y_i.
            // This means the i-th daughter (in the output sequence) gets these items.
            x_result[i] = a_indexed[i].first;
            y_result[i] = b_indexed[n - 1 - i].first;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x_result[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y_result[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

