#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by 'val' to the current_sum.
        // If we have 'count' copies of 'val', they contribute 'val * count' to the sum.
        // This sum can then be potentially combined into higher powers of two.
        // For example, if we have two 512s, they form one 1024.
        // If we have one 512 and one 1024, they don't combine directly.
        // The problem states "choose two equal integers".
        // So, we can only combine 512+512 to get 1024.
        // Then 1024+1024 to get 2048.
        // This means we are effectively summing up all numbers less than or equal to 2048.
        // If the sum is >= 2048, we can always form 2048.
        // Example: {1024, 512, 512, 4}
        // Sum = 1024 + 512 + 512 + 4 = 2092.
        // We can do 512+512 -> 1024. Multiset becomes {1024, 1024, 4}.
        // Then 1024+1024 -> 2048. Multiset becomes {2048, 4}. Win.
        // This logic holds because all numbers are powers of two.
        // Any sum of powers of two can be represented as a sum of unique powers of two (binary representation).
        // If the total sum of numbers <= 2048 is X, and X >= 2048, then we can always form 2048.
        // This is because we can always combine smaller powers of two to form larger ones until we reach 2048 or exceed it.
        // For example, if we have 1, 1, 1, 1, 1, 1, 1, 1 (sum=8), we can form 8.
        // 1+1=2, 1+1=2, 1+1=2, 1+1=2. Then 2+2=4, 2+2=4. Then 4+4=8.
        // The total sum of all numbers less than or equal to 2048 is what matters.
        // If this sum is 2048 or more, we can always form 2048.
        // If it's less than 2048, we can't.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

