void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    int has_pos_one = 0; // Flag to check if there's a '1' in a[0...i-1]
    int has_neg_one = 0; // Flag to check if there's a '-1' in a[0...i-1]

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    for (int i = 0; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (has_pos_one == 0) { // No '1' available before index i
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (has_neg_one == 0) { // No '-1' available before index i
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position,
        // but we still need to update has_pos_one/has_neg_one for future positions.

        if (a[i] == 1) {
            has_pos_one = 1;
        } else if (a[i] == -1) {
            has_neg_one = 1;
        }
    }

    std::cout << "YES\n";
}

