int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // Skip a_i,i which is 0
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If all are n-1, it means the actual n was not found.
    // This happens if the true p_k = n, then max_j(min(p_k, p_j)) = max_j(p_j) = n-1.
    // In this case, one of the p_i should be n.
    // The problem states that p is a permutation of 1 to n.
    // If all p[i] are n-1, it means the value 'n' is missing from our reconstructed p.
    // This implies that the actual value 'n' was assigned to some p_k,
    // and for that k, max_{j!=k} min(p_k, p_j) = max_{j!=k} p_j = n-1.
    // So, if all p[i] are n-1, we need to change one of them to n.
    // Since any such permutation is valid, we can just pick the first one.
    bool all_n_minus_1 = true;
    for (int i = 0; i < n; ++i) {
        if (p[i] != n - 1) {
            all_n_minus_1 = false;
            break;
        }
    }

    if (all_n_minus_1) {
        // If all elements are n-1, it means the actual 'n' was not captured.
        // This happens when p_k = n, then max_{j!=k} min(p_k, p_j) = max_{j!=k} p_j = n-1.
        // So, one of the elements should be 'n'. We can pick any one.
        p[0] = n; 
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
