void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the last element's price
    // because we are looking for prices *later* than current day.
    // The last element a[n-1] can never be a bad price by definition.
    int min_suffix = a[n - 1]; 

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is
            // either smaller than or equal to min_suffix.
            // In this case, a[i] becomes the new minimum for elements
            // to its left.
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

