        // The length of the string is n. Cells are 0 to n. Target is n+1.
        // The last possible jump is from last_R_pos to n+1.
        // If last_R_pos is -1, it means no 'R's were found, so the jump is from 0 to n+1.
        // The distance from last_R_pos to n+1 is (n+1) - last_R_pos.
        max_gap = std::max(max_gap, (int)s.length() + 1 - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

