int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is A_total = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of A_piece = A_total / n = (h/2) / n = h / (2n).

    // Consider a cut made at a distance x from the apex.
    // This cut forms a smaller triangle at the top.
    // By similar triangles, if the original triangle has height H and base B,
    // a smaller triangle with height x will have base b_x = B * (x/H).
    // In our case, H=h, B=1, so b_x = 1 * (x/h) = x/h.
    // The area of this smaller triangle is A_x = (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want to make n-1 cuts. Let x_k be the distance from the apex to the k-th cut.
    // The region from the apex to the k-th cut (at x_k) must contain k pieces.
    // So, the area of the triangle formed by the k-th cut must be k * A_piece.
    // A_{x_k} = k * (h / (2n))
    // x_k^2 / (2h) = k * h / (2n)
    // x_k^2 = k * h^2 / n
    // x_k = sqrt(k * h^2 / n)
    // x_k = h * sqrt(k / n)

    // We need to find x_1, x_2, ..., x_{n-1}.
    std::cout << std::fixed << std::setprecision(12);
    for (int k = 1; k < n; ++k) {
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
