void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This means a[i] <= a[i+1] <= ... <= a[n-1].
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This means a[j] >= a[j+1] >= ... >= a[i-1].
    // We start from i-1 because we want to find the "peak" before the non-decreasing suffix.
    // If i is 0, this loop won't run, j will remain 0.
    int j = i; // j is the start of the non-increasing part
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // The prefix to remove is a[0...j-1].
    // The length of this prefix is j.

    std::cout << j << std::endl;
}

