int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k = n / m; // Number of multiples of m up to n

        // The last digits of (i * m) % 10 repeat in a cycle.
        // The cycle length is at most 10, because (i * m) % 10 depends only on (i % 10) and (m % 10).
        // More precisely, (i * m) % 10 is periodic with period 10.
        // For example, (1*m)%10, (2*m)%10, ..., (10*m)%10, (11*m)%10 = (1*m)%10.
        // So we can precompute the sum of last digits for one full cycle of 10 multiples.

        long long sum_of_first_ten_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_ten_last_digits += (static_cast<long long>(i) * m) % 10;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * sum_of_first_ten_last_digits;

        // Calculate the sum for the remaining multiples
        long long remaining_multiples = k % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (static_cast<long long>(i) * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are already initialized to pos[1].
        // The length is 1, min value is 1, max value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the current segment [min_idx, max_idx]
        // to include 'm'.
        // The current segment [min_idx, max_idx] already contains 1, 2, ..., m-1.
        // To make it a permutation of 1, ..., m, we must include 'm'.
        // 'm' must be at pos[m].
        // We update min_idx and max_idx to cover the range from 1 to m.
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // A segment p[min_idx ... max_idx] is a permutation of 1, ..., m
        // if and only if:
        // 1. Its length is m. (max_idx - min_idx + 1 == m)
        // 2. It contains all numbers from 1 to m. (This is guaranteed by how min_idx/max_idx are updated)
        // 3. It contains no numbers greater than m. (This is guaranteed by the length check)

        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

