#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        // The quadratic equation for 'a' is a^2 - d*a + d = 0
        // Using the quadratic formula: a = (d +/- sqrt(d^2 - 4d)) / 2
        // For real solutions, the discriminant (d^2 - 4d) must be non-negative.
        // d^2 - 4d >= 0
        // d * (d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // Or d = 0.
        // If d = 0, then 0 * (-4) = 0, which is >= 0.
        // So, solutions exist if d = 0 or d >= 4.

        if (d == 0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4) { // d is positive, but d < 4, so d^2 - 4d < 0
            std::cout << "N\n";
        } else { // d >= 4
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // We need a and b to be non-negative.
            // a = (d + sqrt_discriminant) / 2
            // b = (d - sqrt_discriminant) / 2
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant is real and non-negative.
            // d + sqrt_discriminant is clearly non-negative.
            // For b to be non-negative, we need d - sqrt_discriminant >= 0.
            // d >= sqrt_discriminant
            // d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both a and b will be non-negative.

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    long long total_toys = A + B + C + D;

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Case 1: Final toy in Box 1 (negative, magnitude >= 1)
    // This requires an odd number of negative factors.
    // And at least one factor with magnitude >= 1, or a chain of factors that eventually produce magnitude >= 1.
    // The only way to guarantee magnitude >= 1 is if there's at least one toy from Box 1 or Box 4.
    // If all initial toys are from Box 2 and Box 3, the magnitude will always be < 1.
    // So, A+D must be > 0 for Box 1 or Box 4 to be possible.
    // If A+D == 0, then all toys are from Box 2 and Box 3, so magnitude will always be < 1.
    // In this case, Box 1 and Box 4 are impossible.
    if (A + D > 0) { // At least one toy with magnitude >= 1
        // To get negative: B must be odd, or A must be odd.
        // Total negative toys: A + B.
        // If (A + B) is odd, the final sign can be negative.
        // If (A + B) is even, the final sign can be positive.
        // We need to check if we can achieve magnitude >= 1 AND negative sign.
        // This means we need an odd number of negative toys.
        if ((A + B) % 2 == 1) {
            ans1 = "Ya";
        }
    }

    // Case 2: Final toy in Box 2 (negative, magnitude < 1)
    // This requires an odd number of negative factors.
    // And all factors with magnitude < 1, or a chain of factors that eventually produce magnitude < 1.
    // This is always possible if A+D > 0, by multiplying a large magnitude toy with many small magnitude toys.
    // Or if A+D == 0, then all toys are from Box 2 and Box 3, so magnitude will always be < 1.
    // If (A+B) is odd, we can get a negative sign.
    if ((A + B) % 2 == 1) {
        ans2 = "Ya";
    }

    // Case 3: Final toy in Box 3 (positive, magnitude < 1)
    // This requires an even number of negative factors.
    // And all factors with magnitude < 1, or a chain of factors that eventually produce magnitude < 1.
    // If (A+B) is even, we can get a positive sign.
    if ((A + B) % 2 == 0) {
        ans3 = "Ya";
    }

    // Case 4: Final toy in Box 4 (positive, magnitude >= 1)
    // This requires an even number of negative factors.
    // And at least one factor with magnitude >= 1, or a chain of factors that eventually produce magnitude >= 1.
    // Similar to Box 1, A+D must be > 0.
    if (A + D > 0) { // At least one toy with magnitude >= 1
        // If (A + B) is even, the final sign can be positive.
        if ((A + B) % 2 == 0) {
            ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

