}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Ensure elements to the left of median are <= s
    // If a[i] > s, we must decrease it to s.
    // Since a is sorted, if a[i] > s, then a[i+1], a[i+2], ... will also be > s.
    // We only need to consider elements from a[0] to a[median_idx-1].
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Ensure elements to the right of median are >= s
    // If a[i] < s, we must increase it to s.
    // Since a is sorted, if a[i] < s, then a[i-1], a[i-2], ... will also be < s.
    // We only need to consider elements from a[median_idx+1] to a[n-1].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
