#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Store original index if needed, though not for this problem
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    // Create the result array A'
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th element in the sorted B (descending) should be paired with
        // the i-th element in the sorted A (ascending).
        // The original index of this B element is b_elements[i].original_index.
        // This means A'[b_elements[i].original_index] should be a_elements[i].value.
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (the 'b' values)
    int right_ptr = 0; // Pointer for original positions (the 'a' values)

    // We iterate through the sorted original array (a[right_ptr])
    // and try to find a larger element from the sorted available elements (a[left_ptr])
    // to place at that position.
    // Since both arrays are sorted, if a[left_ptr] > a[right_ptr],
    // then a[left_ptr] is the smallest available element that is greater than a[right_ptr].
    // We use it and move both pointers.
    // If a[left_ptr] <= a[right_ptr], we cannot use a[left_ptr] for a[right_ptr],
    // so we try a larger available element by incrementing left_ptr.
    while (left_ptr < n && right_ptr < n) {
        if (a[left_ptr] > a[right_ptr]) {
            // Found an element a[left_ptr] that is greater than a[right_ptr].
            // This means we can make a[right_ptr] position "successful".
            count++;
            left_ptr++;  // Move to the next available element to place
            right_ptr++; // Move to the next original position
        } else {
            // a[left_ptr] is not greater than a[right_ptr].
            // We need a larger element to place at a[right_ptr]'s position.
            // So, we try the next available element to place.
            left_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
