#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a sub-array is a permutation of 1 to len
// This version is optimized for checking prefixes and suffixes efficiently.
// It takes precomputed max_val and distinct_count arrays.
bool check_permutation(int len, int max_val, int distinct_count) {
    return len > 0 && max_val == len && distinct_count == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix properties
    std::vector<int> prefix_max(n + 1, 0);
    std::vector<int> prefix_distinct_count(n + 1, 0);
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false); // Using n+1 for 1-based indexing up to n

    int current_max = 0;
    int current_distinct_count = 0;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val > n || seen_prefix[val]) { // Value out of range or duplicate
            // Cannot form a permutation from this point onwards
            // Mark subsequent prefix_is_perm as false
            // (already initialized to false, so no explicit action needed)
            break; 
        }
        seen_prefix[val] = true;
        current_max = std::max(current_max, val);
        current_distinct_count++;

        prefix_max[i + 1] = current_max;
        prefix_distinct_count[i + 1] = current_distinct_count;
        prefix_is_perm[i + 1] = check_permutation(i + 1, current_max, current_distinct_count);
    }

    // Precompute suffix properties
    std::vector<int> suffix_max(n + 1, 0);
    std::vector<int> suffix_distinct_count(n + 1, 0);
    std::vector<bool> suffix_is_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false); // Using n+1 for 1-based indexing up to n

    current_max = 0;
    current_distinct_count = 0;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        if (val > n || seen_suffix[val]) { // Value out of range or duplicate
            // Cannot form a permutation from this point backwards
            break;
        }
        seen_suffix[val] = true;
        current_max = std::max(current_max, val);
        current_distinct_count++;

        int suffix_len = n - i;
        suffix_max[suffix_len] = current_max;
        suffix_distinct_count[suffix_len] = current_distinct_count;
        suffix_is_perm[suffix_len] = check_permutation(suffix_len, current_max, current_distinct_count);
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can be from 1 to n-1
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

