int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_coins = 0;
        long long opponent_coins = 0;

        bool chanek_turn = true;

        while (N > 0) {
            if (chanek_turn) {
                if (N % 2 != 0) { // N is odd
                    chanek_coins += 1;
                    N -= 1;
                } else { // N is even
                    if (N == 2) { // Special case for N=2, taking 1 is optimal
                        chanek_coins += 1;
                        N -= 1;
                    } else if ((N / 2) % 2 != 0 && N / 2 != 1) { // N/2 is odd and N/2 > 1
                        // If N/2 is odd, taking N/2 leaves an odd number for opponent.
                        // Opponent will take 1, leaving an even number for Chanek.
                        // This seems good for Chanek.
                        // But if Chanek takes 1, N-1 is odd. Opponent takes 1, N-2 is even.
                        // This is the tricky part.
                        // If N/2 is odd, taking N/2 means opponent gets an odd number of coins.
                        // If N/2 is odd, and N/2 > 1, then N is 2 * (odd number > 1).
                        // Example: N=6. N/2=3 (odd).
                        // Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                        // Chanek: 3+1=4. Opponent: 1+1=2.
                        // Example: N=10. N/2=5 (odd).
                        // Chanek takes 5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                        // Chanek: 5+2+1=8. Opponent: 1+1=2.
                        // It seems taking N/2 is always better if N/2 is odd and N/2 > 1.
                        chanek_coins += N / 2;
                        N /= 2;
                    } else { // N/2 is even or N/2 == 1
                        // If N/2 is even, taking N/2 leaves an even number for opponent.
                        // Opponent can take N/4. This is bad.
                        // So, if N/2 is even, Chanek should take 1.
                        // Example: N=4. N/2=2 (even).
                        // Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                        // Chanek: 1+1=2. Opponent: 1+1=2.
                        // If Chanek took N/2=2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                        // Chanek: 2+1=3. Opponent: 1.
                        // This contradicts the example for N=4.
                        // The example for N=4 is not given, but for N=6, Chanek takes 3.
                        // Let's re-evaluate.
                        // The strategy is: if N is odd, take 1.
                        // If N is even:
                        //   If taking N/2 leaves an odd number for the opponent, it's good.
                        //   If taking N/2 leaves an even number for the opponent, it's bad.
                        //   In the "bad" case, taking 1 leaves an odd number for the opponent. This is good.
                        // So, if N is even:
                        //   If N/2 is odd (and N/2 > 1), take N/2.
                        //   If N/2 is even (or N/2 == 1), take 1.
                        // This covers all cases.
                        // N=2: N/2=1. N/2 is odd, but N/2 == 1. So take 1. Correct.
                        // N=4: N/2=2. N/2 is even. So take 1. Correct.
                        // N=6: N/2=3. N/2 is odd and N/2 > 1. So take N/2=3. Correct.
                        // N=8: N/2=4. N/2 is even. So take 1.
                        // N=10: N/2=5. N/2 is odd and N/2 > 1. So take N/2=5.
                        // This logic seems sound.
                        chanek_coins += 1;
                        N -= 1;
                    }
                }
            } else { // Opponent's turn
                if (N % 2 != 0) { // N is odd
                    opponent_coins += 1;
                    N -= 1;
                } else { // N is even
                    if (N == 2) {
                        opponent_coins += 1;
                        N -= 1;
                    } else if ((N / 2) % 2 != 0 && N / 2 != 1) {
                        opponent_coins += N / 2;
                        N /= 2;
                    } else {
                        opponent_coins += 1;
                        N -= 1;
                    }
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
