    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append elements b1, b2, ... such that
        // (current_sum + sum(b_i)) = 2 * (current_xor ^ xor(b_i))
        // Let's try to append two elements.
        // Let b1 = current_xor.
        // Then new_xor = current_xor ^ current_xor = 0.
        // The equation becomes (current_sum + current_xor + b2) = 2 * (0 ^ b2) = 2 * b2.
        // current_sum + current_xor = b2.
        // So, b2 = current_sum + current_xor.
        // The two elements to append are current_xor and (current_sum + current_xor).

        long long b1 = current_xor;
        long long b2 = current_sum + current_xor;

        std::cout << 2 << std::endl;
        std::cout << b1 << " " << b2 << std::endl;
    }
