int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_total_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // Let 'i' be the number of items taken from the left.
    // Then 'n - i' items are taken from the right side.
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right side

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for unbalanced counts
        if (i > j) {
            // More items taken from left.
            // The difference is i - j.
            // If i - j = 1, no penalty.
            // If i - j > 1, penalty for (i - j - 1) extra left actions.
            current_energy += (long long)(i - j - 1) * Ql;
        } else if (j > i) {
            // More items taken from right.
            // The difference is j - i.
            // If j - i = 1, no penalty.
            // If j - i > 1, penalty for (j - i - 1) extra right actions.
            current_energy += (long long)(j - i - 1) * Qr;
        }
        // If i == j, no penalty.

        if (min_total_energy == -1 || current_energy < min_total_energy) {
            min_total_energy = current_energy;
        }
    }

    std::cout << min_total_energy << std::endl;

    return 0;
}

