    // prefix_counts[i][0] stores count of 'x' in s[0...i-1]
    // prefix_counts[i][1] stores count of 'y' in s[0...i-1]
    // prefix_counts[i][2] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> prefix_counts(n + 1, std::vector<int>(3, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[i + 1][0] = prefix_counts[i][0];
        prefix_counts[i + 1][1] = prefix_counts[i][1];
        prefix_counts[i + 1][2] = prefix_counts[i][2];
        if (s[i] == 'x') {
            prefix_counts[i + 1][0]++;
        } else if (s[i] == 'y') {
            prefix_counts[i + 1][1]++;
        } else { // s[i] == 'z'
            prefix_counts[i + 1][2]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;
        // Adjust to 0-indexed
        --l; 
        // r is already exclusive for prefix_counts[r]

        if (r - l < 3) { // Substring length is less than 3
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[r][0] - prefix_counts[l][0];
        int count_y = prefix_counts[r][1] - prefix_counts[l][1];
        int count_z = prefix_counts[r][2] - prefix_counts[l][2];

        // The algorithm terminates if and only if it's possible to reach a state
        // where all 3-character substrings are permutations of 'x', 'y', 'z'.
        // This means all 3-character substrings must have one 'x', one 'y', one 'z'.
        // This is only possible if the counts of 'x', 'y', 'z' in the entire substring
        // are "balanced" enough. Specifically, the difference between any two counts
        // must not exceed 1.
        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_x - count_z) <= 1 &&
            std::abs(count_y - count_z) <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

