long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0) {
                current_p /= i;
            }
            // current_p is p with all factors of i removed.
            // If we multiply current_p by some power of i, say i^k,
            // such that i^k is the highest power of i that divides p,
            // then current_p * i^k is p.
            // We need to find the largest divisor of p that is not divisible by q.
            // If we remove one factor of i from p, we get p/i.
            // This p/i might not be divisible by q.
            // We want to maximize p/i^k such that p/i^k is not divisible by q.
            // The largest such value would be p / (i^k) where i^k is the highest power of i that divides p
            // AND p / (i^k) is not divisible by q.
            // A simpler approach: for each prime factor `i` of `q`,
            // divide `p` by `i` repeatedly until it's no longer divisible by `i`.
            // This gives `p_prime = p / i^k`.
            // Then `p_prime * i^(k-1)` is a candidate for `x`.
            // This candidate `p / i` (after removing all factors of i from q)
            // is `p` divided by the highest power of `i` that divides `q`.
            // Let `p_val = p`. While `p_val % i == 0`, `p_val /= i`.
            // This `p_val` is `p` with all factors of `i` removed.
            // The candidate `x` is `p_val * (i^(count_i_in_p - count_i_in_q + 1))`.
            // No, this is too complicated.
            // A simpler way:
            // For each prime factor `f` of `q`:
            //   Calculate `p_prime = p`.
            //   While `p_prime % f == 0` and `p_prime % q == 0`:
            //     `p_prime /= f`.
            //   `max_x = max(max_x, p_prime)`.
            // This ensures `p_prime` is a divisor of `p` and `p_prime % q != 0`.

            long long current_candidate = p;
            while (current_candidate % i == 0) {
                if ((current_candidate / i) % q != 0) { // If removing one more factor of i makes it not divisible by q
                    max_x = std::max(max_x, current_candidate / i);
                    break; // Found the largest candidate for this prime factor i
                }
                current_candidate /= i;
            }
            // After the loop, current_candidate is p with all factors of i removed.
            // If current_candidate is not divisible by q, it's a valid candidate.
            // But we want the largest. The loop above already finds the largest by removing minimal factors of i.

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    // If temp_q is still > 1, it means temp_q is a prime factor itself (or a product of large primes).
    // This handles the case where q is a prime number.
    if (temp_q > 1) {
        long long i = temp_q; // i is now a prime factor of original q
        long long current_candidate = p;
        while (current_candidate % i == 0) {
            if ((current_candidate / i) % q != 0) {
                max_x = std::max(max_x, current_candidate / i);
                break;
            }
            current_candidate /= i;
        }
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

