        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                colors[i] = '1';
                if (d[i] < last1) { // Check non-decreasing for color 1
                    possible_k = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > k) {
                colors[i] = '2';
                if (first2 != -1 && d[i] < first2) { // Check non-decreasing for color 2
                    possible_k = false;
                    break;
                }
                first2 = d[i];
            }
        }

        if (!possible_k) {
            continue;
        }

        // Now handle digits equal to k
        // Digits equal to k can be either 1 or 2.
        // If colored 1, they must be >= last1.
        // If colored 2, they must be >= first2 (if first2 exists).
        // Also, last1 (if exists) must be <= first2 (if exists).

        // Strategy: Color all 'k's that appear before the first '2' as '1'.
        // Color all 'k's that appear after the last '1' as '2'.
        // This is equivalent to finding the first 'k' that we *must* color '2'.
        // All 'k's before that are '1', all 'k's after that are '2'.

        int split_idx = -1; // Index of the first 'k' that must be colored '2'
        for (int i = 0; i < n; ++i) {
            if (d[i] == k) {
                if (last1 != -1 && k < last1) { // This 'k' cannot be colored '1'
                    split_idx = i;
                    break;
                }
                // This 'k' can be colored '1'. Update last1 if we do.
                // We don't actually color it yet, just check possibility.
            } else if (colors[i] == '2') {
                // If we encounter a '2' before finding a problematic 'k',
                // then all 'k's up to this point can be '1'.
                // The first 'k' that must be '2' would be the first 'k' after this '2'.
                // But we need to ensure that if we color a 'k' as '1', it's >= last1.
                // And if we color a 'k' as '2', it's >= first2.
                // The critical point is where the 'k's transition from '1' to '2'.
                // This transition must happen at some point.
                // The simplest is to find the first 'k' that is greater than or equal to the first '2' encountered so far.
                // Or, more generally, the first 'k' that is greater than or equal to the first '2' in the final sequence.
                // This is equivalent to finding the first 'k' that we *must* color '2'.
                // This happens if coloring it '1' would violate the non-decreasing property of S1.
                // Or if coloring it '2' would violate the non-decreasing property of S2.

                // Let's try a simpler approach for 'k's:
                // Find the first 'k' that is followed by a digit 'd_j' (j > i) such that d_j < k.
                // If such a 'k' is colored '1', then d_j must be colored '1' too, but d_j < k, so d_j < this 'k'.
                // This would violate S1 non-decreasing. So this 'k' must be '2'.
                // This is not quite right.
                // The condition is: if d[i] == k, and we color it '1', then it must be >= last1.
                // If we color it '2', then it must be >= first2 (if first2 exists).
                // And the last '1' must be <= the first '2'.

                // Let's try to find the "split point" for digits equal to k.
                // All d[i] < k are '1'. All d[i] > k are '2'.
                // For d[i] == k:
                // We want to color as many as possible '1's first, then '2's.
                // So, we iterate through d[i] == k.
                // If d[i] == k, we try to color it '1'.
                // This is valid if k >= last1.
                // If it's valid, we color it '1' and update last1 = k.
                // If it's not valid (k < last1), then this d[i] must be '2'.
                // Once we color a 'k' as '2', all subsequent 'k's must also be '2'.
                // And they must satisfy k >= first2 (if first2 exists).

                // Let's refine:
                // Iterate through the digits.
                // If d[i] < k: color '1'. Check d[i] >= last1. Update last1.
                // If d[i] > k: color '2'. Check d[i] >= first2. Update first2.
                // If d[i] == k:
                //   If we have already decided to color 'k's as '2' (i.e., split_idx != -1 and i >= split_idx),
                //     then color '2'. Check k >= first2. Update first2.
                //   Else (we are still trying to color 'k's as '1'):
                //     If k >= last1: color '1'. Update last1 = k.
                //     Else (k < last1): This 'k' cannot be '1'. It must be '2'.
                //       Set split_idx = i. Color '2'. Check k >= first2. Update first2.
            }
        }

        // Reset for the actual coloring with split_idx logic
        last1 = -1;
        first2 = -1;
        split_idx = -1; // This will mark the first 'k' that gets color '2'

        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                colors[i] = '1';
                if (d[i] < last1) { possible_k = false; break; }
                last1 = d[i];
            } else if (d[i] > k) {
                colors[i] = '2';
                if (first2 != -1 && d[i] < first2) { possible_k = false; break; }
                first2 = d[i];
            } else { // d[i] == k
                // If we haven't found a split_idx yet, try to color '1'
                if (split_idx == -1) {
                    if (k >= last1) { // Can color '1'
                        colors[i] = '1';
                        last1 = k;
                    } else { // Cannot color '1', must color '2'
                        split_idx = i; // This is the first 'k' that must be '2'
                        colors[i] = '2';
                        if (first2 != -1 && k < first2) { possible_k = false; break; }
                        first2 = k;
                    }
                } else { // We are past split_idx, all subsequent 'k's must be '2'
                    colors[i] = '2';
                    if (first2 != -1 && k < first2) { possible_k = false; break; }
                    first2 = k;
                }
            }
        }

        if (!possible_k) {
            continue;
        }

        // Final check: last digit of S1 <= first digit of S2
        // If last1 is -1 (no '1's) or first2 is -1 (no '2's), this is fine.
        if (last1 != -1 && first2 != -1 && last1 > first2) {
            possible_k = false;
        }

        if (possible_k) {
            std::cout << colors << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

