#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <numeric>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i-1]].insert(s[i]);
            adj[s[i]].insert(s[i-1]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_prefix = "";
    std::set<char> visited_in_layout;

    // Find a starting character for a chain
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() <= 1) { // A character with 0 or 1 neighbor can be an endpoint
            start_char = c;
            break;
        }
    }

    // If all characters in s have 2 neighbors, it means they form a cycle.
    // This is problematic for a linear layout unless it's a single chain.
    // If start_char is still '\0', it means all characters in `used_in_s` have 2 neighbors.
    // This implies a cycle or multiple disjoint cycles.
    // A single cycle is fine if it's the only component and we can break it.
    // But the problem is that we need to pick one character to start, and if all have 2 neighbors,
    // we can pick any, but we need to ensure it's a single chain.
    // Let's refine: if all characters in `used_in_s` have 2 neighbors, it means they form a cycle.
    // A cycle cannot be represented on a linear keyboard without breaking an adjacency.
    // Example: a-b-c-a. If we lay it out as a-b-c, then a and c are not adjacent.
    // So, if all characters in `used_in_s` have 2 neighbors, it's impossible.
    // Exception: if `used_in_s` has only one character, it has 0 neighbors.
    // If `used_in_s` has two characters, say 'a' and 'b', then 'a' has 'b' as neighbor, 'b' has 'a' as neighbor. Both have 1 neighbor.
    // So, if `start_char` is still `\0` and `used_in_s` is not empty, it means all characters in `used_in_s` have exactly 2 neighbors.
    // This forms a cycle, which is impossible.
    if (start_char == '\0' && !used_in_s.empty()) {
        std::cout << "NO\n";
        return;
    }

    // If used_in_s is empty (s was empty, but problem constraints say |s| >= 1),
    // or if s has only one character, start_char will be that character.
    // If s has only one character, say 'a', then adj['a'] is empty, so size is 0.
    // start_char will be 'a'.

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the previous character in the layout
        while (current != '\0') {
            layout_prefix += current;
            visited_in_layout.insert(current);
            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters from `s` were included in the constructed chain
    if (visited_in_layout.size() != used_in_s.size()) {
        // This means there are multiple disjoint components or cycles.
        // If there are multiple components, we can't connect them all into one linear layout
        // while preserving all adjacencies.
        // Example: "ab" and "cd". Layout "abcd" means b and c are adjacent, but they shouldn't be.
        // The only way to combine multiple components is if they are single characters not adjacent to anything.
        // But if they are part of a chain, they must be connected.
        // The current logic builds one chain. If `visited_in_layout` doesn't cover all `used_in_s`,
        // it means there's another chain or cycle that couldn't be reached.
        // This is impossible.
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout_prefix;

    // Append remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            std::cout << c;
        }
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

