int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r for r from 1 to b-1: (b-1) * b / 2
    long long sum_r = (b - 1) % MOD * (b % MOD) % MOD;
    sum_r = sum_r * ((MOD + 1) / 2) % MOD; // Multiply by modular inverse of 2

    // Sum of k for k from 1 to a: a * (a+1) / 2
    long long sum_k = a % MOD * ((a + 1) % MOD) % MOD;
    sum_k = sum_k * ((MOD + 1) / 2) % MOD; // Multiply by modular inverse of 2

    // The total sum is sum_{k=1 to a} sum_{r=1 to b-1} (k*b + 1) * r
    // This can be factored as:
    // (sum_{k=1 to a} (k*b + 1)) * (sum_{r=1 to b-1} r)
    //
    // sum_{k=1 to a} (k*b + 1) = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * (sum_{k=1 to a} k) + a
    // = b * sum_k + a

    long long term_k_b_plus_1 = (b % MOD * sum_k % MOD + a % MOD) % MOD;

    long long total_sum = term_k_b_plus_1 * sum_r % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_idx = i;
        int block_end_idx = std::min(i + k, n);

        // Fill this block in decreasing order
        // The values for this block are current_val, current_val-1, ..., current_val - (block_end_idx - block_start_idx) + 1
        for (int j = block_end_idx - 1; j >= block_start_idx; --j) {
            p[j] = current_val;
            current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c1 = s[k_actual]; // t[0] revealed by Kolya

        // For a fixed c1, find all possible k' such that s[k'] == c1.
        // These are the candidate k values Vasya considers.
        const std::vector<int>& candidate_k_indices = char_indices[c1 - 'a'];

        if (candidate_k_indices.empty()) { // Should not happen if k_actual is valid
            continue;
        }

        if (candidate_k_indices.size() == 1) {
            // If only one k' matches c1, Vasya already knows k_actual.
            // He wins regardless of the second character.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal p (1 to L-1) to maximize his win probability
        // given that t[0] is c1.
        // The win probability for a given c1 is the maximum over all p of
        // (number of k' that are uniquely determined by (c1, t[p])) / (number of candidate k' for c1)

        // For each possible p, calculate how many candidate k' values would be uniquely determined.
        int max_unique_count_for_c1 = 0;

        for (int p = 1; p < L; ++p) {
            std::map<char, int> char_counts_at_p; // Stores counts of t[p] for candidate k'
            for (int k_prime : candidate_k_indices) {
                char c2_val = s[(k_prime + p) % L];
                char_counts_at_p[c2_val]++;
            }

            int unique_count_for_this_p = 0;
            for (auto const& [c2_val, count] : char_counts_at_p) {
                if (count == 1) {
                    unique_count_for_this_p++;
                }
            }
            max_unique_count_for_c1 = std::max(max_unique_count_for_c1, unique_count_for_this_p);
        }

        total_win_prob += static_cast<double>(max_unique_count_for_c1) / candidate_k_indices.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

