        //
        // The total number of elements $\le m_1$ or $\ge m_2$ is at least $(S_1+1)/2 + (S_2+1)/2 = n+1$.
        // This means that the interval $(m_1, m_2)$ can contain at most $2n - (n+1) = n-1$ elements.
        //
        // If $m_1$ is $a_i$ and $m_2$ is $a_j$, then $j-i \ge 1$.
        // The elements $a_0, \dots, a_{n-1}$ are $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are $n$ elements.
        //
        // Any median $m_1$ must be one of $a_0, \dots, a_{2n-1}$.
        // Any median $m_2$ must be one of $a_0, \dots, a_{2n-1}$.
        //
        // The $n$-th element $a_{n-1}$ must belong to some class, say $C_A$.
        // The $(n+1)$-th element $a_n$ must belong to some class, say $C_B$.
        //
        // If $C_A = C_B$, then $a_{n-1}$ and $a_n$ are in the same class.
        // The median of that class must be $\ge a_{n-1}$ and $\le a_n$.
        // The other class must have its median.
        //
        // This is a known result: the minimum difference between medians of two partitions of odd size
        // is $a[n] - a[n-1]$ (0-indexed).
        //
        // So, the solution is to sort the array and output $a[n] - a[n-1]$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s in a[n-k...n-1]) - (count of 2s in a[n-k...n-1])
    // This is equivalent to (count of 1s in a[0...n-1] - count of 2s in a[0...n-1])
    // minus (count of 1s in a[0...n-k-1] - count of 2s in a[0...n-k-1])
    // Let's rephrase: diff_L[k] is the balance of the *remaining* jars on the left side
    // after eating k jars from the left (i.e., jars a[n-k]...a[n-1] are eaten).
    // The remaining jars are a[0]...a[n-k-1].
    // No, this is not what the problem implies.
    // "first non-empty jar to his left" means he eats a_n, then a_{n-1}, etc.
    // So if he eats k jars from the left, he eats a_n, a_{n-1}, ..., a_{n-k+1}.
    // The remaining jars on the left are a_1, ..., a_{n-k}.
    // Let's define balance as (count of 1s) - (count of 2s).
    // We need to find the balance of the remaining jars.
    // The total number of jars is 2n.
    // He eats `k_L` jars from the left and `k_R` jars from the right.
    // Jars eaten from left: a_n, a_{n-1}, ..., a_{n-k_L+1}.
    // Jars eaten from right: a_{n+1}, a_{n+2}, ..., a_{n+k_R}.
    // Remaining jars: a_1, ..., a_{n-k_L} and a_{n+k_R+1}, ..., a_{2n}.

    // Let's calculate the balance of the remaining jars.
    // `balance_left[k]` = balance of jars `a_1, ..., a_{n-k}`.
    // `balance_right[k]` = balance of jars `a_{n+k+1}, ..., a_{2n}`.

    // `balance_left[k_L]` stores the balance of jars `a_0, ..., a_{n-k_L-1}` (0-indexed)
    // `balance_right[k_R]` stores the balance of jars `a_{n+k_R}, ..., a_{2n-1}` (0-indexed)

    std::map<int, int> left_balances; // map balance_value -> k_L (number of jars eaten from left)
    left_balances[0] = 0; // If 0 jars are eaten from left, balance is 0.

    int current_balance = 0;
    for (int k_L = 1; k_L <= n; ++k_L) {
        // Jar a[n-k_L] is the last remaining jar on the left if k_L jars are eaten.
        // The jars eaten are a[n-1], a[n-2], ..., a[n-k_L].
        // The balance of the *eaten* jars on the left side.
        // This is the balance of a[n-k_L]...a[n-1] (0-indexed)
        current_balance += (a[n - k_L] == 1 ? 1 : -1);
        if (left_balances.find(current_balance) == left_balances.end()) {
            left_balances[current_balance] = k_L;
        }
    }

    // Calculate the total balance of all 2n jars.
    int total_balance_all_jars = 0;
    for (int x : a) {
        total_balance_all_jars += (x == 1 ? 1 : -1);
    }

    int min_eaten = 2 * n; // Max possible jars to eat

    // Case 1: No jars eaten from the right side (k_R = 0)
    // The remaining jars are a_1, ..., a_{n-k_L} and a_{n+1}, ..., a_{2n}.
    // The balance of these remaining jars must be 0.
    // This means the balance of the *eaten* jars must be equal to the total balance.
    // Balance of eaten jars = current_balance (from left_balances map)
    // Total balance of all jars = total_balance_all_jars
    // Balance of remaining jars = total_balance_all_jars - current_balance_of_eaten_jars
    // We want total_balance_all_jars - current_balance_of_eaten_jars = 0
    // So, current_balance_of_eaten_jars = total_balance_all_jars.
    if (left_balances.count(total_balance_all_jars)) {
        min_eaten = std::min(min_eaten, left_balances[total_balance_all_jars]);
    }

    // Iterate through possible number of jars eaten from the right side (k_R)
    current_balance = 0; // This will be the balance of jars eaten from the right.
    for (int k_R = 1; k_R <= n; ++k_R) {
        // Jars eaten from right: a_{n}, a_{n+1}, ..., a_{n+k_R-1} (0-indexed)
        current_balance += (a[n + k_R - 1] == 1 ? 1 : -1);

        // The total balance of all jars is `total_balance_all_jars`.
        // If we eat `k_L` jars from left (balance `bal_L`) and `k_R` jars from right (balance `bal_R`),
        // the balance of remaining jars is `total_balance_all_jars - bal_L - bal_R`.
        // We want this to be 0, so `bal_L + bal_R = total_balance_all_jars`.
        // We are looking for `bal_L = total_balance_all_jars - current_balance` (where current_balance is `bal_R`).
        int target_left_balance = total_balance_all_jars - current_balance;
        if (left_balances.count(target_left_balance)) {
            min_eaten = std::min(min_eaten, left_balances[target_left_balance] + k_R);
        }
    }

    std::cout << min_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute prefix sums of '0's
    std::vector<int> prefix_zeros(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_zeros[i + 1] = prefix_zeros[i] + (s[i] == '0');
    }

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            continue; // A good substring cannot start with '0' if its value is > 0.
                      // If value is 0, length must be 0, which is not possible.
                      // So, a good substring must start with '1' to have a positive value.
                      // The only exception is f("0")=0, but length is 1.
                      // f("00")=0, length is 2.
                      // The problem statement says f(000)=0, f(000100)=4.
                      // This implies leading zeros are part of the binary representation.
                      // So, f(0) = 0, length 1. 1 != 0. Not good.
                      // f(00) = 0, length 2. 2 != 0. Not good.
                      // So, a good substring must have a value > 0, meaning it must contain at least one '1'.
                      // If it starts with '0', its value is $f(0\dots)$.
                      // The condition $r-l+1 = f(s_l \dots s_r)$ means $len = val$.
                      // If $s_l = '0'$, then $val$ is at most $2^{len-1}-1$.
                      // For $len = val$ to hold, $len \le 2^{len-1}-1$.
                      // This is true for $len \ge 3$.
                      // For $len=1$, $s_l='0'$, $val=0$, $len=1$. $1 \ne 0$.
                      // For $len=2$, $s_l='0'$, $s_{l+1}='0'$, $val=0$, $len=2$. $2 \ne 0$.
                      // For $len=2$, $s_l='0'$, $s_{l+1}='1'$, $val=1$, $len=2$. $2 \ne 1$.
                      // So, a good substring cannot start with '0'. It must start with '1'.
        }

        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            // Max length of substring to check is limited by MAX_VAL_BITS
            // If current_val exceeds n, then it's too large to be a length.
            // If j - i + 1 (length) exceeds MAX_VAL_BITS, then current_val will be too large.
            // MAX_VAL_BITS is around 18-19 for n=2e5.
            if (j - i + 1 > 19 && current_val > n) { // Optimization: if length is already large and value is also large
                break;
            }

            current_val = (current_val << 1) | (s[j] - '0');

            // If current_val becomes 0, it means the substring is all '0's.
            // But we already established that good substrings must start with '1'.
            // So current_val will always be > 0 here.

            int len = j - i + 1;

            if (current_val > n + 1) { // Optimization: if value exceeds max possible length + small buffer
                break;
            }

            if (current_val == len) {
                good_substrings_count++;
            } else if (current_val < len) {
                // If current_val is less than len, it means the binary value is "small".
                // This can only happen if there are many leading zeros in the binary representation
                // relative to its length. But we are processing from '1'.
                // Example: s_i...s_j = "10000", len=5, val=16. Here val > len.
                // Example: s_i...s_j = "1", len=1, val=1. Here val = len.
                // Example: s_i...s_j = "10", len=2, val=2. Here val = len.
                // Example: s_i...s_j = "100", len=3, val=4. Here val > len.
                // Example: s_i...s_j = "11", len=2, val=3. Here val > len.
                // The only way current_val < len is if the substring starts with '0's,
                // but we are iterating from s[i] == '1'.
                // So, if s[i] == '1', then current_val >= len for len >= 1.
                // current_val = 2^(len-1) + ...
                // For len=1, val=1.
                // For len=2, val=2 (10) or val=3 (11).
                // For len=3, val=4 (100) or val=5 (101) or val=6 (110) or val=7 (111).
                // In general, for a binary string of length L starting with '1', its value is at least 2^(L-1).
                // We need L = val. So L >= 2^(L-1).
                // This inequality L >= 2^(L-1) only holds for L=1 (1 >= 2^0 = 1) and L=2 (2 >= 2^1 = 2).
                // For L=3, 3 < 2^2 = 4.
                // For L > 2, L < 2^(L-1).
                // This means if current_val < len, it's impossible if s[i] == '1'.
                // So this branch is effectively unreachable for s[i] == '1'.
                // This implies that if s[i] == '1', we only need to check current_val == len.
                // If current_val > len, we continue.
            } else { // current_val > len
                // This is the case where current_val is large.
                // We need to find if there's a substring starting with '0's before s[i]
                // such that its value is current_val and its length is current_val.
                // The substring would be s_k...s_j where k < i.
                // The length would be j - k + 1.
                // The value would be f(s_k...s_j) = current_val.
                // So we need j - k + 1 = current_val.
                // This means k = j + 1 - current_val.
                // We need to check if s_k...s_{i-1} are all '0's.
                // The number of leading zeros required is i - k.
                // i - k = i - (j + 1 - current_val) = i - j - 1 + current_val.
                // Let num_leading_zeros = i - k.
                // We need k >= 0, so j + 1 - current_val >= 0, or current_val <= j + 1.
                // We also need k < i, so j + 1 - current_val < i, or current_val > j + 1 - i.
                // The number of zeros needed is (i - 1) - k + 1 = i - k.
                // This is equivalent to checking if prefix_zeros[i] - prefix_zeros[k] == i - k.
                // Or, prefix_zeros[i] - prefix_zeros[j + 1 - current_val] == i - (j + 1 - current_val).

                // The number of zeros we need to prepend to s[i...j] to make its length equal to current_val
                // is current_val - len.
                // Let this be `needed_zeros`.
                long long needed_zeros = current_val - len;

                // The starting index of such a substring would be `i - needed_zeros`.
                long long start_idx_with_zeros = i - needed_zeros;

                // Check if this starting index is valid (non-negative)
                if (start_idx_with_zeros >= 0) {
                    // Check if all characters from start_idx_with_zeros to i-1 are '0's.
                    // This can be done efficiently using prefix_zeros.
                    // The count of zeros in s[start_idx_with_zeros ... i-1] should be equal to
                    // (i - 1) - start_idx_with_zeros + 1 = i - start_idx_with_zeros.
                    if (prefix_zeros[i] - prefix_zeros[start_idx_with_zeros] == needed_zeros) {
                        good_substrings_count++;
                    }
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise
bool apply_median_smoothing(const std::vector<int>& a, std::vector<int>& b) {
    int n = a.size();
    bool changed = false;

    b[0] = a[0];
    b[n - 1] = a[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        if (sum >= 2) { // At least two 1s
            b[i] = 1;
        } else { // At least two 0s
            b[i] = 0;
        }
        if (b[i] != a[i]) {
            changed = true;
        }
    }
    return changed;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only ends exist)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> current_seq = a;
    std::vector<int> next_seq(n);

    // Find the first 1 and last 0
    int first_one = -1;
    for (int i = 0; i < n; ++i) {
        if (current_seq[i] == 1) {
            first_one = i;
            break;
        }
    }

    int last_zero = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (current_seq[i] == 0) {
            last_zero = i;
            break;
        }
    }

    if (first_one == -1 || last_zero == -1 || first_one > last_zero) {
        // Sequence is all 0s or all 1s, or already sorted (0...01...1)
        // It's already stable.
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Calculate initial distances for 0s and 1s
    std::vector<int> dist_to_one(n, n + 1); // Distance to nearest 1 on the right
    std::vector<int> dist_to_zero(n, n + 1); // Distance to nearest 0 on the left

    // Fill dist_to_one
    if (current_seq[n - 1] == 1) {
        dist_to_one[n - 1] = 0;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (current_seq[i] == 1) {
            dist_to_one[i] = 0;
        } else {
            dist_to_one[i] = dist_to_one[i + 1] + 1;
        }
    }

    // Fill dist_to_zero
    if (current_seq[0] == 0) {
        dist_to_zero[0] = 0;
    }
    for (int i = 1; i < n; ++i) {
        if (current_seq[i] == 0) {
            dist_to_zero[i] = 0;
        } else {
            dist_to_zero[i] = dist_to_zero[i - 1] + 1;
        }
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (current_seq[i] == 0) { // For 0s, we care about dist_to_one
            max_dist = std::max(max_dist, dist_to_one[i]);
        } else { // For 1s, we care about dist_to_zero
            max_dist = std::max(max_dist, dist_to_zero[i]);
        }
    }

    int steps = (max_dist + 1) / 2;

    // Apply smoothing 'steps' times
    for (int k = 0; k < steps; ++k) {
        apply_median_smoothing(current_seq, next_seq);
        current_seq = next_seq;
    }

    std::cout << steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] is set per run
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, 0);
    std::vector<int> dp_x(n + 1, 0);
    std::vector<bool> visited(n + 1, false);
    std::vector<bool> in_stack(n + 1, false);

    for (int i = 2; i <= n; ++i) {
        if (!visited[i]) {
            std::vector<int> path;
            int current_x = i;

            while (current_x > 0 && current_x <= n && !visited[current_x] && !in_stack[current_x]) {
                in_stack[current_x] = true;
                path.push_back(current_x);
                long long val = a[current_x];
                current_x = current_x - val; // This is the x value after step 3
            }

            if (current_x <= 0 || current_x > n) { // Terminates outside bounds
                for (int node : path) {
                    visited[node] = true;
                    in_stack[node] = false;
                    dp_y[node] = a[node]; // y from step 2
                    dp_x[node] = current_x;
                }
            } else if (visited[current_x]) { // Terminates by hitting an already computed state
                for (int node : path) {
                    visited[node] = true;
                    in_stack[node] = false;
                    dp_y[node] = a[node] + dp_y[current_x];
                    dp_x[node] = dp_x[current_x];
                }
            } else { // Terminates by hitting a cycle (current_x is in_stack)
                for (int node : path) {
                    visited[node] = true;
                    in_stack[node] = false;
                    dp_y[node] = -1; // Cycle detected, non-terminating
                    dp_x[node] = -1;
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run

        long long current_y = 0;
        int current_x = 1;

        // Step 2
        current_y += a[current_x];
        current_x += a[current_x];

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
        } else {
            // Now we are at a state (current_x, current_y) and need to apply step 3
            // The precomputed dp_y[current_x] and dp_x[current_x] are for the sequence starting with step 3
            // i.e., x_after_step3 = current_x - a[current_x]
            // y_after_step3 = current_y + a[current_x]

            if (dp_x[current_x] == -1) { // Cycle detected from this point
                std::cout << -1 << "\n";
            } else {
                current_y += dp_y[current_x];
                std::cout << current_y << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    // Process type 2 operations to find upper bounds for initial_a[j]
    // initial_a[j] <= m - current_delta[j]
    // We need to find the minimum possible m - current_delta[j] for each j
    // over all type 2 operations that cover j.

    // current_delta_at_op[i][j] stores the sum of d values applied to a[j]
    // just before operation i.
    std::vector<std::vector<long long>> current_delta_at_op(m + 1, std::vector<long long>(n, 0));

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            current_delta_at_op[i+1][j] = current_delta_at_op[i][j];
        }

        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_at_op[i+1][j] += ops[i].val;
            }
        } else { // type 2
            long long M = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], M - current_delta_at_op[i][j]);
            }
        }
    }

    // If initial_a[j] is still max_long_long, it means no type 2 operation constrained it.
    // We can set it to 0 (or any value within [-10^9, 10^9])
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == std::numeric_limits<long long>::max()) {
            initial_a[j] = 0;
        }
    }

    // Verify the solution
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long M = ops[i].val;
            long long max_val_in_range = std::numeric_limits<long long>::min();
            bool found_M = false;

            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                long long current_val = initial_a[j] + current_delta_at_op[i][j];
                max_val_in_range = std::max(max_val_in_range, current_val);
                if (current_val == M) {
                    found_M = true;
                }
            }

            if (max_val_in_range != M || !found_M) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0;
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a[i] >= prev_b
        // We need to find b_i such that prev_b <= b_i <= a[i] + x (mod m)
        // If a[i] >= prev_b, we can potentially set b_i = a[i].
        // This is valid if a[i] <= (a[i] + x) % m.
        // This condition means (a[i] + x) % m must be >= a[i].
        // This happens if a[i] + x < m, or if a[i] + x >= m and (a[i] + x) % m >= a[i].
        // The second part (a[i] + x >= m and (a[i] + x) % m >= a[i]) is only true if a[i] + x is in the range [m, m + a[i] - 1].
        // This means x must be in the range [m - a[i], m - 1].
        // So, if a[i] + x < m, then a[i] is a valid choice for b_i.
        // If a[i] + x >= m, then (a[i] + x) % m is the upper bound.
        // If a[i] <= (a[i] + x) % m, then a[i] is a valid choice.
        // This means we don't need to "wrap around" to satisfy the upper bound.
        // This happens if x < m - a[i].
        // If x >= m - a[i], then (a[i] + x) % m will be < a[i].
        // In this case, we must choose b_i from [prev_b, m-1] or [0, (a[i]+x)%m].
        // If a[i] >= prev_b:
        //   If x < m - a[i]: (a[i] + x) % m is a[i] + x.
        //     We can choose b_i = a[i]. This is valid since a[i] <= a[i] + x.
        //     So, prev_b remains a[i].
        //   If x >= m - a[i]: (a[i] + x) % m is < a[i].
        //     We must choose b_i = prev_b. This is valid if prev_b is in the allowed range.
        //     The allowed range is [a[i], m-1] U [0, (a[i]+x)%m].
        //     Since a[i] >= prev_b, prev_b is in [a[i], m-1]. So prev_b is a valid choice.
        //     So, prev_b remains prev_b.
        // Combining these: if a[i] >= prev_b, and x < m - a[i], we can set prev_b = a[i].
        // Otherwise, prev_b remains prev_b.

        // Case 2: a[i] < prev_b
        // We must choose b_i such that prev_b <= b_i.
        // The only way to satisfy this is if we "wrap around" a[i].
        // That is, b_i must be chosen from [prev_b, m-1] or [0, (a[i]+x)%m].
        // Specifically, b_i must be >= prev_b.
        // This means we must have (a[i] + x) % m >= prev_b.
        // If (a[i] + x) % m < prev_b, then it's impossible to choose b_i >= prev_b.
        // So, if a[i] < prev_b, we must check if (a[i] + x) % m >= prev_b.
        // If it is, we can choose b_i = prev_b.
        // If not, this x is not possible.

        if (current_a >= prev_b) {
            // We can potentially keep current_a as b_i.
            // This is possible if current_a + x doesn't wrap around such that the new value is less than prev_b.
            // Specifically, if current_a + x < m, then current_a + x is the upper bound.
            // We can choose b_i = current_a. This is valid as current_a <= current_a + x.
            // If current_a + x >= m, then (current_a + x) % m is the upper bound.
            // If (current_a + x) % m < prev_b, then we cannot choose current_a.
            // In this case, we must choose b_i = prev_b.
            // This happens if x is large enough to cause a wrap-around, AND the wrapped value is less than prev_b.
            // The condition for wrap-around is x >= m - current_a.
            // If x >= m - current_a, then (current_a + x) % m < current_a.
            // If (current_a + x) % m < prev_b, then we must use prev_b.
            // Otherwise, we can use current_a.

            // If x is small enough that current_a + x doesn't wrap around (i.e., current_a + x < m),
            // then the available range for b_i is [current_a, current_a + x].
            // Since current_a >= prev_b, we can choose b_i = current_a.
            // So, prev_b remains current_a.
            if (current_a + x < m) { // No wrap-around for a[i]
                // We can choose b_i = current_a. It satisfies b_i >= prev_b and b_i <= current_a + x.
                prev_b = current_a;
            } else { // current_a + x >= m, so it wraps around.
                // The available values for b_i are [current_a, m-1] U [0, (current_a + x) % m].
                // We need to choose b_i >= prev_b.
                // If (current_a + x) % m < prev_b, then we cannot choose any b_i >= prev_b.
                // This means we cannot satisfy the condition.
                // Example: a[i]=6, m=7, x=1. (a[i]+x)%m = 0. prev_b=0.
                // a[i] >= prev_b (6 >= 0). x >= m-a[i] (1 >= 7-6).
                // (a[i]+x)%m (0) < prev_b (0) is false.
                // So we can choose b_i = prev_b (0).
                // Example: a[i]=0, m=7, x=6. (a[i]+x)%m = 6. prev_b=5.
                // a[i] < prev_b (0 < 5).
                // (a[i]+x)%m (6) >= prev_b (5). So we can choose b_i = prev_b (5).
                // Example: a[i]=0, m=7, x=5. (a[i]+x)%m = 5. prev_b=6.
                // a[i] < prev_b (0 < 6).
                // (a[i]+x)%m (5) < prev_b (6). So this is impossible.

                // If (current_a + x) % m < prev_b, then we cannot choose b_i = prev_b.
                // We also cannot choose b_i = current_a because current_a >= prev_b, but current_a is not in the range [0, (current_a+x)%m].
                // The only way to satisfy b_i >= prev_b is if prev_b is in the range [current_a, m-1].
                // But if x causes a wrap-around, then (current_a + x) % m < current_a.
                // So if (current_a + x) % m < prev_b, it's impossible.
                // Otherwise, we can choose b_i = prev_b.
                if ((current_a + x) % m < prev_b) {
                    // This means the upper bound after wrap-around is less than prev_b.
                    // So we cannot pick prev_b.
                    // We also cannot pick current_a because current_a is not in [0, (current_a+x)%m].
                    // The only way to pick current_a is if current_a is in [current_a, m-1].
                    // But if we pick current_a, it must be <= (current_a+x)%m if we consider the wrapped range.
                    // This is confusing. Let's simplify.
                    // We need to find b_i such that prev_b <= b_i and b_i is reachable from current_a with x operations.
                    // Reachable means b_i is in [current_a, current_a+x] (if no wrap) or
                    // b_i is in [current_a, m-1] U [0, (current_a+x)%m] (if wrap).
                    // If current_a >= prev_b:
                    //   If x < m - current_a: (no wrap for current_a)
                    //     Range is [current_a, current_a + x].
                    //     We can choose b_i = current_a. prev_b becomes current_a.
                    //   If x >= m - current_a: (wrap for current_a)
                    //     Range is [current_a, m-1] U [0, (current_a + x) % m].
                    //     We need to choose b_i >= prev_b.
                    //     If (current_a + x) % m < prev_b:
                    //       Then prev_b is not in [0, (current_a + x) % m].
                    //       And prev_b is not in [current_a, m-1] because current_a >= prev_b.
                    //       So, we cannot choose b_i >= prev_b. This x is invalid.
                    //     Else ((current_a + x) % m >= prev_b):
                    //       We can choose b_i = prev_b. prev_b remains prev_b.
                    // This logic is correct.
                    return false;
                }
                // Else, (current_a + x) % m >= prev_b. We can choose b_i = prev_b.
                // prev_b remains prev_b.
            }
        } else { // current_a < prev_b
            // We must choose b_i >= prev_b.
            // This means we must use the wrap-around part.
            // The only way to satisfy b_i >= prev_b is if (current_a + x) % m >= prev_b.
            // If this condition is not met, then it's impossible.
            if ((current_a + x) % m < prev_b) {
                return false;
            }
            // If it is met, we can choose b_i = prev_b.
            // prev_b remains prev_b.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations is m-1 (e.g., 0 -> m-1)
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].id = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply v_i effect
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Apply d_j effect from previous children crying
            children[j].p -= total_d_effect;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

