int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current state for a bit that is 0 and a bit that is 1
    // We only care about bits 0-9, as constants are up to 1023.
    // Let's track the value for an input bit 0 and an input bit 1.
    // For each bit position, the transformation is independent.
    // So, we can find the final state for an input bit 0 and an input bit 1.
    // Let `val0` be the result if the initial bit was 0.
    // Let `val1` be the result if the initial bit was 1.
    // We need to track this for all 10 bits.
    // A more compact way is to track the full 10-bit number.
    // Let `current_val_if_input_is_0` be the result if the input was 0.
    // Let `current_val_if_input_is_all_ones` be the result if the input was 1023 (all 1s for 10 bits).
    // This is not quite right. We need to track for each bit position.
    // Let's track two numbers:
    // `val_for_0`: what 0 becomes after all operations.
    // `val_for_1023`: what 1023 becomes after all operations.
    // This is still not enough.
    // We need to know for each bit position `j`:
    // 1. What `0` at position `j` becomes.
    // 2. What `1` at position `j` becomes.
    // Let's represent this as two numbers:
    // `res_if_input_bit_is_0`: a 10-bit number where the j-th bit is the result of applying all operations to an input where only the j-th bit is 0 and all other bits are 1. This is not right.

    // Let's track the transformation for a single bit.
    // For each bit position `j` (0 to 9):
    // `bit_state[j][0]` will be the final value of bit `j` if its initial value was 0.
    // `bit_state[j][1]` will be the final value of bit `j` if its initial value was 1.
    // Initialize:
    // `bit_state[j][0] = 0`
    // `bit_state[j][1] = 1`
    // This means if input bit `j` is 0, it remains 0. If input bit `j` is 1, it remains 1.
    // This is equivalent to the identity transformation `x -> x`.

    // We can represent this more compactly.
    // Let `current_val_0` be the value that an input `0` would become after all operations.
    // Let `current_val_1023` be the value that an input `1023` (all 1s for 10 bits) would become after all operations.
    // This is still not enough to determine the final operations.

    // The key insight is that for each bit position `j`, the final value `res_j` depends only on the initial value `x_j` and the sequence of constants' `j`-th bits.
    // So, for each bit `j`, we can determine a function `f_j(x_j)` that maps `x_j` to `res_j`.
    // There are 4 possible functions for a single bit:
    // 1. `f(b) = b` (identity)
    // 2. `f(b) = !b` (NOT)
    // 3. `f(b) = 0` (constant 0)
    // 4. `f(b) = 1` (constant 1)

    // Let's track two numbers:
    // `val_if_input_is_0`: what the number 0 becomes after all operations.
    // `val_if_input_is_1023`: what the number 1023 (binary 1111111111) becomes after all operations.
    // These two values are sufficient to determine the final transformation for each bit.
    // For each bit position `j`:
    // Let `x_j` be the `j`-th bit of the input.
    // Let `c_j` be the `j`-th bit of the constant.
    // `final_0_j` = `j`-th bit of `val_if_input_is_0`
    // `final_1_j` = `j`-th bit of `val_if_input_is_1023`

    // If `final_0_j == 0` and `final_1_j == 1`: `x_j` maps to `x_j` (identity)
    // If `final_0_j == 1` and `final_1_j == 0`: `x_j` maps to `!x_j` (NOT)
    // If `final_0_j == 0` and `final_1_j == 0`: `x_j` maps to `0` (constant 0)
    // If `final_0_j == 1` and `final_1_j == 1`: `x_j` maps to `1` (constant 1)

    // Initialize `val_if_input_is_0 = 0` and `val_if_input_is_1023 = 1023`.
    // This represents the identity transformation `x -> x`.
    int val_for_0 = 0;
    int val_for_1023 = 1023; // 2^10 - 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val_for_0 &= x;
            val_for_1023 &= x;
        } else if (op_char == '|') {
            val_for_0 |= x;
            val_for_1023 |= x;
        } else if (op_char == '^') {
            val_for_0 ^= x;
            val_for_1023 ^= x;
        }
    }

    // Now we have `val_for_0` and `val_for_1023`.
    // We need to find a sequence of at most 5 operations that achieves this.
    // The target operations are:
    // `res_x = (x & C_AND) | C_OR ^ C_XOR`
    // Or some combination.
    // A common way to represent any bitwise function `f(x)` is `(x & A) | (B & ~x)`.
    // For our case, we have `f_j(x_j)` for each bit `j`.
    // `f_j(0) = final_0_j`
    // `f_j(1) = final_1_j`

    // Let's construct the constants for the final operations.
    // We can always represent any bitwise function `f(x)` as `(x & A) | B` or `(x ^ A) & B` etc.
    // A canonical form for any bitwise function of one variable `x` is `(x & M1) | (x ^ M2)`.
    // Or more simply, `(x & A) | B` or `(x ^ A) | B`.
    // Let's try to find `C_AND`, `C_OR`, `C_XOR` such that:
    // `(x & C_AND) | C_OR ^ C_XOR`
    // This is too complex.

    // Let's use the property that `(x & A) | B` can represent any function.
    // If `x=0`: `(0 & A) | B = B`. So `B = val_for_0`.
    // If `x=1023`: `(1023 & A) | B = A | B`. So `A | B = val_for_1023`.
    // We need to find `A` such that `A | val_for_0 = val_for_1023`.
    // This means for every bit `j`:
    // `A_j | (val_for_0)_j = (val_for_1023)_j`.
    // If `(val_for_0)_j = 0`: `A_j = (val_for_1023)_j`.
    // If `(val_for_0)_j = 1`: `(val_for_1023)_j` must be 1. If it's 0, then no such `A_j` exists.
    // But `val_for_0` is the result for input 0, and `val_for_1023` is for input 1023.
    // If `(val_for_0)_j = 1` and `(val_for_1023)_j = 0`, it means `0` maps to `1` and `1` maps to `0` for bit `j`. This is `!x_j`.
    // In this case, `A_j | 1 = 0` is impossible.

    // Let's analyze the bit transformations:
    // For each bit `j`:
    // `f_j(0) = (val_for_0 >> j) & 1`
    // `f_j(1) = (val_for_1023 >> j) & 1`

    // We want to find `C_AND`, `C_OR`, `C_XOR` such that for any `x` (0 to 1023):
    // `(x & C_AND) | C_OR ^ C_XOR` is the result.
    // This is equivalent to finding `C_AND`, `C_OR`, `C_XOR` such that:
    // `(0 & C_AND) | C_OR ^ C_XOR = val_for_0`
    // `(1023 & C_AND) | C_OR ^ C_XOR = val_for_1023`

    // Let's try to construct the constants for `&`, `|`, `^` operations.
    // We can always achieve any bitwise function `f(x)` using at most 3 operations:
    // `(x & M_AND) | M_OR ^ M_XOR`
    // This is not quite right. The standard form is `(x & A) | B`.
    // Or `(x ^ A) & B`.
    // Or `(x | A) & B`.

    // Let's use the fact that any bitwise function `f(x)` can be represented as `(x & A) | B`.
    // If `x=0`, `f(0) = (0 & A) | B = B`. So `B = val_for_0`.
    // If `x=1023`, `f(1023) = (1023 & A) | B = A | B`. So `A | B = val_for_1023`.
    // We need to find `A` such that `A | val_for_0 = val_for_1023`.
    // For each bit `j`: `A_j | (val_for_0)_j = (val_for_1023)_j`.
    // If `(val_for_0)_j = 0`: `A_j = (val_for_1023)_j`.
    // If `(val_for_0)_j = 1`: `(val_for_1023)_j` must be 1. If it's 0, then this form `(x & A) | B` cannot represent the function.
    // This means `(val_for_0)_j <= (val_for_1023)_j` for all bits `j`.
    // This is equivalent to `(val_for_0 & ~val_for_1023) == 0`.
    // If this condition holds, then `A = val_for_1023`.
    // So, if `(val_for_0 & ~val_for_1023) == 0`, we can use `(x & val_for_1023) | val_for_0`.
    // This is 2 operations.

    // What if `(val_for_0 & ~val_for_1023) != 0`?
    // This means for some bit `j`, `(val_for_0)_j = 1` and `(val_for_1023)_j = 0`.
    // This corresponds to the `!x_j` transformation for bit `j`.
    // In this case, `(x & A) | B` is not sufficient.
    // We need to use XOR.
    // Any bitwise function `f(x)` can be represented as `(x ^ C_XOR) & C_AND | C_OR`.
    // This is 3 operations.
    // Let's try to find `C_AND`, `C_OR`, `C_XOR`.
    // Let `y = x ^ C_XOR`. Then `(y & C_AND) | C_OR`.
    // We know `(0 ^ C_XOR) & C_AND | C_OR = val_for_0`.
    // We know `(1023 ^ C_XOR) & C_AND | C_OR = val_for_1023`.

    // Let `C_XOR` be the bits where `f_j(0) != f_j(1)`.
    // No, this is not right.
    // Let's define `C_XOR` such that `x ^ C_XOR` makes the transformation monotonic.
    // For each bit `j`:
    // `f_j(0)` and `f_j(1)` are the target values.
    // If `f_j(0) == 0` and `f_j(1) == 1`: `x_j` maps to `x_j`.
    // If `f_j(0) == 1` and `f_j(1) == 0`: `x_j` maps to `!x_j`.
    // If `f_j(0) == 0` and `f_j(1) == 0`: `x_j` maps to `0`.
    // If `f_j(0) == 1` and `f_j(1) == 1`: `x_j` maps to `1`.

    // Let `C_XOR` be the mask for bits that need to be flipped.
    // If `f_j(0) = 1` and `f_j(1) = 0` (NOT operation), then `x_j` needs to be flipped.
    // So, `C_XOR_j = 1` if `f_j(0) != f_j(1)`.
    // `C_XOR_j = 0` if `f_j(0) == f_j(1)`.
    int C_XOR = 0;
    for (int j = 0; j < 10; ++j) {
        int bit_0_res = (val_for_0 >> j) & 1;
        int bit_1_res = (val_for_1023 >> j) & 1;
        if (bit_0_res != bit_1_res) {
            C_XOR |= (1 << j);
        }
    }

    // After `x ^ C_XOR`, let the new input be `x'`.
    // For bit `j`:
    // If `C_XOR_j = 0`: `x'_j = x_j`. The target is `f_j(x_j)`.
    //   `f_j(0) = 0`, `f_j(1) = 1` (identity) OR `f_j(0) = 0`, `f_j(1) = 0` (constant 0) OR `f_j(0) = 1`, `f_j(1) = 1` (constant 1).
    // If `C_XOR_j = 1`: `x'_j = !x_j`. The target is `f_j(x_j)`.
    //   `f_j(0) = 1`, `f_j(1) = 0` (NOT).
    //   So, `x'_j = 1` (when `x_j=0`) maps to `1`. `x'_j = 0` (when `x_j=1`) maps to `0`.
    //   This means `x'_j` maps to `x'_j` (identity).

    // Let `val_for_0_prime = 0 ^ C_XOR = C_XOR`.
    // Let `val_for_1023_prime = 1023 ^ C_XOR`.
    // Now we need to find `C_AND` and `C_OR` such that `(x' & C_AND) | C_OR` works.
    // `(C_XOR & C_AND) | C_OR = val_for_0`
    // `((1023 ^ C_XOR) & C_AND) | C_OR = val_for_1023`

    // Let `B = C_OR`.
    // Let `A = C_AND`.
    // We need `(x' & A) | B`.
    // For each bit `j`:
    // `(x'_j & A_j) | B_j = f_j(x_j)`.
    // If `C_XOR_j = 0`: `x'_j = x_j`.
    //   `f_j(0) = (0 & A_j) | B_j = B_j`. So `B_j = (val_for_0 >> j) & 1`.
    //   `f_j(1) = (1 & A_j) | B_j = A_j | B_j`. So `A_j | B_j = (val_for_1023 >> j) & 1`.
