// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int current_parity_a = calculate_parity(a);

    // Calculate parity of string b
    int parity_b = calculate_parity(b);

    // The maximum possible length of a string generated from 'a'
    // that could potentially contain 'b' as a suffix.
    // This is |a| + (|b| - 1) if |a| < |b|, or |a| if |a| >= |b|.
    // In general, it's max(|a|, |b|) + (length_of_b - 1)
    // A simpler upper bound is |a| + |b| - 1, because we need to generate at least |b| characters
    // and the first |a| characters are given.
    // If |a| is 1000 and |b| is 1000, we might need to generate 999 parity bits to get a string of length 1999.
    // The maximum length of a string we might need to consider is |a| + |b| - 1.
    // If |a| = 1, |b| = 1000, we need to generate 999 parity bits. Total length 1000.
    // If |a| = 1000, |b| = 1, we don't need to generate any parity bits. Total length 1000.
    // The maximum length of the string `a_extended` we need to consider is `|a| + |b| - 1`.
    // This is because if `b` is a suffix of `a_extended`, and `|a_extended| >= |b|`,
    // then `a_extended` must have been formed by `a` followed by `|a_extended| - |a|` parity bits.
    // The longest `b` can be is 1000. The longest `a` can be is 1000.
    // So `a_extended` can be up to `1000 + 1000 - 1 = 1999` characters long.
    // We can use a vector to store the parity bits efficiently.
    std::vector<int> parities_generated;
    parities_generated.reserve(b.length()); // Max |b|-1 parity bits needed

    // Generate parity bits until the effective length of 'a' (including generated parities)
    // is at least |b|.
    // The effective length is |a| + parities_generated.size().
    // We need to generate enough parity bits such that the string `a` followed by these parities
    // is long enough to contain `b` as a suffix.
    // The maximum length of `a` we need to consider is `a.length() + b.length() - 1`.
    // So we generate `b.length() - 1` parity bits at most.
    // If `a.length()` is already greater than or equal to `b.length()`, we might not need to generate any.
    // But we still need to check if `b` can be formed by `a` itself or `a` with some parities.
    // The loop condition ensures we generate enough parities to cover all possible suffixes of length |b|.
    // We need to generate parities until the total length of `a` + generated parities is `a.length() + b.length() - 1`.
    // This means we generate `b.length() - 1` parities.
    for (size_t i = 0; i < b.length(); ++i) {
        parities_generated.push_back(current_parity_a);
        current_parity_a = (current_parity_a + parities_generated.back()) % 2;
    }

    // Now, we have string 'a' and a sequence of generated parity bits.
    // We need to check if 'b' is a suffix of 'a' followed by some of these parity bits.
    // The length of 'a' is |a|.
    // The length of 'b' is |b|.
    // The length of generated parities is `parities_generated.size()`.
    // The total length of the conceptual string `a_extended` is `a.length() + parities_generated.size()`.
    // We need to check if `b` is a suffix of `a_extended`.
    // This means `b` must match the last `|b|` characters of `a_extended`.
    // These last `|b|` characters can be:
    // 1. Entirely from `a` (if `|a| >= |b|`).
    // 2. Partially from `a` and partially from generated parities.
    // 3. Entirely from generated parities (if `|a|` is very small, e.g., 1, and `|b|` is large).

    // Let's iterate through all possible starting points for `b` within the conceptual `a_extended` string.
    // The `a_extended` string is `a[0...|a|-1] + parities_generated[0...|parities_generated|-1]`.
    // The total length of this conceptual string is `a.length() + parities_generated.size()`.
    // We are looking for a suffix of length `b.length()`.
    // The starting index of this suffix in `a_extended` would be `a.length() + parities_generated.size() - b.length()`.
    // This starting index must be non-negative.
    // The number of characters from `a` that are part of this suffix is `std::max(0LL, (long long)a.length() - (long long)(a.length() + parities_generated.size() - b.length()))`.
    // This simplifies to `std::max(0LL, (long long)b.length() - (long long)parities_generated.size())`.
    // Let `num_from_a` be the number of characters from `a` that form the prefix of `b`.
    // Let `num_from_parities` be the number of characters from `parities_generated` that form the suffix of `b`.
    // `num_from_a + num_from_parities = b.length()`.
    // The characters from `a` would be `a[a.length() - num_from_a ... a.length() - 1]`.
    // The characters from `parities_generated` would be `parities_generated[0 ... num_from_parities - 1]`.

    // We need to check if `b` matches the suffix of `a` followed by `k` generated parities,
    // for all `k` from 0 up to `parities_generated.size()`.
    // The length of the string we are checking is `a.length() + k`.
    // If `a.length() + k < b.length()`, it's impossible.
    // So we only check when `a.length() + k >= b.length()`.

    bool possible = false;
    for (size_t k = 0; k <= parities_generated.size(); ++k) {
        // `current_a_len` is the length of `a` plus `k` generated parities.
        size_t current_a_len = a.length() + k;

        if (current_a_len < b.length()) {
            continue; // Not long enough to contain b
        }

        // Check if b matches the last b.length() characters of this extended string.
        bool match = true;
        // Compare characters from 'a'
        // Number of characters from 'a' that are part of the suffix 'b'
        size_t num_from_a_in_suffix = 0;
        if (current_a_len - b.length() < a.length()) { // If the suffix starts within 'a'
            num_from_a_in_suffix = a.length() - (current_a_len - b.length());
        }

        for (size_t i = 0; i < num_from_a_in_suffix; ++i) {
            if (a[a.length() - num_from_a_in_suffix + i] != b[i]) {
                match = false;
                break;
            }
        }

        if (!match) {
            continue;
        }

        // Compare characters from generated parities
        // Number of characters from generated parities that are part of the suffix 'b'
        size_t num_from_parities_in_suffix = b.length() - num_from_a_in_suffix;
        for (size_t i = 0; i < num_from_parities_in_suffix; ++i) {
            if (parities_generated[i] != (b[num_from_a_in_suffix + i] - '0')) {
                match = false;
                break;
            }
        }

        if (match) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: a_1 and a_2 are in different subsequences.
    // This implies a_1 is in S1, a_2 is in S2.
    // To minimize max_f - min_f, we want to make min_f as large as possible
    // and max_f as small as possible.
    //
    // If a_1 and a_2 are in different subsequences, then f(a_1, a_2) = a_1 + a_2 + h.
    // This is the minimum possible f value if a_1 and a_2 are split.
    //
    // Consider the partition where a_1 is in S1, and all other elements (a_2, ..., a_n) are in S2.
    //
    // Values of f:
    // 1. f(a_i, a_j) where a_i, a_j in S2 (i.e., i, j >= 2):
    //    min: a_2 + a_3
    //    max: a_{n-1} + a_n
    // 2. f(a_1, a_j) where a_j in S2 (i.e., j >= 2):
    //    min: a_1 + a_2 + h
    //    max: a_1 + a_n + h
    //
    // Overall min_f for this partition: min(a_2 + a_3, a_1 + a_2 + h)
    // Overall max_f for this partition: max(a_{n-1} + a_n, a_1 + a_n + h)
    //
    // However, the problem statement implies that we need to consider all pairs.
    // The minimum possible value of f is always `a_1 + a_2` or `a_1 + a_2 + h`.
    // The maximum possible value of f is always `a_{n-1} + a_n` or `a_{n-1} + a_n + h`.
    //
    // Let's consider the partition where `elements[0]` is in S1, and all other `elements[1...n-1]` are in S2.
    //
    // min_f:
    //   - If `n=2`, only `f(elements[0], elements[1]) = elements[0].value + elements[1].value + h`.
    //   - If `n > 2`:
    //     - `elements[0]` and `elements[1]` are in different subsequences: `elements[0].value + elements[1].value + h`
    //     - `elements[1]` and `elements[2]` are in the same subsequence (S2): `elements[1].value + elements[2].value`
    //     So, `min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)`
    //     (This is only if n > 2. If n=2, min_f is just elements[0].value + elements[1].value + h)
    //
    // max_f:
    //   - `elements[0]` and `elements[n-1]` are in different subsequences: `elements[0].value + elements[n-1].value + h`
    //   - `elements[n-2]` and `elements[n-1]` are in the same subsequence (S2): `elements[n-2].value + elements[n-1].value`
    //   So, `max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)`
    //
    // Goodness = max_f - min_f
    //
    // Let's calculate this for the partition: elements[0] in S1, elements[1...n-1] in S2.
    long long current_min_f_val;
    if (n == 2) {
        current_min_f_val = elements[0].value + elements[1].value + h;
    } else {
        current_min_f_val = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    }
    long long current_max_f_val = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 2].value + elements[n - 1].value);
    long long goodness2 = current_max_f_val - current_min_f_val;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[elements[i].original_index] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        std::vector<int> partition2(n);
        partition2[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition2[elements[i].original_index] = 2;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

