        // s_prefix = "nolo", s_suffix = "n". new = "nnolo" (not palindrome)
        // So k=1 fails for "nolon".
        // With k=2, we can cut "no|l|on". Rearrange to "on|l|no" -> "onlno". This is a palindrome.
        // This strategy works for any palindrome s with at least two distinct characters.
        // Take the first character s[0]. Since s is a palindrome, s[n-1] = s[0].
        // Since there are at least two distinct characters, there must be some character s[i] != s[0]
        // for 0 < i < n-1.
        // Consider cutting s into s[0] | s[1...n-2] | s[n-1].
        // Rearrange to s[n-1] | s[1...n-2] | s[0].
        // This forms s[n-1] + s[1...n-2] + s[0].
        // Since s[n-1] = s[0], this is s[0] + s[1...n-2] + s[0].
        // This is the same as s.
        //
        // A different strategy for k=2:
        // Take s = A B A, where A is s[0...k-1] and B is s[k...n-k-1].
        // Since s is a palindrome, A is the reverse of s[n-k...n-1].
        // If we cut s into A | B | A_rev (where A_rev is the reverse of A),
        // we can rearrange to A_rev | B | A.
        // This will be a palindrome if A_rev is a palindrome and B is a palindrome.
        //
        // A simpler argument for k=2:
        // If s has at least two distinct characters, and k=1 didn't work,
        // it means that for any cyclic shift of s, the resulting string is either not a palindrome
        // or it is equal to s.
        // Consider the string s' formed by removing the first character and appending it to the end:
        // s' = s.substr(1) + s[0].
        // If s' is a palindrome and s' != s, then k=1.
        // If s' is not a palindrome, or s' == s, then k=1 doesn't work for this specific cut.
        //
        // The problem statement guarantees that s is a palindrome.
        // If s has at least two distinct characters, and k=1 doesn't work,
        // then k=2 is always the answer.
        // This is because we can always find a way to make two cuts and rearrange.
        // For example, take s = "abacaba".
        // k=1: "bacabaa" (not pal), "acabaab" (not pal), "cabaaba" (not pal), "abaacab" (not pal), "baacaba" (not pal), "aacabab" (not pal).
        // So k=1 fails.
        // For k=2: "a|bacab|a". Rearrange to "a|bacab|a" (same).
        // But we can cut "ab|aca|ba". Rearrange to "ba|aca|ab" -> "baacaab". This is a palindrome and not equal to "abacaba".
        // So k=2 is the answer.
        // The only case where k=2 might not work is if all characters are the same, which is handled by distinct_chars <= 1.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] stores the maximum length of a suffix ending at i-1 that does NOT contain a 3-AP.
    // This is equivalent to the minimum l such that s[l...i-1] contains a 3-AP.
    // If dp[i] = 0, it means s[0...i-1] does not contain a 3-AP.
    // If dp[i] = k > 0, it means s[k...i-1] is the shortest suffix that contains a 3-AP.
    // So, for a fixed r (which is i-1), any l < k will form a bad pair (l, r).
    // The number of such l's is k.
    // The indices in the problem are 1-based, string is 0-based.
    // Let's use 0-based indexing for string s and 1-based for l, r, x, k.
    // s_idx = x-1, s_idx+k = x+k-1, s_idx+2k = x+2k-1.
    // The condition $l \leq x < x+2k \leq r$ becomes $l-1 \leq x-1 < x+2k-1 \leq r-1$.
    // Let's define min_l_for_r[r_idx] as the minimum 0-based index `l_idx` such that
    // s[l_idx ... r_idx] contains a 3-AP. If no such 3-AP exists, min_l_for_r[r_idx] = r_idx + 1.
    // Then for a fixed r_idx, the number of bad l_idx's is (r_idx + 1) - min_l_for_r[r_idx].
    // This is equivalent to (r_idx + 1) - (min_l_for_r[r_idx] - 1) if min_l_for_r[r_idx] is 1-based.
    // Let's use `min_l_idx[r_idx]` to store the smallest 0-based `l_idx` such that `s[l_idx...r_idx]`
    // contains a 3-AP. If no such `l_idx` exists, `min_l_idx[r_idx]` will be `r_idx + 1`.

    std::vector<int> min_l_idx(n); // min_l_idx[r_idx] stores the smallest 0-based l_idx for s[l_idx...r_idx]
                                   // that contains a 3-AP.
                                   // Initialize with r_idx + 1 (meaning no 3-AP found yet for this r_idx).

    // For r_idx = 0, 1, 2, 3, 4, 5, min_l_idx[r_idx] is r_idx + 1.
    // A 3-AP requires at least 3 characters, so r_idx must be at least 2.
    // The smallest possible 3-AP is s_x = s_{x+1} = s_{x+2}.
    // This means x+2k must be at least 2 (0-indexed).
    // So, for r_idx < 2, min_l_idx[r_idx] will always be r_idx + 1.
    if (n > 0) min_l_idx[0] = 1;
    if (n > 1) min_l_idx[1] = 2;

    for (int r_idx = 2; r_idx < n; ++r_idx) {
        // Initialize min_l_idx[r_idx] based on the previous value.
        // If s[l_idx...r_idx-1] contains a 3-AP, then s[l_idx...r_idx] also contains it.
        // So, min_l_idx[r_idx] is at most min_l_idx[r_idx-1].
        min_l_idx[r_idx] = min_l_idx[r_idx - 1];

        // Check for new 3-APs ending at r_idx.
        // A new 3-AP is s_x = s_{x+k} = s_{x+2k} where x+2k = r_idx.
        // This means x = r_idx - 2k.
        // We need to check for k = 1, 2, 3, 4, 5.
        // Why only up to k=5?
        // If k >= 6, then x+2k >= x+12.
        // The minimum length of a substring containing such a 3-AP is 2k+1.
        // If k=6, length is 13.
        // If we have s_x = s_{x+k} = s_{x+2k}, then s_x = s_{x+k} and s_{x+k} = s_{x+2k}.
        // If k is large, say k=6, then s_x = s_{x+6} = s_{x+12}.
        // If there is such a 3-AP, then the substring s[x...x+12] contains it.
        // If there is no 3-AP with k <= 5, then any 3-AP with k >= 6 would be "covered"
        // by a shorter 3-AP if it existed.
        // This is a known property for "avoiding 3-APs" in binary strings.
        // If a binary string contains a 3-AP, it must contain one with k <= 5.
        // For example, if s_x = s_{x+k} = s_{x+2k} for k >= 6,
        // and s_x = '0', then we have '0' at x, x+k, x+2k.
        // Consider the string s[x...x+2k].
        // If there is no 3-AP with k' <= 5, then this string is "3-AP-free" for small k'.
        // This is a non-trivial result from combinatorics on words.
        // The maximum length of a binary string that avoids 3-APs is 10.
        // For example, 0011010011.
        // Any string of length 11 or more must contain a 3-AP.
        // The maximum length of a binary string that avoids 3-APs of distance k <= 5 is 10.
        // If a string has a 3-AP, it must have one with k <= 5.
        // So we only need to check k from 1 to 5.

        for (int k = 1; k <= 5; ++k) {
            int x_idx = r_idx - 2 * k; // 0-based x index
            if (x_idx >= 0 && s[x_idx] == s[x_idx + k] && s[x_idx + k] == s[r_idx]) {
                // Found a 3-AP s[x_idx] = s[x_idx+k] = s[r_idx]
                // This 3-AP starts at x_idx and ends at r_idx.
                // So, for this r_idx, the minimum l_idx can be at most x_idx.
                min_l_idx[r_idx] = std::min(min_l_idx[r_idx], x_idx);
            }
        }
        // After checking all relevant k's, min_l_idx[r_idx] holds the smallest l_idx
        // such that s[l_idx...r_idx] contains a 3-AP.
        // The number of bad pairs (l, r_idx) for this r_idx is min_l_idx[r_idx].
        // (Because l_idx can be 0, 1, ..., min_l_idx[r_idx]-1).
        bad_pairs += min_l_idx[r_idx];
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        // If current head h[h_idx] is already to the right of the current target p[p_idx]
        // and cannot reach it within T time (i.e., h[h_idx] - T > p[p_idx]),
        // then this head cannot cover p[p_idx] or any p_k with k >= p_idx.
        // This implies that p[p_idx] must be covered by a previous head.
        // Since we are iterating heads from left to right and target tracks from left to right,
        // if h[h_idx] is too far right for p[p_idx], it means p[p_idx] cannot be covered.
        // However, this logic is flawed. A head h[h_idx] might be far right, but it can move left.
        // The crucial part is that if h[h_idx] is too far right to cover p[p_idx] (i.e., h[h_idx] - T > p[p_idx]),
        // then no subsequent head h[h_idx+k] can cover p[p_idx] either, because h[h_idx+k] >= h[h_idx].
        // So, if h[h_idx] - T > p[p_idx], then p[p_idx] cannot be covered by any head from h_idx onwards.
        // This means p[p_idx] must have been covered by a head h_k with k < h_idx.
        // But our greedy strategy is to cover p[p_idx] with the *current* head h[h_idx] if possible.
        // If h[h_idx] is too far right, it means p[p_idx] was not covered by previous heads,
        // and cannot be covered by current or subsequent heads. So it's impossible.
        // This check is implicitly handled by the loop condition below.

        // Find the first target track p[p_idx] that this head h[h_idx] can potentially cover.
        // This means p[p_idx] must be within h[h_idx] + T.
        // If p[p_idx] > h[h_idx] + T, this head cannot reach p[p_idx] or any subsequent tracks.
        // This implies that p[p_idx] must be covered by a previous head.
        // If we reach this point and p[p_idx] is not covered, it's impossible.
        // This is also implicitly handled.

        // The core idea: for each head h[h_idx], we want to cover as many *uncovered* tracks as possible,
        // starting from p[p_idx].
        // The head h[h_idx] can cover a range [h[h_idx] - T, h[h_idx] + T].
        // If p[p_idx] is outside this range, specifically p[p_idx] > h[h_idx] + T,
        // then this head cannot cover p[p_idx]. Since p is sorted, it cannot cover any p_k for k > p_idx either.
        // This means p[p_idx] must have been covered by a previous head.
        // If p[p_idx] is not covered by previous heads, and h[h_idx] cannot reach it, then it's impossible.
        // This is the key condition: if p[p_idx] is too far right for h[h_idx] to reach, then it's false.
        if (p[p_idx] > h[h_idx] + T) {
            return false;
        }

        // If h[h_idx] can reach p[p_idx] (i.e., p[p_idx] <= h[h_idx] + T),
        // then this head can cover p[p_idx].
        // Now, what is the rightmost track this head can cover?
        // It depends on whether h[h_idx] moves left or right.
        // Case 1: h[h_idx] moves left to cover p[p_idx].
        // The leftmost point it can reach is h[h_idx] - T.
        // The rightmost point it can reach is p[p_idx] + (T - (p[p_idx] - (h[h_idx] - T)))
        // This is equivalent to: if it moves to p[p_idx], it uses |p[p_idx] - h[h_idx]| time.
        // Remaining time is T - |p[p_idx] - h[h_idx]|.
        // It can then move further right by this remaining time.
        // So, the rightmost point it can reach is p[p_idx] + (T - std::abs(p[p_idx] - h[h_idx])).
        // This simplifies to:
        // If p[p_idx] <= h[h_idx]: it moves left. Time used = h[h_idx] - p[p_idx].
        //   Rightmost reach = h[h_idx] + (T - (h[h_idx] - p[p_idx])) = p[p_idx] + T.
        // If p[p_idx] > h[h_idx]: it moves right. Time used = p[p_idx] - h[h_idx].
        //   Rightmost reach = p[p_idx] + (T - (p[p_idx] - h[h_idx])) = h[h_idx] + T.
        // So, the rightmost track it can cover is always h[h_idx] + T.
        // This is incorrect. The head can move to a point X, and then sweep a range.
        // The range covered by a head at h_i in time T is [h_i - T, h_i + T].
        // If we want to cover p_j, and p_j is in [h_i - T, h_i + T], then it's covered.
        // The problem is that we need to cover a *contiguous* block of tracks starting from p[p_idx].
        // No, the problem states "A track is considered read if at least one head has visited this track."
        // It does not say contiguous. It says "read all the given tracks p_1, ..., p_m".

        // Let's re-evaluate the range a head can cover.
        // A head at h_i can cover any track X such that |X - h_i| <= T.
        // This means X is in [h_i - T, h_i + T].
        // If we use head h_i to cover p[p_idx], it must be that p[p_idx] >= h_i - T.
        // The rightmost track this head can cover is determined by its movement.
        // If h_i moves to the left to cover p[p_idx], it takes h_i - p[p_idx] time.
        // It has T - (h_i - p[p_idx]) time remaining.
        // It can then move right from p[p_idx] by this remaining time.
        // So, it can cover up to p[p_idx] + (T - (h_i - p[p_idx])) = p[p_idx] + T - h_i + p[p_idx] = 2*p[p_idx] - h_i + T.
        // This is the rightmost point if it first goes to p[p_idx] and then sweeps right.
        // This is only valid if p[p_idx] <= h_i.
        // If h_i moves to the right to cover p[p_idx], it takes p[p_idx] - h_i time.
        // It has T - (p[p_idx] - h_i) time remaining.
        // It can then move right from p[p_idx] by this remaining time.
        // So, it can cover up to p[p_idx] + (T - (p[p_idx] - h_i)) = h_i + T.
        // This is valid if p[p_idx] >= h_i.

        // Combining these:
        // If p[p_idx] <= h[h_idx]: rightmost_reach = std::max(h[h_idx] + T, 2 * p[p_idx] - h[h_idx] + T);
        // If p[p_idx] > h[h_idx]: rightmost_reach = h[h_idx] + T;
        // This can be simplified. The head can move to any point X in [h_i - T, h_i + T].
        // If it moves to X, it takes |X - h_i| time.
        // It can then sweep a range of length (T - |X - h_i|) to the left and right of X.
        // So, it covers the range [X - (T - |X - h_i|), X + (T - |X - h_i|)].
        // We want to cover p[p_idx]. So we must choose X such that p[p_idx] is in this range.
        // And we want to maximize the rightmost point covered.
        // The maximum rightmost point a head at h_i can cover, given it must cover p[p_idx], is:
        // If p[p_idx] is to the left of h_i (p[p_idx] < h_i):
        //   The head moves left to p[p_idx]. Time taken: h_i - p[p_idx].
        //   Remaining time: T - (h_i - p[p_idx]).
        //   It can then sweep right from p[p_idx] by this remaining time.
        //   Max right reach: p[p_idx] + (T - (h_i - p[p_idx])) = 2 * p[p_idx] - h_i + T.
        //   It can also just move to h_i + T. So it's max(h_i + T, 2 * p[p_idx] - h_i + T).
        // If p[p_idx] is to the right of or at h_i (p[p_idx] >= h_i):
        //   The head moves right to p[p_idx]. Time taken: p[p_idx] - h_i.
        //   Remaining time: T - (p[p_idx] - h_i).
        //   It can then sweep right from p[p_idx] by this remaining time.
        //   Max right reach: p[p_idx] + (T - (p[p_idx] - h_i)) = h_i + T.
        //   It can also just move to h_i + T. So it's max(h_i + T, h_i + T) = h_i + T.

        // So, the effective rightmost reach for head h[h_idx] if it covers p[p_idx] is:
        long long current_head_right_reach;
        if (p[p_idx] <= h[h_idx]) {
            current_head_right_reach = std::max(h[h_idx] + T, 2 * p[p_idx] - h[h_idx] + T);
        } else { // p[p_idx] > h[h_idx]
            current_head_right_reach = h[h_idx] + T;
        }

        // Now, advance p_idx as long as p[p_idx] is covered by this head.
        while (p_idx < m && p[p_idx] <= current_head_right_reach) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance between tracks (10^10) * 2
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

