#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = std::numeric_limits<long long>::max();
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile 'i', we can add 'min_val' to it
            // as many times as possible without exceeding 'k'.
            // The current value of pile 'i' is a[i].
            // We want to find max_ops such that a[i] + max_ops * min_val <= k
            // max_ops * min_val <= k - a[i]
            // max_ops <= (k - a[i]) / min_val
            // Since max_ops must be an integer, max_ops = floor((k - a[i]) / min_val)

            if (a[i] >= k) { // If pile 'i' already has k or more, we can't add anything to it.
                continue;
            }

            long long remaining_capacity = k - a[i];
            if (min_val > 0) { // Avoid division by zero, though problem constraints say a_i >= 1
                total_spells += remaining_capacity / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

#include <iostream>
