int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases
    while (t--) {
        int n;
        std::cin >> n; // Read the length of the permutation
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i]; // Read the elements of the permutation
        }

        // The problem asks for a different permutation p' with the same fingerprint.
        // Reversing the given permutation p always produces a permutation p'
        // with the same set of adjacent sums, and thus the same sorted fingerprint.
        // Since p consists of distinct integers from 1 to n, p can only be equal
        // to its reverse if n=1 (which is not allowed, n>=2) or if it's a palindrome.
        // A permutation of distinct elements from 1 to n cannot be a palindrome
        // unless n=1. For n>=2, p will always be different from its reverse.
        // For example, if p = [1, 2, 3], reverse is [3, 2, 1].
        // If p = [1, 2], reverse is [2, 1].
        // In all cases for n>=2, the reversed permutation will be different from the original.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
