int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    long long total_sent_a = 0;
    long long successful_a = 0;
    long long total_sent_b = 0;
    long long successful_b = 0;

    for (int i = 0; i < n; ++i) {
        int t, x, y;
        std::cin >> t >> x >> y;
        if (t == 1) {
            total_sent_a += 10;
            successful_a += x;
        } else { // t == 2
            total_sent_b += 10;
            successful_b += x;
        }
    }

    // Server is "alive" if at least half of the packets reached it successfully.
    // This means successful_packets / total_packets >= 0.5
    // Which is equivalent to successful_packets * 2 >= total_packets
    if (successful_a * 2 >= total_sent_a) {
