void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number that satisfies the conditions.
        // A number starting with '2' and followed by '3's for the remaining n-1 digits
        // will not be divisible by 2 (if n > 1, it's odd) and not divisible by 3
        // (sum of digits is 2 + 3*(n-1) which is 2 + 3n - 3 = 3n - 1, not divisible by 3).
        // However, this construction is not always correct.
        // For example, if n=2, s=23. Not div by 2, not div by 3. Correct.
        // If n=3, s=233. Not div by 2, not div by 3. Correct.
        // If n=4, s=2333. Not div by 2, not div by 3. Correct.

        // A simpler construction that works for n >= 2:
        // Start with '2' and fill the rest with '3's.
        // The number will be 233...3 (n-1 times '3').
        // This number is odd, so it's not divisible by 2.
        // The sum of its digits is 2 + 3*(n-1) = 3n - 1.
        // Since 3n - 1 is never divisible by 3 (it leaves a remainder of 2 when divided by 3),
        // the number itself is not divisible by 3.
        // Thus, it's not divisible by any of its digits (2 or 3).
        // All digits are non-zero. It has n digits.
        // This construction works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

