#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases
    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n == 0) { // Handle edge case for n=0, though constraints say n >= 1
            std::cout << 0 << "\n";
            continue;
        }
        if (n == 1) { // A single day cannot have a "later" lower price
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price, as it's the minimum in the suffix starting from itself.
        int min_suffix = a[n - 1]; 

        // Iterate from the second to last day backwards to the first day
        for (int i = n - 2; i >= 0; --i) {
            // If the current price a[i] is greater than the minimum price found in the suffix a[i+1...n-1],
            // then a[i] is a bad price.
            if (a[i] > min_suffix) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix, it means a[i] is either
                // equal to or less than min_suffix. In this case, a[i] becomes the new
                // minimum for the suffix a[i...n-1].
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }
    return 0;
}

