        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)

        // Iterate through the string to find 'R' characters
        // s[i] corresponds to cell i+1
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at cell i+1
                // The previous 'R' (or start) was at last_R_pos
                // The gap is (i+1) - last_R_pos
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to current 'R' cell
            }
        }

        // After the loop, last_R_pos holds the position of the last 'R' character encountered.
        // The frog needs to jump from this last 'R' position to cell n+1.
        // The distance is (n+1) - last_R_pos.
        max_gap = std::max(max_gap, (int)s.length() + 1 - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by the minimum of coders and mathematicians.
        // It's also limited by the total number of students divided by 3.
        // So, the upper bound for k is min(c, m, (c + m + x) / 3).
        // We can use binary search to find the maximum k.
        // The search space for k is from 0 to 10^8 (max possible value for c, m, x).

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // An initial upper bound
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students without specialization: x

            // The total number of students available for the 'third' slot in each team
            // (after assigning one coder and one mathematician to each of the 'mid' teams)
            // is (c - mid) + (m - mid) + x.
            // Each of the 'mid' teams needs one more student.
            // So, we need at least 'mid' additional students.

            if ((c - mid) + (m - mid) + x >= mid) {
                // If we have enough students for the 'third' slot for all 'mid' teams,
                // then 'mid' teams are possible. Try for more.
                ans = mid;
                low = mid + 1;
            } else {
                // Not enough students for the 'third' slot. 'mid' teams are not possible.
                // Try for fewer teams.
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

