int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we'll use for the first k+1 elements to generate k distinct differences

    // The first k+1 elements will generate k distinct differences.
    // We alternate between left and right pointers to get differences k, k-1, ..., 1.
    // For example, if k=2, we use numbers 1, 2, 3.
    // Sequence: 1, 3, 2. Differences: |1-3|=2, |3-2|=1. Two distinct differences.
    // If k=3, we use numbers 1, 2, 3, 4.
    // Sequence: 1, 4, 2, 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1. Three distinct differences.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0-indexed)
            std::cout << left << " ";
            left++;
        } else { // Odd index
            std::cout << right << " ";
            right--;
        }
    }

    // The remaining n - (k+1) elements can be appended in increasing order.
    // This will only introduce a difference of 1 (if the last element printed was `x`,
    // the next will be `x+1`, giving `|x - (x+1)| = 1`).
    // Since 1 is already one of the k distinct differences generated by the first part,
    // this does not add new distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

