        long long sum_first_10_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_first_10_digits += (static_cast<long long>(i) * m) % 10;
        }

        // The number of full cycles of 10 multiples
        long long num_full_cycles = k / 10;

        // Sum from full cycles
        long long total_sum = num_full_cycles * sum_first_10_digits;

        // Add the sum for the remaining multiples
        long long remaining_multiples = k % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

