#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length of the segment is 1.
        // min value is 1, max value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1]...pos[m]) to max(pos[1]...pos[m]).
        // We maintain current_min_idx and current_max_idx as the minimum and maximum
        // indices encountered so far for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // The length of the segment spanning from current_min_idx to current_max_idx
        // is (current_max_idx - current_min_idx + 1).
        // If this length is equal to 'm', it means all numbers from 1 to 'm'
        // are contained within this segment, and no other numbers are.
        // (Because if other numbers were, the length would be greater than 'm'
        // for 'm' distinct numbers).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

