            // We know d^2 > d^2 - 4d (since 4d > 0 for d > 0).
            // So sqrt(d^2) > sqrt(d^2 - 4d) => d > sqrt(d^2 - 4d).
            // Therefore, d - sqrt(d^2 - 4d) > 0, so b1 > 0.
            // Both a1 and b1 are guaranteed to be positive for d > 4.
            // If d = 4, sqrt_discriminant = 0, so a1 = b1 = 4/2 = 2.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

