void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if a peak can exist.
    // For a peak at index k (0-indexed), we need:
    // a[0] < a[1] < ... < a[k]
    // a[k] > a[k+1] > ... > a[n-1]
    //
    // To satisfy a[i] < a[i+1] for i < k, we need a[i] >= i.
    // To satisfy a[i] > a[i+1] for i >= k, we need a[i] >= (n-1-i).
    //
    // So, for a peak at k, we need:
    // a[i] >= i for 0 <= i <= k
    // a[i] >= (n-1-i) for k <= i <= n-1
    //
    // The crucial part is that we can decrease elements.
    // So, if a[i] is large enough, we can make it satisfy the condition.
    //
    // For the increasing part (left side of peak):
    // We need a[i] >= i for 0 <= i <= k.
    // If a[i] < i for any i, then it's impossible to make a[i] = i,
    // because we can only decrease. So, a[i] must be at least i.
    //
    // For the decreasing part (right side of peak):
    // We need a[i] >= (n-1-i) for k <= i <= n-1.
    // Similarly, if a[i] < (n-1-i) for any i, it's impossible.
    //
    // So, we need to find if there exists a k such that:
    // 1. a[i] >= i for all 0 <= i <= k
    // 2. a[i] >= (n-1-i) for all k <= i <= n-1

    // Calculate the maximum possible 'k' from the left side.
    // This is the largest k such that a[i] >= i for all 0 <= i <= k.
    int max_k_from_left = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            break;
        }
        max_k_from_left = i;
    }

    // Calculate the maximum possible 'k' from the right side.
    // This is the smallest k such that a[i] >= (n-1-i) for all k <= i <= n-1.
    // Or, equivalently, the largest k such that a[k] >= (n-1-k).
    // We iterate from right to left to find the first index 'i' where a[i] < (n-1-i).
    // Any peak 'k' must be to the left of this 'i'.
    int min_k_from_right = n; // This will be the first index from right that fails the condition
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            break;
        }
        min_k_from_right = i;
    }

    // If max_k_from_left is -1, it means a[0] < 0, which is impossible for non-negative a[i].
    // If max_k_from_left is -1, it means no element can be the start of an increasing sequence.
    // If min_k_from_right is n, it means all elements satisfy a[i] >= (n-1-i).
    // If min_k_from_right is n, it means any element can be the end of a decreasing sequence.

    // A valid peak 'k' must satisfy both conditions.
    // So, we need to find if there's any 'k' such that:
    // k <= max_k_from_left AND k >= min_k_from_right
    // This means we need max_k_from_left >= min_k_from_right.

    if (max_k_from_left >= min_k_from_right) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

