// Function to check if a prefix of length `len` is a permutation
bool is_prefix_permutation(int len, const std::vector<int>& a, const std::vector<int>& prefix_max_val, const std::vector<int>& prefix_counts) {
    if (len == 0) return false; // Permutations must have non-zero length
    if (prefix_max_val[len - 1] != len) {
        return false;
    }
    // Check if all numbers from 1 to len appear exactly once.
    // This is implicitly handled by prefix_max_val == len and the distinctness check.
    // The distinctness check is done by comparing prefix_counts[len-1] with len.
    // If prefix_max_val[len-1] == len, it means all numbers are <= len.
    // If prefix_counts[len-1] == len, it means all numbers are distinct.
    // Together, these imply it's a permutation.
    return prefix_counts[len - 1] == len;
}

// Function to check if a suffix of length `len` is a permutation
bool is_suffix_permutation(int len, int n, const std::vector<int>& a, const std::vector<int>& suffix_max_val, const std::vector<int>& suffix_counts) {
    if (len == 0) return false; // Permutations must have non-zero length
    if (suffix_max_val[n - len] != len) {
        return false;
    }
    // Similar logic as prefix permutation
    return suffix_counts[n - len] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums and distinct counts
    std::vector<int> prefix_max_val(n);
    std::vector<int> prefix_counts(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n-1, so n+1 size is safe
    int current_distinct_count = 0;
    int current_max = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] < 1) { // Values must be within [1, n] for any permutation
            // This element makes it impossible for any permutation of length >= a[i]
            // to be formed. We can mark future counts/maxes as invalid or just let
            // the max_val check handle it.
            // For simplicity, we'll just let the max_val check handle it.
        }
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_count++;
        }
        current_max = std::max(current_max, a[i]);
        prefix_max_val[i] = current_max;
        prefix_counts[i] = current_distinct_count;
    }

    // Precompute suffix maximums and distinct counts
    std::vector<int> suffix_max_val(n);
    std::vector<int> suffix_counts(n);
    std::vector<bool> seen_suffix(n + 1, false);
    current_distinct_count = 0;
    current_max = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] < 1) {
            // Similar to prefix, let max_val check handle it.
        }
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_count++;
        }
        current_max = std::max(current_max, a[i]);
        suffix_max_val[i] = current_max;
        suffix_counts[i] = current_distinct_count;
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;
        if (is_prefix_permutation(l1, a, prefix_max_val, prefix_counts) &&
            is_suffix_permutation(l2, n, a, suffix_max_val, suffix_counts)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

