    //   So, if B+C > 0 and (A+B)%2 == 0, then ans3 = "Ya".

    // Box 4 (value >= 1):
    //   Condition 1: (A+B) is even (for positive sign)
    //   Condition 2: A+D > 0 (for magnitude >= 1)
    //   So, if A+D > 0 and (A+B)%2 == 0, then ans4 = "Ya".

    // Let's check the example: 1 2 0 1
    // A=1, B=2, C=0, D=1
    // total_toys = 4
    // A+B = 1+2 = 3 (odd)
    // B+C = 2+0 = 2 (>0)
    // A+D = 1+1 = 2 (>0)

    // Box 1: (A+B)%2 == 1 (3 is odd) AND A+D > 0 (2 > 0). -> Ya
    // Box 2: (A+B)%2 == 1 (3 is odd) AND B+C > 0 (2 > 0). -> Ya
    // Box 3: (A+B)%2 == 0 (3 is not even). -> Tidak
    // Box 4: (A+B)%2 == 0 (3 is not even). -> Tidak

    // Output: Ya Ya Tidak Tidak. Matches example.

    // Second example: 0 1 0 0
    // A=0, B=1, C=0, D=0
    // total_toys = 1
    // A+B = 0+1 = 1 (odd)
    // B+C = 1+0 = 1 (>0)
    // A+D = 0+0 = 0 (not >0)

    // Box 1: (A+B)%2 == 1 (1 is odd) AND A+D > 0 (0 is not >0). -> Tidak
    // Box 2: (A+B)%2 == 1 (1 is odd) AND B+C > 0 (1 > 0). -> Ya
    // Box 3: (A+B)%2 == 0 (1 is not even). -> Tidak
    // Box 4: (A+B)%2 == 0 (1 is not even). -> Tidak

    // Output: Tidak Ya Tidak Tidak. Matches example.

    // The logic seems sound.

    if ((a + b) % 2 == 1) { // Final product is negative
        if (a + d > 0) { // Can achieve magnitude >= 1
            ans1 = "Ya";
        }
        if (b + c > 0) { // Can achieve magnitude < 1
            ans2 = "Ya";
        }
    } else { // Final product is positive
        if (b + c > 0) { // Can achieve magnitude < 1
            ans3 = "Ya";
        }
        if (a + d > 0) { // Can achieve magnitude >= 1
            ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

