#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 == 1) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: N=2, Chanek takes 1, Opponent takes 1. Chanek gets 1.
                chanek_coins += 1;
                n -= 1; // N becomes 1, next turn opponent takes 1.
            } else if ((n / 2) % 2 == 1) { // N is even, N/2 is odd.
                // Chanek takes N/2. Remaining N/2 is odd. Opponent takes 1.
                // Chanek takes 1. Opponent takes 1.
                // This path gives Chanek N/2 + (N/2-1)/2 + ...
                // If Chanek takes 1. Remaining N-1 is odd. Opponent takes 1.
                // Chanek takes 1. Opponent takes 1.
                // This path gives Chanek 1 + (N-2)/2 + ...
                // Taking N/2 is generally better if N/2 is odd, as it leaves an odd number for opponent.
                // Example: N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // If Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // In this case, both give 4.
                // The logic is that if N/2 is odd, taking N/2 is good because it leaves an odd number for the opponent.
                // If N/2 is even, taking N/2 is good because it leaves an even number for the opponent, and the opponent might take N/4.
                // The only time Chanek should take 1 when N is even is if taking N/2 leads to a worse outcome.
                // This happens when N/2 is odd, and N/2 is not 1.
                // If N/2 is odd and N/2 > 1, then taking N/2 leaves an odd number for the opponent.
                // Opponent will take 1, leaving an even number.
                // If Chanek takes 1, it leaves an odd number for the opponent.
                // The key is that if N/2 is odd, the opponent will be forced to take 1, leaving an even number for Chanek.
                // If Chanek takes 1, the opponent will be forced to take 1, leaving an even number for Chanek.
                // The difference is that Chanek gets N/2 vs 1. So taking N/2 is better.
                // This means Chanek always takes N/2 if N is even and N > 2.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N is even, N/2 is even.
                // Chanek takes N/2. Remaining N/2 is even. Opponent takes N/4.
                // Chanek takes 1. Remaining N-1 is odd. Opponent takes 1.
                // This is the only scenario where Chanek might consider taking 1.
                // If Chanek takes N/2, he gets N/2. Opponent gets N/4.
                // If Chanek takes 1, he gets 1. Opponent gets 1.
                // The game continues with N/2 vs N-2.
                // The optimal strategy for Chanek is to take N/2.
                // The only exception is N=2, handled above.
                chanek_coins += n / 2;
                n /= 2;
            }
        }

        if (n > 0) { // Opponent's turn
            if (n % 2 == 1) {
                n -= 1;
            } else {
                if (n == 2) {
                    n -= 1;
                } else if ((n / 2) % 2 == 1) {
                    n /= 2;
                } else {
                    n /= 2;
                }
            }
        }
    }
    return chanek_coins;
}

