int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means all 'a's to its left
            // will eventually have to pass this 'b'.
            // Each 'a' currently to its left will double the number of 'a's
            // that need to pass this 'b' (because 'ab' -> 'bba' creates a new 'b').
            // So, the current count_a (representing 'a's that need to pass this 'b')
            // effectively doubles for the next 'b' to its left.
            // This is equivalent to saying that each 'a' to the left of this 'b'
            // will contribute to the total steps, and for each such 'a',
            // the number of 'a's that will need to pass the *next* 'b' to the left
            // will be doubled.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // have to pass all 'b's that were to its right.
            // The current value of count_a represents the number of 'a's
            // that are effectively "waiting" to pass the 'b's to their right.
            // This 'a' adds one to that count.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

