int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
        } else {
            // We need to append at most 3 elements.
            // Let S_0 be current_sum and X_0 be current_xor_sum.
            // We want S_0 + b_1 + ... + b_k = 2 * (X_0 ^ b_1 ^ ... ^ b_k).
            //
            // Strategy: Append two elements.
            // Let b_1 = X_0.
            // New XOR sum becomes X_0 ^ X_0 = 0.
            // New sum becomes S_0 + X_0.
            //
            // Now we need S_0 + X_0 + b_2 = 2 * (0 ^ b_2)
            // S_0 + X_0 + b_2 = 2 * b_2
            // S_0 + X_0 = b_2
            //
            // So, we can append X_0 and (S_0 + X_0).
            // The new array will have elements a_1, ..., a_n, X_0, (S_0 + X_0).
            // The new sum will be S_0 + X_0 + (S_0 + X_0) = 2 * (S_0 + X_0).
            // The new XOR sum will be X_0 ^ X_0 ^ (S_0 + X_0) = 0 ^ (S_0 + X_0) = S_0 + X_0.
            //
            // The condition S' = 2 * X' becomes 2 * (S_0 + X_0) = 2 * (S_0 + X_0), which is true.
            //
            // The problem states that appended elements can be up to 10^18.
            // S_0 can be up to 10^5 * 10^9 = 10^14.
            // X_0 can be up to 2^30 (approx 10^9).
            // So S_0 + X_0 can be up to 10^14 + 10^9, which fits in long long.
            // This strategy always works and uses 2 elements.

            std::cout << 2 << "\n";
            std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
        }
    }
    return 0;
}

