// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        return "0"; // Special case for 0
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should normalize to a fixed length, say 18, by padding with '0's.
    // For example, 92 (01) and 010.
    // 92 -> 01 (right to left)
    // 010 -> 010 (right to left)
    // The example 92 matches 010.
    // 92: ...000000000000000010 (padded to 18 digits, right to left)
    // 010: ...000000000000000010 (padded to 18 digits, right to left)
    // This means we should pad the *generated* pattern with '0's to the left to a fixed length.
    // The maximum number of digits for 10^18-1 is 18.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Normalize the query pattern to 18 digits, padding with '0's from the left.
            // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // This means the pattern '010' for 92 (01) should be treated as '010' for 92.
            // The example 92 matches 010.
            // 92 (decimal) -> 2 (even) 9 (odd) -> 01 (right to left)
            // 010 (pattern) -> 0 (rightmost) 1 (middle) 0 (leftmost)
            // If we align from right:
            // 92: ...000000000000000010 (padded to 18 digits, right to left)
            // 010: ...000000000000000010 (padded to 18 digits, right to left)
            // This means we should reverse the input pattern string and then pad with '0's.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

