#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    std::vector<long long> prime_factors;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors.push_back(temp_q);
    }

    // For each prime factor r of q, find the largest divisor of p that is not divisible by q
    for (long long r : prime_factors) {
        long long current_p = p;
        while (current_p % r == 0) {
            current_p /= r;
        }
        // current_p is p with all factors of r removed.
        // If current_p is not divisible by q, it's a candidate for max_x.
        // We need to find the largest divisor of p that is not divisible by q.
        // Consider p / (r^k) where r^k is the highest power of r that divides p.
        // This value is current_p.
        // If current_p is not divisible by q, then it's a candidate.
        // However, we need to find x such that x % q != 0.
        // The strategy is to take p, and for each prime factor r of q,
        // divide p by r until it's no longer divisible by q.
        // More precisely, for each prime factor r of q,
        // find the largest k such that p is divisible by r^k.
        // Then consider p / r. If (p/r) % q != 0, then p/r is a candidate.
        // If (p/r) % q == 0, then consider p / r^2, and so on.
        // We want to find the smallest power of r, say r^k, such that (p / r^k) % q != 0.
        // The largest such x would be p / r^k.
        // This is equivalent to finding the largest divisor of p, say x', such that x' is not divisible by q.
        // If p % q == 0, we must remove some factors from p.
        // We iterate through prime factors r of q.
        // For each r, we find the largest power of r, say r^k, that divides p.
        // Then we consider p / r. If (p/r) % q != 0, then p/r is a candidate.
        // If (p/r) % q == 0, we continue dividing by r.
        // The largest x not divisible by q will be p / (r^k) for some r that is a prime factor of q.
        // We want to find the maximum of such p / (r^k) over all prime factors r of q.

        long long current_val = p;
        while (current_val % q == 0) {
            current_val /= r;
        }
        max_x = std::max(max_x, current_val);
    }

    return max_x;
}

