#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_s.insert(c1);
        used_in_s.insert(c2);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_s.insert(s[0]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_for_layout;

    for (char c_node : used_in_s) {
        if (visited_for_layout.count(c_node)) {
            continue;
        }

        if (adj[c_node].size() <= 1) { // Start of a path or isolated node
            std::string current_path = "";
            char current_char = c_node;
            char prev_char = '\0'; // Sentinel for no previous char

            while (current_char != '\0' && !visited_for_layout.count(current_char)) {
                visited_for_layout.insert(current_char);
                current_path += current_char;

                char next_char = '\0';
                for (char neighbor : adj[current_char]) {
                    if (neighbor != prev_char) {
                        next_char = neighbor;
                        break;
                    }
                }
                prev_char = current_char;
                current_char = next_char;
            }
            layout_str += current_path;
        }
    }

    if (layout_str.length() != used_in_s.size()) {
        // This means there's a cycle or a path where all nodes have degree 2.
        // If all nodes in a component have degree 2, it's a cycle.
        // A cycle cannot be laid out on a 1D keyboard.
        // The only exception is if the entire graph is a single path, which would be handled by the above logic.
        // If there are multiple components and some are cycles, or if a component is a cycle, it's impossible.
        // The logic above only processes nodes with degree <= 1 as starting points.
        // If layout_str.length() < used_in_s.size(), it means there are nodes in used_in_s that were not visited.
        // These unvisited nodes must belong to components where all nodes have degree 2 (cycles).
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout_str;

    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited_for_layout.count(c)) {
            std::cout << c;
        }
    }
    std::cout << "\n";
}

