    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1}^{b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_val;
    if (b == 1) { // If b=1, then b-1=0, sum is 0.
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long b_val = b;

        // One of b_minus_1 or b must be even.
        // To avoid division by 2 with modulo, we can divide first.
        if (b_minus_1 % 2 == 0) {
            b_minus_1 /= 2;
        } else {
            b_val /= 2;
        }
        sum_r_val = (b_minus_1 % MOD * (b_val % MOD)) % MOD;
    }

    // Calculate sum_k = sum_{k=1}^{a} (k * b + 1)
    // sum_k = b * sum_{k=1}^{a} k + sum_{k=1}^{a} 1
    // sum_k = b * (a * (a+1) / 2) + a
    long long sum_k_val;
    long long a_val = a;
    long long a_plus_1_val = a + 1;

    // Calculate a * (a+1) / 2
    long long sum_a_k;
    if (a_val % 2 == 0) {
        a_val /= 2;
    } else {
        a_plus_1_val /= 2;
    }
    sum_a_k = (a_val % MOD * (a_plus_1_val % MOD)) % MOD;

    // Calculate b * sum_a_k
    long long term1 = (b % MOD * sum_a_k) % MOD;

    // Calculate a
    long long term2 = a % MOD;

    sum_k_val = (term1 + term2) % MOD;

    // Total sum = sum_k_val * sum_r_val
    long long total_sum = (sum_k_val * sum_r_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_probability = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char char0 = s[k_actual];

        const std::vector<int>& possible_k_indices = char_indices[char0 - 'a'];

        if (possible_k_indices.size() == 1) {
            total_win_probability += 1.0;
            continue;
        }

        double max_win_prob_for_char0 = 0.0;

        for (int p = 2; p <= n; ++p) { // Vasya chooses position p (1-indexed), so t[p-1]
            // For a fixed p, calculate how many k's are uniquely determined
            // among the possible_k_indices.

            // Map from (char0, char_at_p_minus_1) to count of k's that produce it
            std::vector<std::vector<int>> counts(26, std::vector<int>(26, 0));
            // For each possible k, what char it produces at p-1
            std::vector<int> char_at_p_minus_1_for_k(n);

            for (int k_cand : possible_k_indices) {
                char char_p_minus_1 = s[(k_cand + p - 1) % n];
                char_at_p_minus_1_for_k[k_cand] = char_p_minus_1;
                counts[char0 - 'a'][char_p_minus_1 - 'a']++;
            }

            // Check if k_actual is uniquely determined for this p
            char actual_char_p_minus_1 = char_at_p_minus_1_for_k[k_actual];
            if (counts[char0 - 'a'][actual_char_p_minus_1 - 'a'] == 1) {
                max_win_prob_for_char0 = 1.0; // Found a p that guarantees win for this k_actual
                break; // No need to check other p's for this k_actual
            }
        }
        total_win_probability += max_win_prob_for_char0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_probability / n << std::endl;

    return 0;
}

