#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0; // Value if input is 0
    int current_val_1 = 1023; // Value if input is 1023 (all 10 bits are 1)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1 |= x;
        } else { // '^'
            current_val_0 ^= x;
            current_val_1 ^= x;
        }
    }

    int final_and_mask = 1023; // Represents the 'a' in (x & a)
    int final_or_mask = 0;    // Represents the 'b' in (x | b)
    int final_xor_mask = 0;   // Represents the 'c' in (x ^ c)

    for (int bit = 0; bit < 10; ++bit) {
        int bit_mask = (1 << bit);
        int bit_val_0 = (current_val_0 & bit_mask) >> bit; // 0-th bit of current_val_0
        int bit_val_1 = (current_val_1 & bit_mask) >> bit; // 0-th bit of current_val_1

        if (bit_val_0 == 0 && bit_val_1 == 0) {
            // If input bit is 0, output bit is 0. If input bit is 1, output bit is 0.
            // This means the bit is always 0, regardless of input.
            // To achieve this: (x & 0) | 0 ^ 0 = 0
            // So, set final_and_mask's bit to 0.
            final_and_mask &= (~bit_mask);
        } else if (bit_val_0 == 1 && bit_val_1 == 1) {
            // If input bit is 0, output bit is 1. If input bit is 1, output bit is 1.
            // This means the bit is always 1, regardless of input.
            // To achieve this: (x & 1) | 1 ^ 0 = 1
            // So, set final_or_mask's bit to 1.
            final_or_mask |= bit_mask;
        } else if (bit_val_0 == 0 && bit_val_1 == 1) {
            // If input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
            // This means the bit is unchanged.
            // To achieve this: (x & 1) | 0 ^ 0 = x
            // So, final_and_mask's bit is 1, final_or_mask's bit is 0, final_xor_mask's bit is 0.
            // (These are default values, so no change needed for this bit)
        } else { // bit_val_0 == 1 && bit_val_1 == 0
            // If input bit is 0, output bit is 1. If input bit is 1, output bit is 0.
            // This means the bit is flipped.
            // To achieve this: (x & 1) | 0 ^ 1 = ~x
            // So, set final_xor_mask's bit to 1.
            final_xor_mask |= bit_mask;
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit needs to be forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit needs to be forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

