void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s_count = 0;
    int initial_b_count = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s_count++;
        } else {
            initial_b_count++;
        }
    }

    int initial_diff = initial_s_count - initial_b_count;

    // Calculate prefix differences for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // This is for removing k jars from the left.
    // The remaining jars on the left are a[k...n-1].
    // The difference for the segment a[k...n-1] is diff_L[n] - diff_L[k].
    // We need to store diff_L[k] for k from 0 to n.
    // diff_L[0] = 0 (no jars removed, no jars considered)
    // diff_L[k] = diff for a[0...k-1]
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix differences for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // This is for removing k jars from the right.
    // The remaining jars on the right are a[n...2n-k-1].
    // The difference for the segment a[n...2n-k-1] is diff_R[0] - diff_R[k].
    // We need to store diff_R[k] for k from 0 to n.
    // diff_R[0] = 0 (no jars removed, no jars considered)
    // diff_R[k] = diff for a[2n-k...2n-1]
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left (k_L)
    // to achieve a certain difference `d` for the remaining left segment `a[k_L...n-1]`.
    // The difference for `a[k_L...n-1]` is `diff_L[n] - diff_L[k_L]`.
    // We want to find `k_L` such that `diff_L[n] - diff_L[k_L] = target_diff_L`.
    // This means `diff_L[k_L] = diff_L[n] - target_diff_L`.
    // So, we map `diff_L[k_L]` to `k_L`.
    std::map<int, int> left_diff_to_kL;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff_val = diff_L[k_L];
        if (left_diff_to_kL.find(current_diff_val) == left_diff_to_kL.end()) {
            left_diff_to_kL[current_diff_val] = k_L;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removals

    // Iterate through all possible number of jars removed from the right (k_R)
    // k_R goes from 0 to n.
    for (int k_R = 0; k_R <= n; ++k_R) {
        // The difference for the segment `a[n...2n-k_R-1]` is `diff_R[0] - diff_R[k_R]`.
        // Since `diff_R[0]` is 0, this is `-diff_R[k_R]`.
        // The total difference for the remaining jars `a[k_L...2n-k_R-1]` should be 0.
        // So, `(diff_L[n] - diff_L[k_L]) + (-diff_R[k_R]) = 0`.
        // This means `diff_L[n] - diff_L[k_L] = diff_R[k_R]`.
        // We need to find `k_L` such that `diff_L[k_L] = diff_L[n] - diff_R[k_R]`.

        int target_diff_val_for_kL = initial_diff - diff_R[k_R];

        if (left_diff_to_kL.count(target_diff_val_for_kL)) {
            int k_L = left_diff_to_kL[target_diff_val_for_kL];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

