            b[i] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> current_a = b; // current_a represents a_0[i] + current_delta[i]
    std::vector<long long> delta_prefix_sum(n + 1, 0); // For efficient range updates

    for (const auto& op : ops) {
        if (op.type == 1) {
            // Apply type 1 operation to current_a
            // This is equivalent to adding d to delta_prefix_sum[l] and subtracting from delta_prefix_sum[r+1]
            delta_prefix_sum[op.l] += op.val;
            if (op.r + 1 < n) {
                delta_prefix_sum[op.r + 1] -= op.val;
            }
        } else {
            // Verify type 2 operation
            long long max_val = LLONG_MIN;
            long long current_delta_val = 0;
            for (int j = 0; j < n; ++j) {
                current_delta_val += delta_prefix_sum[j];
                if (j >= op.l && j <= op.r) {
                    max_val = std::max(max_val, b[j] + current_delta_val);
                }
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
