int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top part (from apex to cut i) should be i * (total_area / n).
        // Let A_total be the total area of the carrot. A_total = (1/2) * base * h = h/2.
        // The area of the top part up to cut x_i is A_i = (1/2) * (x_i/h) * x_i = x_i^2 / (2h).
        // We want A_i = i * (A_total / n) = i * ( (h/2) / n ) = i * h / (2n).
        // So, x_i^2 / (2h) = i * h / (2n).
        // x_i^2 = i * h^2 / n.
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.
// x can also exceed n, but its value is only used for array indexing if x is within [1, n].
// If x goes out of bounds, the program terminates.

// Memoization table for results of (x, parity)
// dp[x][0] stores (final_x, final_y_increment) if starting at x with even step count (first op is x+a_x)
// dp[x][1] stores (final_x, final_y_increment) if starting at x with odd step count (first op is x-a_x)
// The y_increment is relative to the y value at the start of the subproblem.
// We use a pair {long long, long long} where first is final_x and second is final_y_increment.
// A special value like {0, 0} can indicate "not computed" or "cycle detected".
// For cycle detection, we can use a `visiting` state.
std::vector<std::vector<std::pair<long long, long long>>> dp;
std::vector<std::vector<bool>> visiting; // To detect cycles

int N;
std::vector<long long> A_values; // a_1 is set dynamically, a_2...a_n are stored here.

// Function to solve for a given starting x and parity
// x_curr: current x position (1-indexed)
// parity: 0 for even step count (next op is x+a_x), 1 for odd step count (next op is x-a_x)
// a_1_val: the value of a[1] for the current run
std::pair<long long, long long> solve(long long x_curr, int parity, long long a_1_val) {
    // Base cases for termination
    if (x_curr <= 0 || x_curr > N) {
        return {x_curr, 0}; // x_curr is the final x, 0 is the y increment from this point
    }

    // Check memoization table
    if (dp[x_curr][parity].first != 0 || dp[x_curr][parity].second != 0) {
        // If it's not {0,0}, it means it's already computed.
        // {0,0} is used as an initial value, so we need to be careful if a valid result could be {0,0}.
        // A valid result {0,0} would mean x ends at 0 and y increment is 0.
        // This is possible if x_curr=0, but we handle x_curr<=0 above.
        // If x_curr > N, it's also handled.
        // So, for x_curr in [1, N], {0,0} is a safe initial value.
        return dp[x_curr][parity];
    }

    // Cycle detection
    if (visiting[x_curr][parity]) {
        // Cycle detected, return a special value indicating infinite loop
        return {-1, -1};
    }

    visiting[x_curr][parity] = true;

    long long current_a_val;
    if (x_curr == 1) {
        current_a_val = a_1_val;
    } else {
        current_a_val = A_values[x_curr - 2]; // A_values stores a_2...a_n, so index x_curr-2 corresponds to a_x_curr
    }

    long long next_x;
    long long y_increment_from_this_step;

    if (parity == 0) { // Current operation is x = x + a_x, y = y + a_x
        next_x = x_curr + current_a_val;
        y_increment_from_this_step = current_a_val;
    } else { // Current operation is x = x - a_x, y = y + a_x
        next_x = x_curr - current_a_val;
        y_increment_from_this_step = current_a_val;
    }

    // Recursively solve for the next state
    std::pair<long long, long long> result_from_next_state = solve(next_x, 1 - parity, a_1_val);

    // If a cycle was detected in the recursive call, propagate it
    if (result_from_next_state.first == -1 && result_from_next_state.second == -1) {
        dp[x_curr][parity] = {-1, -1};
    } else {
        // Combine results
        dp[x_curr][parity] = {result_from_next_state.first, y_increment_from_this_step + result_from_next_state.second};
    }

    visiting[x_curr][parity] = false; // Backtrack: mark as not visiting

    return dp[x_curr][parity];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    A_values.resize(N - 1);
    for (int i = 0; i < N - 1; ++i) {
        std::cin >> A_values[i];
    }

    // Initialize dp table and visiting table
    // dp[x][parity] stores {final_x, total_y_increment}
    // x goes from 1 to N. parity is 0 or 1.
    dp.resize(N + 1, std::vector<std::pair<long long, long long>>(2, {0, 0}));
    visiting.resize(N + 1, std::vector<bool>(2, false));

    // For each possible a_1 value (from 1 to N-1)
    for (long long i = 1; i < N; ++i) {
        // Clear dp and visiting for each new a_1_val
        // This is crucial because a_1_val changes the 'a' array, thus changing the transitions.
        // A more efficient approach would be to pass a_1_val as a parameter to solve,
        // and only clear dp states that depend on a_1_val (i.e., dp[1][0] and dp[1][1]).
        // However, since N is up to 2*10^5, clearing the whole table N times is too slow (N*N*2 states).
        // The current implementation of `solve` passes `a_1_val` as a parameter,
        // so the `dp` table should be cleared for each `i`.
        // This means the `dp` table should be part of the `solve` function's scope or passed around,
        // or we need to re-think the memoization.

        // The problem states "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means a_1 is set to `i` for each run. The `a` array effectively changes.
        // So, the DP table needs to be re-initialized for each `i`.
        // This makes the DP approach as described above too slow if `dp` is global.
        // N * (N * 2) states * (some constant work) = N^2, which is (2*10^5)^2 = 4*10^10. Too slow.

        // Let's re-evaluate the problem.
        // The only value that changes is a_1.
        // The transitions for x > 1 are fixed.
        // The transitions for x = 1 depend on a_1.
        // This means we can precompute results for x > 1.
        // For x = 1, the first step is `x = 1 + a_1`, `y = a_1`.
        // Then we are at `(1 + a_1, a_1)` and the next operation is `x = x - a_x`.
        // So we need to solve `solve(1 + a_1, 1, a_1)`.

        // Let's define a new DP state:
        // dp[x][parity] stores {final_x, final_y_increment} assuming a_1 is NOT involved in the path.
        // This means dp[1][0] and dp[1][1] cannot be computed this way.
        // We can compute dp for x from 2 to N.
        // Then for each `i`, we start at `x=1, y=0`.
        // First step: `x = 1 + i`, `y = i`.
        // Then call `solve(1 + i, 1, i)` using the precomputed DP table.
        // The `a_1_val` parameter is only needed for `x_curr == 1`.
        // If `x_curr > 1`, `a_1_val` is not used.

        // Clear dp and visiting for each new `i`
        for (int k = 0; k <= N; ++k) {
            dp[k][0] = {0, 0};
            dp[k][1] = {0, 0};
            visiting[k][0] = false;
            visiting[k][1] = false;
        }

        // Initial state for the run: x=1, y=0.
        // First operation: x = 1 + i, y = 0 + i.
        // Then, the next operation is x = x - a_x. So parity is 1.
        long long initial_x_after_first_op = 1 + i;
        long long initial_y_after_first_op = i;

        std::pair<long long, long long> result = solve(initial_x_after_first_op, 1, i);

        if (result.first == -1 && result.second == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << initial_y_after_first_op + result.second << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cry from child i in office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry from children who left
            children[j].p -= total_d_cry_from_leaving;

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0; // The smallest possible value for b_i, given b_{i-1}
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a_i is already >= prev_b.
        // We can potentially keep a_i as b_i, or increment it.
        // The smallest possible b_i is max(prev_b, a_i).
        // If a_i >= prev_b, then we can set b_i = a_i.
        // This requires 0 operations for a_i.
        // The value a_i is valid if a_i >= prev_b.
        // The value (a_i + k) % m is valid if (a_i + k) % m >= prev_b.

        // We need to find a b_i such that b_i >= prev_b and b_i can be formed from a_i with <= x operations.
        // The possible values for b_i are in the range [a_i, (a_i + x) % m] if a_i + x < m,
        // or [a_i, m-1] U [0, (a_i + x) % m] if a_i + x >= m.

        // Let's consider the range of values [a_i, (a_i + x) % m] that b_i can take.
        // If a_i + x < m:
        //   The possible values for b_i are [a_i, a_i + x].
        //   We need to pick b_i >= prev_b.
        //   If a_i + x < prev_b, then no such b_i exists.
        //   Otherwise, we can pick b_i = max(a_i, prev_b).
        //   If a_i >= prev_b, we can pick b_i = a_i.
        //   If a_i < prev_b, we must pick b_i = prev_b. This requires prev_b - a_i operations.
        //     This is only possible if prev_b - a_i <= x.

        // If a_i + x >= m (i.e., the range wraps around):
        //   The possible values for b_i are [a_i, m-1] U [0, (a_i + x) % m].
        //   We need to pick b_i >= prev_b.
        //   If a_i >= prev_b:
        //     We can pick b_i = a_i (0 operations). This is always valid.
        //   If a_i < prev_b:
        //     We need to pick b_i >= prev_b.
        //     The values in [a_i, m-1] are not useful if a_i < prev_b.
        //     We must pick a value from [0, (a_i + x) % m] that is >= prev_b.
        //     This is only possible if (a_i + x) % m >= prev_b.
        //     If it is, we can pick b_i = prev_b. This requires (m - a_i + prev_b) operations.
        //     This is only possible if (m - a_i + prev_b) <= x.

        // Let's simplify. We want to find b_i such that:
        // 1. b_i >= prev_b
        // 2. b_i is reachable from a_i with at most x operations.
        //    This means (b_i - a_i + m) % m <= x.

        // Option 1: Try to set b_i = a_i.
        // This is valid if a_i >= prev_b.
        // If a_i >= prev_b, we can potentially use a_i as b_i.
        // This requires 0 operations.
        // So, if a_i >= prev_b, we can set prev_b = a_i and continue.

        // Option 2: If a_i < prev_b, we must increment a_i.
        // We need to reach at least prev_b.
        // The number of operations needed to reach prev_b from a_i is (prev_b - a_i + m) % m.
        // If a_i <= prev_b:
        //   If a_i + x >= prev_b:
        //     We can set b_i = prev_b. This requires prev_b - a_i operations.
        //     This is valid if prev_b - a_i <= x.
        //   If a_i + x < prev_b:
        //     This means we cannot reach prev_b by just incrementing a_i without wrapping around.
        //     We must wrap around. The values we can reach are [a_i, m-1] U [0, (a_i+x)%m].
        //     If a_i < prev_b, then we need to reach prev_b.
        //     The cost to reach prev_b from a_i is (m - a_i + prev_b).
        //     This is only possible if (m - a_i + prev_b) <= x.
        //     If this is true, we can set b_i = prev_b.
        //     If this is false, we cannot reach prev_b. So it's impossible.

        // Let's combine these.
        // We need to find a b_i such that b_i >= prev_b and (b_i - a_i + m) % m <= x.

        // Consider the value `a_i`.
        // If `a_i >= prev_b`:
        //   We can potentially use `a_i` as `b_i`. This costs 0 operations.
        //   So, `prev_b` can remain `a_i`.
        //   However, we also have the option to increment `a_i` up to `a_i + x`.
        //   If `a_i + x >= m`, then we can reach any value in `[a_i, m-1]` and `[0, (a_i+x)%m]`.
        //   If `a_i + x < m`, then we can reach any value in `[a_i, a_i+x]`.
        //   In this case (`a_i >= prev_b`), we can always choose `b_i = a_i`, which satisfies `b_i >= prev_b` and costs 0.
        //   So, `prev_b` for the next iteration can be `a_i`.

        // If `a_i < prev_b`:
        //   We *must* increment `a_i` to at least `prev_b`.
        //   The cost to reach `prev_b` from `a_i` is `(prev_b - a_i + m) % m`.
        //   If `prev_b >= a_i`, the cost is `prev_b - a_i`.
        //   If `prev_b < a_i`, the cost is `m - a_i + prev_b`.
        //   This can be written as `(prev_b - a_i + m) % m`.
        //   Let `cost_to_reach_prev_b = (prev_b - a_i + m) % m`.
        //   If `cost_to_reach_prev_b <= x`:
        //     We can set `b_i = prev_b`. This is valid.
        //     So, `prev_b` for the next iteration remains `prev_b`.
        //   If `cost_to_reach_prev_b > x`:
        //     We cannot reach `prev_b` from `a_i` with at most `x` operations.
        //     This means it's impossible to make the array non-decreasing with `x` operations.
        //     Return `false`.

        // Simplified logic:
        // We need to find a `b_i` such that `b_i >= prev_b` and `(b_i - a_i + m) % m <= x`.
        //
        // Let `val_a = a[i]`.
        //
        // If `val_a >= prev_b`:
        //   We can potentially use `val_a` as `b_i`. This costs 0 operations.
        //   This is always a valid choice for `b_i` if `val_a >= prev_b`.
        //   So, we can set `prev_b = val_a` for the next iteration.
        //   However, we also need to consider if we *must* increment `val_a` to satisfy `b_i >= prev_b`
        //   while also satisfying `(b_i - val_a + m) % m <= x`.
        //   If `val_a + x < m`:
        //     The reachable values are `[val_a, val_a + x]`.
        //     If `val_a >= prev_b`, we can pick `b_i = val_a`. This is fine.
        //   If `val_a + x >= m`: (wraps around)
        //     The reachable values are `[val_a, m-1]` and `[0, (val_a + x) % m]`.
        //     If `val_a >= prev_b`, we can pick `b_i = val_a`. This is fine.
        //
        // The only case where we *must* increment `val_a` is if `val_a < prev_b`.
        // In this case, we need to find `b_i` such that `b_i >= prev_b`.
        // The cost to reach `prev_b` from `val_a` is `(prev_b - val_a + m) % m`.
        // If `(prev_b - val_a + m) % m <= x`, then we can set `b_i = prev_b`.
        // If `(prev_b - val_a + m) % m > x`, then we cannot reach `prev_b` with `x` operations.
        // In this scenario, it's impossible.

        // So, the logic is:
        // If `a[i] >= prev_b`:
        //   We can potentially use `a[i]` as `b_i`. This costs 0 operations.
        //   This is always valid. So `prev_b` for the next iteration can be `a[i]`.
        //   However, we also need to check if `a[i]` is too large such that even if we increment it `x` times,
        //   it still doesn't wrap around to be less than `prev_b`.
        //   This is the tricky part. We want to keep `b_i` as small as possible.
        //   If `a[i]` can be `prev_b` (i.e., `(prev_b - a[i] + m) % m <= x`), then we should try to make `b_i = prev_b`.
        //   Otherwise, we must make `b_i = a[i]`.

        // Let's re-evaluate. For each `a_i`, we need to choose `b_i` such that:
        // 1. `b_i >= prev_b`
        // 2. `(b_i - a_i + m) % m <= x`
        // We want to find the smallest possible `b_i` that satisfies these conditions, to make it easier for `b_{i+1}`.

        // Candidate values for `b_i` are `a_i` (cost 0) and `(a_i + k) % m` for `1 <= k <= x`.
        //
        // Let `min_val_b_i = prev_b`.
        //
        // If `a[i] >= prev_b`:
        //   We can choose `b_i = a[i]`. This satisfies `b_i >= prev_b` and costs 0.
        //   This is a valid choice.
        //   However, we also have the option to increment `a[i]` by `k` operations.
        //   If `a[i] + x >= m`: (wraps around)
        //     This means we can reach any value in `[a[i], m-1]` and `[0, (a[i]+x)%m]`.
        //     Since `a[i] >= prev_b`, we can always pick `b_i = prev_b`.
        //     The cost to reach `prev_b` from `a[i]` is `(prev_b - a[i] + m) % m`.
        //     If `prev_b <= a[i]`, this cost is `prev_b - a[i]`.
        //     If `prev_b > a[i]`, this cost is `m - a[i] + prev_b`.
        //     Wait, if `a[i] >= prev_b`, then `prev_b - a[i]` is negative or zero.
        //     So `(prev_b - a[i] + m) % m` would be `m - (a[i] - prev_b)` if `a[i] > prev_b`.
        //     This is the cost to reach `prev_b` by wrapping around.
        //     If `a[i] >= prev_b`, we have two options for `b_i`:
        //     1. `b_i = a[i]`. Cost is 0. This is valid.
        //     2. `b_i = prev_b`. This requires `(prev_b - a[i] + m) % m` operations.
        //        This is only possible if `(prev_b - a[i] + m) % m <= x`.
        //        If `prev_b <= a[i]`, then `prev_b - a[i]` is negative or zero.
        //        The cost to reach `prev_b` from `a[i]` by wrapping around is `m - (a[i] - prev_b)`.
        //        If `m - (a[i] - prev_b) <= x`, then we can choose `b_i = prev_b`.
        //        Otherwise, we must choose `b_i = a[i]`.
        //
        // This is the core logic:
        // If `a[i]` can be transformed into `prev_b` with at most `x` operations:
        //   i.e., `(prev_b - a[i] + m) % m <= x`
        //   Then we can set `b_i = prev_b`. This is the smallest possible value for `b_i`.
        // Else (if `a[i]` cannot be transformed into `prev_b` with at most `x` operations):
        //   We must choose `b_i >= a[i]`.
        //   Since `b_i` must also be `>= prev_b`, and we know `a[i]` cannot be transformed to `prev_b`
        //   (meaning `a[i]` is "too large" to wrap around to `prev_b` within `x` ops, or `a[i]` is simply `> prev_b` and cannot be reduced),
        //   we must set `b_i = a[i]`.
        //   But we also need `b_i >= prev_b`.
        //   So, if `a[i] < prev_b`, and `(prev_b - a[i] + m) % m > x`, then it's impossible.
        //   Otherwise, if `a[i] >= prev_b`, we set `prev_b = a[i]`.

        // Let's try this:
        // `current_val = a[i]`
        // `target_val = prev_b`
        //
        // Calculate the cost to transform `current_val` to `target_val` by incrementing:
        // `cost = (target_val - current_val + m) % m`
        //
        // If `cost <= x`:
        //   This means we can transform `current_val` to `target_val` (or any value between `current_val` and `target_val` if `current_val <= target_val`, or `current_val` to `m-1` then `0` to `target_val` if `current_val > target_val`).
        //   Since we want to keep `b_i` as small as possible, we set `b_i = target_val`.
        //   So, `prev_b` remains `target_val` for the next iteration.
        // Else (`cost > x`):
        //   This means we cannot transform `current_val` to `target_val` with `x` operations.
        //   Therefore, `b_i` must be greater than `target_val`.
        //   The smallest possible `b_i` that satisfies `b_i >= target_val` and `(b_i - current_val + m) % m <= x`
        //   must be `current_val` itself (if `current_val >= target_val`).
        //   If `current_val < target_val`, and `cost > x`, then it's impossible to make `b_i >= target_val`.
        //   So, if `current_val < target_val` and `cost > x`, return `false`.
        //   Otherwise (`current_val >= target_val` and `cost > x`), we must set `b_i = current_val`.
        //   So, `prev_b` becomes `current_val`.

        // This logic seems correct and covers all cases.

        long long cost_to_reach_prev_b;
        if (current_a <= prev_b) {
            cost_to_reach_prev_b = prev_b - current_a;
        } else { // current_a > prev_b
            // We need to wrap around to reach prev_b.
            // e.g., a_i=6, prev_b=0, m=7. Cost is (7-6+0)=1.
            // e.g., a_i=6, prev_b=1, m=7. Cost is (7-6+1)=2.
            cost_to_reach_prev_b = m - current_a + prev_b;
        }

        if (cost_to_reach_prev_b <= x) {
            // We can make b_i = prev_b. This is the smallest possible.
            // prev_b remains prev_b.
        } else {
            // We cannot make b_i = prev_b.
            // This means b_i must be greater than prev_b.
            // The smallest value b_i can take is current_a (if current_a >= prev_b).
            // If current_a < prev_b, and we cannot reach prev_b, then it's impossible.
            if (current_a < prev_b) {
                return false;
            }
            // If current_a >= prev_b, we must take b_i = current_a.
            // This means prev_b for the next iteration becomes current_a.
            prev_b = current_a;
        }
    }
    return true;
}

