                // Any interval of length 9 or more must contain a pattern with $k \le 4$.
                // So, if there is a pattern with $k \ge 5$, there must also be one with $k \le 4$
                // that is contained within the same or an earlier interval.
                // This means that for any $l$, the $R_l$ value will be determined by a $k \le 4$.
                // So, we only need to check $k=1,2,3,4$.
                // This makes the inner loop constant time. $O(N \cdot 4) = O(N)$.

                // Let's use this optimized approach.
                // min_end_idx[l] stores the minimum $r$ such that $s[l \dots r]$ contains a pattern.
                // Initialize min_end_idx[l] = n for all l.
                // Iterate $x$ from $0$ to $n-1$.
                // Iterate $k$ from $1$ to $4$.
                // If $x+2k < n$ and $s[x] == s[x+k] == s[x+2k]$:
                //   Then for any $l \le x$, the substring $s[l \dots x+2k]$ contains a pattern.
                //   So, $min\_end\_idx[l]$ can be at most $x+2k$.
                //   We update $min\_end\_idx[x] = \min(min\_end\_idx[x], x+2k)$.
                // After the loops, propagate minimums:
                // For $l$ from $n-2$ down to $0$: $min\_end\_idx[l] = \min(min\_end\_idx[l], min\_end\_idx[l+1])$.
                // This ensures $min\_end\_idx[l]$ stores the minimum $r$ for any pattern starting at or before $l$.

                // Example: s = 010101, n=6
                // min_end_idx = [6, 6, 6, 6, 6, 6]
                // x=0:
                //   k=1: x+2k=2. s[0]=0, s[1]=1, s[2]=0. No.
                //   k=2: x+2k=4. s[0]=0, s[2]=0, s[4]=0. Yes! Pattern (0,2,4).
                //     min_end_idx[0] = min(6, 4) = 4.
                //   k=3: x+2k=6. Out of bounds.
                // x=1:
                //   k=1: x+2k=3. s[1]=1, s[2]=0, s[3]=1. No.
                //   k=2: x+2k=5. s[1]=1, s[3]=1, s[5]=1. Yes! Pattern (1,3,5).
                //     min_end_idx[1] = min(6, 5) = 5.
                // x=2:
                //   k=1: x+2k=4. s[2]=0, s[3]=1, s[4]=0. No.
                //   k=2: x+2k=6. Out of bounds.
                // x=3:
                //   k=1: x+2k=5. s[3]=1, s[4]=0, s[5]=1. No.
                // x=4:
                //   k=1: x+2k=6. Out of bounds.
                // x=5:
                //   No k possible.

                // After first pass: min_end_idx = [4, 5, 6, 6, 6, 6]

                // Propagate minimums:
                // l=4: min_end_idx[4] = min(min_end_idx[4], min_end_idx[5]) = min(6,6) = 6.
                // l=3: min_end_idx[3] = min(min_end_idx[3], min_end_idx[4]) = min(6,6) = 6.
                // l=2: min_end_idx[2] = min(min_end_idx[2], min_end_idx[3]) = min(6,6) = 6.
                // l=1: min_end_idx[1] = min(min_end_idx[1], min_end_idx[2]) = min(5,6) = 5.
                // l=0: min_end_idx[0] = min(min_end_idx[0], min_end_idx[1]) = min(4,5) = 4.

                // Final min_end_idx = [4, 5, 6, 6, 6, 6]
                // This means:
                // For l=0, smallest r is 4. Good pairs: (0,4), (0,5). Count = 2.
                // For l=1, smallest r is 5. Good pairs: (1,5). Count = 1.
                // For l=2, smallest r is 6 (n). No good pairs starting at l=2. Count = 0.
                // For l=3, smallest r is 6 (n). No good pairs starting at l=3. Count = 0.
                // For l=4, smallest r is 6 (n). No good pairs starting at l=4. Count = 0.
                // For l=5, smallest r is 6 (n). No good pairs starting at l=5. Count = 0.

                // Total good pairs = (n - min_end_idx[0]) + (n - min_end_idx[1]) + ...
                // For l=0: n - min_end_idx[0] = 6 - 4 = 2. (Pairs (0,4), (0,5))
                // For l=1: n - min_end_idx[1] = 6 - 5 = 1. (Pair (1,5))
                // For l=2: n - min_end_idx[2] = 6 - 6 = 0.
                // For l=3: n - min_end_idx[3] = 6 - 6 = 0.
                // For l=4: n - min_end_idx[4] = 6 - 6 = 0.
                // For l=5: n - min_end_idx[5] = 6 - 6 = 0.
                // Total = 2 + 1 + 0 + 0 + 0 + 0 = 3.
                // This matches the example output. The $k \le 4$ optimization seems correct.

                // Let's implement this.
            }
        }
    }

    std::vector<int> min_r_for_l(n, n); // min_r_for_l[i] = smallest r (0-indexed) such that s[i...r] contains a pattern.

    for (int x = 0; x < n; ++x) {
        for (int k = 1; k <= 4; ++k) { // Only check k up to 4 based on the Ramsey theory result.
            int x_plus_2k = x + 2 * k;
            if (x_plus_2k >= n) {
                break;
            }
            if (s[x] == s[x + k] && s[x + k] == s[x_plus_2k]) {
                min_r_for_l[x] = std::min(min_r_for_l[x], x_plus_2k);
            }
        }
    }

    // Propagate minimums backwards:
    // min_r_for_l[i] should be the minimum r for any pattern starting at or before i.
    // So, min_r_for_l[i] = min(min_r_for_l[i], min_r_for_l[i+1])
    for (int i = n - 2; i >= 0; --i) {
        min_r_for_l[i] = std::min(min_r_for_l[i], min_r_for_l[i + 1]);
    }

    long long good_pairs_count = 0;
    for (int l = 0; l < n; ++l) {
        if (min_r_for_l[l] < n) { // If a pattern exists for this l
            // For a fixed l, any r from min_r_for_l[l] to n-1 forms a good pair.
            // Number of such r's is (n-1) - min_r_for_l[l] + 1 = n - min_r_for_l[l].
            good_pairs_count += (n - min_r_for_l[l]);
        }
    }

    std::cout << good_pairs_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_reach_left(n);
    std::vector<long long> head_reach_right(n);
    for (int i = 0; i < n; ++i) {
        head_reach_left[i] = h[i] - T;
        head_reach_right[i] = h[i] + T;
    }

    std::vector<long long> dp_left(m); // dp_left[j] = minimum head index needed to cover p[0]...p[j]
    std::vector<long long> dp_right(m); // dp_right[j] = minimum head index needed to cover p[j]...p[m-1]

    // Calculate dp_left
    int current_head_idx = 0;
    for (int j = 0; j < m; ++j) {
        while (current_head_idx < n && head_reach_right[current_head_idx] < p[j]) {
            current_head_idx++;
        }
        if (current_head_idx == n || head_reach_left[current_head_idx] > p[j]) {
            dp_left[j] = n + 1; // Cannot cover p[j] with any head starting from current_head_idx
        } else {
            dp_left[j] = current_head_idx;
        }
    }

    // Calculate dp_right
    current_head_idx = n - 1;
    for (int j = m - 1; j >= 0; --j) {
        while (current_head_idx >= 0 && head_reach_left[current_head_idx] > p[j]) {
            current_head_idx--;
        }
        if (current_head_idx < 0 || head_reach_right[current_head_idx] < p[j]) {
            dp_right[j] = -1; // Cannot cover p[j] with any head ending at current_head_idx
        } else {
            dp_right[j] = current_head_idx;
        }
    }

    // Check if all tracks can be covered
    // Case 1: All tracks covered by a single head
    for (int i = 0; i < n; ++i) {
        if (head_reach_left[i] <= p[0] && head_reach_right[i] >= p[m - 1]) {
            return true;
        }
    }

    // Case 2: Split into two groups
    // We need to find if there exist i1, i2 such that i1 < i2 and
    // head i1 covers p[0]...p[k] and head i2 covers p[k+1]...p[m-1] for some k.
    // This is equivalent to finding if there exists k such that
    // dp_left[k] < n and dp_right[k+1] > -1 and dp_left[k] < dp_right[k+1].
    // The condition dp_left[k] < dp_right[k+1] ensures distinct heads.
    // However, the problem allows heads to overlap or be the same.
    // The actual condition is that there exist two heads i1, i2 such that
    // head i1 covers p[0]...p[k] and head i2 covers p[k+1]...p[m-1].
    // This means we need to find k such that there is a head i1 with h[i1]-T <= p[0] and h[i1]+T >= p[k]
    // AND there is a head i2 with h[i2]-T <= p[k+1] and h[i2]+T >= p[m-1].
    // And we need to ensure that the remaining m-2 heads can cover the remaining tracks.

    // The problem is a standard interval covering problem.
    // We have n heads, each covering [h_i - T, h_i + T].
    // We need to cover all p_j.
    // Let's use a greedy approach for `check(T)`:
    // We want to cover p[0]. Find the head that can cover p[0] and reaches furthest to the right.
    // Then, from the next uncovered p_j, repeat.
    // This greedy approach is for minimum number of heads. Here we have a fixed number of heads `n`.

    // A more robust check(T) for fixed N heads:
    // We iterate through the target tracks p_j.
    // `current_p_idx` is the index of the leftmost target track not yet covered.
    // `head_ptr` is the index of the next available head.
    // We try to cover `p[current_p_idx]` using `head_ptr`.
    // If `head_ptr` cannot cover `p[current_p_idx]` (i.e., `h[head_ptr] + T < p[current_p_idx]`),
    // then `head_ptr` is useless for `p[current_p_idx]` and any subsequent `p_k`. So we advance `head_ptr`.
    // If `head_ptr` can cover `p[current_p_idx]` (i.e., `h[head_ptr] - T <= p[current_p_idx]`),
    // then we use this head. It covers up to `h[head_ptr] + T`.
    // We advance `current_p_idx` past all `p_k` that are covered by this head.
    // We then advance `head_ptr` to the next head.
    // If we run out of heads before covering all `p_j`, return false.
    // If we cover all `p_j`, return true.

    int p_idx = 0;
    int h_idx = 0;
    while (p_idx < m && h_idx < n) {
        // Find the first head that can potentially cover p[p_idx]
        // A head h[h_idx] can cover p[p_idx] if h[h_idx] - T <= p[p_idx].
        // If h[h_idx] + T < p[p_idx], this head is too far left to cover p[p_idx]
        // and cannot cover any p_k for k > p_idx either. So we must use a later head.
        while (h_idx < n && head_reach_right[h_idx] < p[p_idx]) {
            h_idx++;
        }
        if (h_idx == n) { // Ran out of heads
            return false;
        }

        // Now h[h_idx] is the first head that *might* cover p[p_idx].
        // If h[h_idx] - T > p[p_idx], then even this head cannot cover p[p_idx].
        // This means p[p_idx] cannot be covered by any head from h_idx onwards.
        // Since earlier heads were already too far left, p[p_idx] cannot be covered at all.
        if (head_reach_left[h_idx] > p[p_idx]) {
            return false;
        }

        // Head h[h_idx] can cover p[p_idx]. It covers up to head_reach_right[h_idx].
        long long current_coverage_limit = head_reach_right[h_idx];

        // Advance p_idx past all tracks covered by this head.
        while (p_idx < m && p[p_idx] <= current_coverage_limit) {
            p_idx++;
        }

        // Move to the next head for the next uncovered track.
        h_idx++;
    }

    return p_idx == m; // All tracks covered
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between p_m and h_1, or p_1 and h_n.
                               // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                               // Max p_i is 10^10, max h_i is 10^10. Max diff is 10^10.
                               // So 2 * 10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}
